-- Poems batch 246
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('aac44283-0be3-4fb8-867a-25cb3d962b49','挽實齋劉尚書  其一','王義山','宋','宋诗','song-poetry','','[]','緊官都做了，只欠到台司。',48,'全唐诗/poet.song.222000.json','["緊官都做了，只欠到台司。", "言路古之直，經筵帝者師。", "極中五福備，天下達尊推。", "方曳星辰履，商山已茹芝。"]'),
('1f4f0639-2e04-4df0-b70d-99012780d14f','挽實齋劉尚書  其二','王義山','宋','宋诗','song-poetry','','[]','節麾仍帥閫，三道福星臨。',48,'全唐诗/poet.song.222000.json','["節麾仍帥閫，三道福星臨。", "政澈寒潭底，人行明鏡心。", "船中不留月，童背也無琴。", "誰憩甘棠下，無窮蔽芾陰。"]'),
('b2a9c5ca-2d66-42bc-9edf-00c33f32d27b','春日即事二首  其一','王義山','宋','宋诗','song-poetry','','[]','朔氣稜稜带雪吹，凝陰四面鎖寒枝。',64,'全唐诗/poet.song.222000.json','["朔氣稜稜带雪吹，凝陰四面鎖寒枝。", "自回造化微和後，如再洪濛未判時。", "天遣江山醒醉眼，春將景色入新詩。", "鄉晨一部簫韶奏，草綠花紅山鳥嬉。"]'),
('ca7d0b42-323e-4496-a80c-3e90c7b868ae','春日即事二首  其二','王義山','宋','宋诗','song-poetry','','[]','步屧隨風過柳川，眼前氣象覺熙然。',64,'全唐诗/poet.song.222000.json','["步屧隨風過柳川，眼前氣象覺熙然。", "勾萌甲拆皆春意，魚躍鳶飛遂性天。", "綠草方濃山盡髮，紫芽新迸蕨初拳。", "自形自色何容巧，稟賦元來物得偏。"]'),
('8d821c9e-43db-4d73-bbd0-c3550f83f296','送雲遊瑩上人','王義山','宋','宋诗','song-poetry','','[]','從前身不染飛埃，雪竇雲峯任往來。',64,'全唐诗/poet.song.222000.json','["從前身不染飛埃，雪竇雲峯任往來。", "石路滑時宜駐錫，浪頭危處且浮杯。", "眼高桑下肯三宿，脚健山中能萬回。", "四大空虛何底止，信渠鑽得紙窗開。"]'),
('c954d4dc-6089-4f6f-a10c-5e1e1e3bf7c4','挽鹿泉賈參政二首  其一','王義山','宋','宋诗','song-poetry','','[]','奪得公來鎮古洪，武昌棠蔭藹春融。',64,'全唐诗/poet.song.222000.json','["奪得公來鎮古洪，武昌棠蔭藹春融。", "生民立命學有用，活佛救人天大功。", "上帝遣符徵范鎮，斯民失怙哭溫公。", "山橫抱犢人何在，草木悲號一夜風。"]'),
('0a353cbb-0708-4163-ba93-65ea7d5c9a2a','挽鹿泉賈參政二首  其二','王義山','宋','宋诗','song-poetry','','[]','一老皤皤六十餘，直從苦硬做工夫。',64,'全唐诗/poet.song.222000.json','["一老皤皤六十餘，直從苦硬做工夫。", "可憐爵齒嗇於德，惟有詩書付爾孤。", "後學失師誰主此，斯文墜地果天乎。", "櫬歸只借帆風力，最是舟中麥也無。"]'),
('0fe7247b-98dd-41fc-bfb0-8429b01b2c9d','餞張宣慰三首  其一','王義山','宋','宋诗','song-poetry','','[]','奉宣德意慰羣生，曾未□年政已成。',64,'全唐诗/poet.song.222000.json','["奉宣德意慰羣生，曾未□年政已成。", "乃父勳名在彝鼎，當家衣鉢合鈞衡。", "如何歸隠山林得，不管從來利祿輕。", "裴度淮西功業了，佇乘馹傳上神京。"]'),
('4f750def-f1db-441e-a9ec-964e4ca83636','餞張宣慰三首  其二','王義山','宋','宋诗','song-poetry','','[]','貴介而能大耐官，留心翰墨此爲難。',64,'全唐诗/poet.song.222000.json','["貴介而能大耐官，留心翰墨此爲難。", "龍蛇現影筆端活，風雨驚人紙上寒。", "教子一經文墨續，讀書萬卷夜燈殘。", "一門數世衣冠盛，曾把君家家傳看。"]'),
('f24c54d7-1594-46c7-bffe-56983af42454','餞張宣慰三首  其三','王義山','宋','宋诗','song-poetry','','[]','種了甘棠打疊回，遮留競湊轍轅來。',64,'全唐诗/poet.song.222000.json','["種了甘棠打疊回，遮留競湊轍轅來。", "只存詩檐作行李，若問歸囊清過梅。", "抵爲運籌咨漢傑，傳聞近日築燕臺。", "爲言民力東南竭，好趁層霄閶闔開。"]'),
('53aed5d5-8f2d-45ec-a0cf-2a7fd56c49f2','贈心月相士','王義山','宋','宋诗','song-poetry','','[]','十五以前月，清光逐夜生。',96,'全唐诗/poet.song.222000.json','["十五以前月，清光逐夜生。", "自朔以至望，浸長而浸盈。", "十五以後月，明減而生魄。", "自望以至晦，浸微而浸闕。", "嗟彼天上月，有圓闕陰晴。", "惟有心月月，天者常清明。", "持此以鑒人，妍媸奚所遁。", "此月不在天，月在爾方寸。"]'),
('53819c20-eb49-4f5a-82fb-4b5ba7039350','挽白鹿洞賓呂善居','王義山','宋','宋诗','song-poetry','','[]','元是雙峯門下士，席間參請到源頭。',64,'全唐诗/poet.song.222000.json','["元是雙峯門下士，席間參請到源頭。", "魯人知有樂正子，漢世曾稱馬少游。", "白鹿洞賓儒領袖，紫陽教主道源流。", "有兒曾斫月中桂，家學相傳卒未休。"]'),
('65068863-a307-4f01-bc5b-67415377965a','和韓御史題滕王閣韻  其一','王義山','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','閣枕臺隍暇日臨，興懷風景寄情深。',64,'全唐诗/poet.song.222000.json','["閣枕臺隍暇日臨，興懷風景寄情深。", "江山爲友更添我，宇宙皆詩放縱吟。", "不盡川流朝復夜，無窮事會古來今。", "一般輸與漁翁好，閒是閒非不累心。"]'),
('d841bab3-5134-4465-8aa9-44a87cfe74cb','和韓御史題滕王閣韻  其二','王義山','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','喜瞻御史又來臨，感慨登高此興深。',64,'全唐诗/poet.song.222000.json','["喜瞻御史又來臨，感慨登高此興深。", "許大乾坤付盃酒，幾多景物入孤吟。", "慚無王勃詩家數，頼有韓公記古今。", "休訝江東暮雲隔，相逢萍水兩知心。"]'),
('6045ebf5-e8bc-4e38-9834-71e2dbf1c701','古意二首  其一','王義山','宋','宋诗','song-poetry','','[]','少年紅顔女，敷芬對芳樹。',84,'全唐诗/poet.song.222000.json','["少年紅顔女，敷芬對芳樹。", "盈盈淡艷粧，清歌雜妙舞。", "凝睇倚高樓，桐絲試一譜。", "世間知音稀，誰識姱節素。", "清貞守幽閨，不作凡子婦。", "容華委西山，良人兮何暮。", "空牀思悠悠，明月正當戶。"]'),
('9f0c6c82-cf10-451e-855d-6e621bff3540','古意二首  其二','王義山','宋','宋诗','song-poetry','','[]','東籬採秋菊，秋菊清且香。',72,'全唐诗/poet.song.222000.json','["東籬採秋菊，秋菊清且香。", "採之欲寄誰，聊以寓感傷。", "感傷何所思，故人天一方。", "故人日以遠，思君豈能忘。", "瞻望兮弗及，西山傾夕陽。", "黄昏人倚樓，一聲笛何長。"]'),
('fe577ad4-aac8-4041-937d-8640e78ccb18','贈陳梅垣','王義山','宋','宋诗','song-poetry','','[]','竹外重門不待扃，此垣繚繞自天成。',64,'全唐诗/poet.song.222000.json','["竹外重門不待扃，此垣繚繞自天成。", "一枝瀟灑無塵涴，半夜高寒對月明。", "特立丰標仁者靜，生平骨格聖之清。", "縱饒曾與逋仙約，只許溪前見影橫。"]'),
('8ec5aba3-eaa7-48f9-ad7a-accf8e99f008','挽雲屋徐侍郎  其一','王義山','宋','宋诗','song-poetry','','[]','闔朝奔逸蕩無關，夜半瀟瀟風雨寒。',64,'全唐诗/poet.song.222000.json','["闔朝奔逸蕩無關，夜半瀟瀟風雨寒。", "世亂爭先尋活路，時貧輸與做窮官。", "平生自謂學無事，一死諒非君所難。", "到此徬徨猶不忍，國亡那敢計身安。"]'),
('18d0181d-b3bc-4320-8f9b-59a48e950277','挽雲屋徐侍郎  其二','王義山','宋','宋诗','song-poetry','','[]','雁塔題名墨尚鮮，九州四海此同年。',64,'全唐诗/poet.song.222000.json','["雁塔題名墨尚鮮，九州四海此同年。", "故人直上青雲路，凡俗那能白骨仙。", "不善巧圖真箇拙，祇因方處久些圓。", "萬鍾不博簞瓢樂，有命何如有性焉。"]'),
('d55260dc-dde3-4f93-97b6-502503ddf600','送余仲謙赴江州教','王義山','宋','宋诗','song-poetry','','[]','廣文要飯又何難，所在侏儒爛飽餐。',64,'全唐诗/poet.song.222000.json','["廣文要飯又何難，所在侏儒爛飽餐。", "熱選儘教衆人取，冷官要耐五更寒。", "田園彭澤菊三逕，意思濂溪草一般。", "湓浦依然遺跡在，道源須是靜中看。"]'),
('2fa22e02-b4a0-4b16-bf48-2411fdbaef92','贈鄧可欺','王義山','宋','宋诗','song-poetry','','[]','萌一欺心理便虧，久之天定勝人爲。',64,'全唐诗/poet.song.222000.json','["萌一欺心理便虧，久之天定勝人爲。", "買臣負擔行吟日，韓信低頭出胯時。", "自怯終於强者弱，不爭是乃勝之基。", "彼來欺我自欺耳，只要我心無自欺。"]'),
('6d58a75a-64b6-4a7e-a82d-1b624185a9ee','冷舍偶成示兒','王義山','宋','宋诗','song-poetry','','[]','悔著當初誤出山，無聊情緒幾多般。',64,'全唐诗/poet.song.222000.json','["悔著當初誤出山，無聊情緒幾多般。", "儘教茅舍雲遮斷，已約梅花月送還。", "旅興須憑酒消遣，家書不住報平安。", "逢人休道爲官好，骨肉團欒勝做官。"]'),
('ff854137-1348-40ed-bd59-0ee1655dcfe9','贈丁道士遊浙','王義山','宋','宋诗','song-poetry','','[]','畢竟前身是令威，昂藏鶴樣更能詩。',32,'全唐诗/poet.song.222000.json','["畢竟前身是令威，昂藏鶴樣更能詩。", "此行遊遍江湖了，來訪逋仙又一奇。"]'),
('7167e26f-b06c-4bac-85ae-a1b6c89994b7','感興','王義山','宋','宋诗','song-poetry','','[]','靈均作天問，子厚爲之對。',84,'全唐诗/poet.song.222000.json','["靈均作天問，子厚爲之對。", "玄冥莫可詰，幻說多詭怪。", "蒼蒼特其形，厥義了難解。", "尼山自絕筆，人文已久壞。", "果有司造者，應不終泯晦。", "吾欲灰吾心，納世於聾聵。", "復爲崆峒民，穴野奚土蕢。"]'),
('6c9b11e1-cacf-41ba-8e92-d6dd43b7fee5','贈山村梅癯','王義山','宋','宋诗','song-poetry','','[]','我愛梅花村得好，來伴山村與卜鄰。',96,'全唐诗/poet.song.222000.json','["我愛梅花村得好，來伴山村與卜鄰。", "却有一般不村處，冰爲胸次玉爲神。", "別有村人村得俗，滿口肥甘爛錢穀。", "那知山村梅樣癯，肯向人言飯不足。", "山村切莫學我癡，腹中有字不療饑。", "會有東君老知己，隴頭先春寄一枝。"]'),
('4cc8bb02-038c-438d-85ff-2ecc03c700ae','梅梢上雪','王義山','宋','宋诗','song-poetry','','[]','六出霏霏過小簾，梅梢著處似沾粘。',32,'全唐诗/poet.song.222000.json','["六出霏霏過小簾，梅梢著處似沾粘。", "天工底事巧裝點，只爲花疏特故添。"]'),
('32e10eb1-e418-47b6-8231-c10b611fd3ec','謁申屠御史  其一','王義山','宋','宋诗','song-poetry','','[]','向來漢相肅朝綱，建武中興又說剛。',32,'全唐诗/poet.song.222000.json','["向來漢相肅朝綱，建武中興又說剛。", "等是當年名御史，到今百世又流芳。"]'),
('e53fc1ad-7e0c-4588-839d-b469fd5ac01c','謁申屠御史  其二','王義山','宋','宋诗','song-poetry','','[]','雲渺梁碭山水深，千年標致杳難尋。',32,'全唐诗/poet.song.222000.json','["雲渺梁碭山水深，千年標致杳難尋。", "祇今來伴東湖月，惟有沙鷗識此心。"]'),
('10b1af94-afd2-40b2-8e1a-199dd19af5ea','謁申屠御史  其三','王義山','宋','宋诗','song-poetry','','[]','褰帷問俗駐洪都，聽得輿人夾道呼。',32,'全唐诗/poet.song.222000.json','["褰帷問俗駐洪都，聽得輿人夾道呼。", "好事被君都做了，箇般風力自前無。"]'),
('f12d9257-7efb-46a6-8104-04a98f69db7e','申屠御史袖詩來訪和韻以謝  其一','王義山','宋','宋诗','song-poetry','','[]','曾侍鵷行步赤墀，入山正爲怕人知。',32,'全唐诗/poet.song.222000.json','["曾侍鵷行步赤墀，入山正爲怕人知。", "自慚不直百金伎，空有囊中藥不龜。"]'),
('b6ea8ba9-8144-4d40-9959-e77655ad30c4','申屠御史袖詩來訪和韻以謝  其二','王義山','宋','宋诗','song-poetry','','[]','滿前舞鱔雜號狸，攬轡澄清衆所期。',32,'全唐诗/poet.song.222000.json','["滿前舞鱔雜號狸，攬轡澄清衆所期。", "今日忠良方得路，願歌守道四賢詩。"]'),
('5334384c-f397-44f9-a1dc-ae0016f6c443','申屠御史袖詩來訪和韻以謝  其三','王義山','宋','宋诗','song-poetry','','[]','雲卿曾屈帥垣尊，詎謂如今古道存。',32,'全唐诗/poet.song.222000.json','["雲卿曾屈帥垣尊，詎謂如今古道存。", "驄馬行行人且避，如何容易到山村。"]'),
('fb22a5c6-b3da-4b0c-8dfc-5db5a69d659f','和九月十日紫極登高韻','王義山','宋','宋诗','song-poetry','','[]','誰報江州遣白衣，如雲勝友好追隨。',64,'全唐诗/poet.song.222000.json','["誰報江州遣白衣，如雲勝友好追隨。", "滿斟綠斝安排醉，牢裹烏紗照顧吹。", "兩箇重陽前後日，一年好景這些時。", "到今不數重山會，坐上元來欠了詩。"]'),
('d3224176-df58-4b76-832b-abd355d2bcaf','座間分韻得道字','王義山','宋','宋诗','song-poetry','','[]','一年景物秋最好，秋到重陽秋更老。',64,'全唐诗/poet.song.222000.json','["一年景物秋最好，秋到重陽秋更老。", "留取黄花待再來，慇懃寄與西風道。", "菊花了後到梅花，梅花開時雪交加。", "何當雪月交光夜，與君重約醉流霞。"]'),
('edc7aae2-dcd4-4f46-af86-701cbbf82ac7','挽竹薌龔侍郎  其一','王義山','宋','宋诗','song-poetry','','[]','猶記烏臺第一章，當年物論忒雌黄。',64,'全唐诗/poet.song.222000.json','["猶記烏臺第一章，當年物論忒雌黄。", "人心自有公非是，天理豈能終晦亡。", "姦魄雖生名已死，彈文尚濕墨猶香。", "偷生寧復百年活，地下何顔見竹薌。"]'),
('cc604914-bac6-4ebd-bb2c-cc29dd0c95bb','挽竹薌龔侍郎  其二','王義山','宋','宋诗','song-poetry','','[]','一木難支大厦傾，闔門拚却赴波鯨。',64,'全唐诗/poet.song.222000.json','["一木難支大厦傾，闔門拚却赴波鯨。", "歸來止爲尋墳隴，隠去不教知姓名。", "賸有詩篇傳不朽，相從野老話生平。", "翩翩隻鶴扶雲去，羣玉峯頭籍大清。"]'),
('bb6df757-7ed8-49fe-8e75-b1f2b0c4bc63','挽平軒王府判  其一','王義山','宋','宋诗','song-poetry','','[]','兒女來前痛別離，遺言埋骨用深衣。',32,'全唐诗/poet.song.222000.json','["兒女來前痛別離，遺言埋骨用深衣。", "當家曾把僧衣葬，誰識平生此意微。"]'),
('6965c73a-3cb6-41e6-a962-216c6e7f691f','挽平軒王府判  其二','王義山','宋','宋诗','song-poetry','','[]','猶記瓊林錫宴時，平軒折得好花歸。',32,'全唐诗/poet.song.222000.json','["猶記瓊林錫宴時，平軒折得好花歸。", "而今花與人何在，日暮江東雲自飛。"]'),
('20f4b5fc-eadd-4380-978a-208f2cb22660','謁按察馬僉事  其一','王義山','宋','宋诗','song-poetry','','[]','黷貨無厭政賄成，幾年蔀屋不曾晴。',64,'全唐诗/poet.song.222000.json','["黷貨無厭政賄成，幾年蔀屋不曾晴。", "擊奸霹靂從天降，燭物晶明揭日行。", "曩在烏臺已風采，特煩龍節更澄清。", "兒童走卒更相顧，夾道傳呼司馬名。"]'),
('6a68b4cb-0305-4793-804c-ebf86cc4b479','謁按察馬僉事  其二','王義山','宋','宋诗','song-poetry','','[]','化瑟新更擊巨貪，六條察吏首言贓。',64,'全唐诗/poet.song.222000.json','["化瑟新更擊巨貪，六條察吏首言贓。", "劃開雲覩青天日，全藉風聞白簡霜。", "僉謂激揚須獬豸，如何放過此豺狼。", "諸生饑欲死難忍，惟有廣文饜稻粱。"]'),
('d9a30ea6-79e3-4141-962b-b9b782df241b','贈鄧梓林','王義山','宋','宋诗','song-poetry','','[]','喬木森森說鄧林，自從拱把至于今。',64,'全唐诗/poet.song.222000.json','["喬木森森說鄧林，自從拱把至于今。", "雖然本質生成美，全是乃翁培植深。", "勿使杯棬戕所有，或容斤斧得而尋。", "非材自愧溝中斷，也有庭槐滿地陰。"]'),
('fcc52c4f-026f-434d-b9e1-11a962aec8fb','京庠校文和同考官','王義山','宋','宋诗','song-poetry','','[]','文堂翕聚衆星明，剖蚌揚沙著意精。',64,'全唐诗/poet.song.222000.json','["文堂翕聚衆星明，剖蚌揚沙著意精。", "幸執楮毫陪末席，敢將文字品諸生。", "烘堂莫共賡酬笑，徹夜惟聞倡嘆聲。", "要使西崑文體變，歐公不怕咈人情。"]'),
('1056f2f6-a332-4ce9-a445-9b2cd1fe1c75','月巖','王義山','宋','宋诗','song-poetry','','[]','巖中一箇月胚胎，知是誰將斧鑿開。',32,'全唐诗/poet.song.222000.json','["巖中一箇月胚胎，知是誰將斧鑿開。", "一夜六丁將帝敕，駕空推起上天來。"]'),
('69976d64-cbc9-4c63-900e-22e3118e0bd4','宿安仁縣市','王義山','宋','宋诗','song-poetry','','[]','安仁斗來大，地窄瞰官途。',48,'全唐诗/poet.song.222000.json','["安仁斗來大，地窄瞰官途。", "吏散晚衙早，人稀夜市無。", "山多田占少，澗曲水來迂。", "猶道茅包錦，縣官來索租。"]'),
('81bf2d80-92ff-440c-b61e-30eeea0ab277','丫頭巖','王義山','宋','宋诗','song-poetry','','[]','露出佳人半面看，曉鬟梳起碧雲團。',32,'全唐诗/poet.song.222000.json','["露出佳人半面看，曉鬟梳起碧雲團。", "路傍老盡幾春色，猶學丫頭不頂冠。"]'),
('64bb0a4f-ebef-473d-889f-024adfb89d73','偶成  其一','王義山','宋','宋诗','song-poetry','','[]','五性感而動，其間善惡萌。',48,'全唐诗/poet.song.222000.json','["五性感而動，其間善惡萌。", "危微相對立，體認要研精。", "大學靜而得，中庸誠則明。", "原頭不參透，何以約其情。"]'),
('9833b388-7d13-4e63-9a12-d46d5b23c734','偶成  其二','王義山','宋','宋诗','song-poetry','','[]','良貴由天賦，欺心天可欺。',48,'全唐诗/poet.song.222000.json','["良貴由天賦，欺心天可欺。", "功名皆夢幻，道理厭新奇。", "楓葉敲窗際，梅花對月時。", "箇般清趣味，料得少人知。"]'),
('b3968fb7-2a89-470c-b879-ee7549d79aea','夜宿嚴陵舟中','王義山','宋','宋诗','song-poetry','','[]','好風特地送帆開，刺破蘆花雪幾堆。',64,'全唐诗/poet.song.222000.json','["好風特地送帆開，刺破蘆花雪幾堆。", "浪裏煙波漁唱歇，岸頭更點雁聲催。", "船空載取月同去，蓬破偷將天入來。", "拂早起看鷗睡醒，笑儂抹過子陵臺。"]'),
('ecf9c069-aa9d-4c82-9004-b50be476872f','挽山居劉侯官  其一','王義山','宋','宋诗','song-poetry','','[]','渥漥生出此驊騮，父子當今第一流。',64,'全唐诗/poet.song.222000.json','["渥漥生出此驊騮，父子當今第一流。", "爭道老泉生二秀，最難錦水又三劉。", "慤亡明道碑東洛，塾死文公哭婺州。", "留得一家書脈在，郎君見說突煙樓。"]'),
('bd9e8ea3-49de-4d16-875a-d044c9b4a191','挽山居劉侯官  其二','王義山','宋','宋诗','song-poetry','','[]','賦埒相如軋子雲，詞場幾度策奇勳。',64,'全唐诗/poet.song.222000.json','["賦埒相如軋子雲，詞場幾度策奇勳。", "不卑銅綬肯爲宰，須是玉堂方著君。", "準擬日邊行接武，奈何地下要修文。", "試將六稿從頭讀，羞殺時流把硯焚。"]'),
('f1f3d0ba-e209-4feb-99e7-c63477da1c83','挽山居劉侯官  其三','王義山','宋','宋诗','song-poetry','','[]','雪坡仙去又山居，凋謝堪爲世道悲。',64,'全唐诗/poet.song.222000.json','["雪坡仙去又山居，凋謝堪爲世道悲。", "師魯僅存遺集在，樂天無限故人思。", "追懷把酒論文日，忍讀停雲對雨詩。", "千里有書報埋玉，銜哀莫寫淚交頤。"]'),
('bd10b966-868f-4fdf-8af7-1ce68b7ae360','題袁州邵錄三老圖  其一','王義山','宋','宋诗','song-poetry','','[]','堂前活現老人星，兩箇齊眉作壽朋。',32,'全唐诗/poet.song.222000.json','["堂前活現老人星，兩箇齊眉作壽朋。", "更有膝邊兒戲綵，此身都及見雲仍。"]'),
('2ac8d9b3-93ee-4686-9f08-40ef8ea00aec','題袁州邵錄三老圖  其二','王義山','宋','宋诗','song-poetry','','[]','不誇九老寫成圖，要似一家三老無。',32,'全唐诗/poet.song.222000.json','["不誇九老寫成圖，要似一家三老無。", "滿把壽觴拚一醉，父前母後子來扶。"]'),
('bad0ca23-2129-4a26-8eca-17da0ea5d000','和康節天意爲人二吟  其一','王義山','宋','宋诗','song-poetry','','[]','一毫矯揉不安然，人衆豈能終勝天。',64,'全唐诗/poet.song.222000.json','["一毫矯揉不安然，人衆豈能終勝天。", "透出夢關方是覺，要從心地自澄源。", "人能窮理始知命，事到容心便費言。", "造物安排都已定，道中浩浩而淵淵。"]'),
('a0bc4638-1219-464f-aeda-0b7765555fa5','和康節天意爲人二吟  其二','王義山','宋','宋诗','song-poetry','','[]','鳥獸不可與同羣，人道無虧方是人。',64,'全唐诗/poet.song.222000.json','["鳥獸不可與同羣，人道無虧方是人。", "已分工夫須盡我，學中本領在明倫。", "川雲意思乾坤外，盃酒襟懷天地春。", "識得眼前真道理，世間何事切吾身。"]'),
('e4485821-b208-457f-b703-75a119efbe05','挽熊墨莊','王義山','宋','宋诗','song-poetry','','[]','積穀翁家詫富强，千斯倉與萬斯箱。',64,'全唐诗/poet.song.222000.json','["積穀翁家詫富强，千斯倉與萬斯箱。", "儘教此輩更多蓄，輸與先生這一莊。", "身已九京名不朽，家藏萬卷字猶香。", "向來有子曾充賦，贏得此田常不荒。"]'),
('43fd1986-2807-4930-b843-7360fb953186','題韶州李同知百泉漱雪吟卷  其一','王義山','宋','宋诗','song-poetry','','[]','癖到膏肓藥不醫，把泉煮石煉成詩。',32,'全唐诗/poet.song.222000.json','["癖到膏肓藥不醫，把泉煮石煉成詩。", "齒根更著雪來嚼，吟過梅關又一奇。"]'),
('732b79f1-b261-4462-a9c7-21b1e69cf20a','題韶州李同知百泉漱雪吟卷  其二','王義山','宋','宋诗','song-poetry','','[]','奉命來宣古曲江，春回畫戟晝凝香。',32,'全唐诗/poet.song.222000.json','["奉命來宣古曲江，春回畫戟晝凝香。", "使君吟到蘇州意，願覩斯民一日康。"]'),
('79534952-b0f8-4186-af81-2252723fc37d','天問','王義山','宋','宋诗','song-poetry','','[]','鴻冥未判初，動靜根已互。',168,'全唐诗/poet.song.222000.json','["鴻冥未判初，動靜根已互。", "陰陽無停機，一闔一闢戶。", "太虛本塊氣，無形何八柱。", "四時自爾行，列星自爾布。", "吾聞女媧氏，曾把五色補。", "補處絕無痕，亦有未補處。", "日無息不運，何處獨陰霧。", "有龍銜燭照，終日燒不住。", "玉川子有言，日月作眼行。", "應不外幽獨，同此雙眼睛。", "彼何地而暗，乃假燭以明。", "亦有無燭地，暗塞幽冥冥。", "吾不解其故，蒼蒼徒具形。", "試喚盧仝鬼，爲我叩太清。"]'),
('cffb129a-6906-482a-bcc9-03c8e0b712e5','送按察魏經歷','王義山','宋','宋诗','song-poetry','','[]','公論難磨口似碑，肯將虛譽博人詩。',64,'全唐诗/poet.song.222000.json','["公論難磨口似碑，肯將虛譽博人詩。", "心常近厚元非弱，職在詳刑安忍施。", "兩載依然如始至，一廉豈是要人知。", "怕聞驄馬騎將去，惹起西人無限思。"]'),
('35a4f10e-62f2-43e8-9e49-0a07181d9f4b','挽熊縣丞','王義山','宋','宋诗','song-poetry','','[]','三嘆丞哉不負余，階庭蘭玉又森如。',64,'全唐诗/poet.song.222000.json','["三嘆丞哉不負余，階庭蘭玉又森如。", "鄉鄰稱道有是子，祖父傳來只此書。", "勇上璧流逼霄漢，相將金牓到門閭。", "從前不朽惟家學，不必籯金自有餘。"]'),
('67489bfe-ffe2-48d7-8107-abdf7333b26b','送昇甫歸九江  其一','王義山','宋','宋诗','song-poetry','','[]','雲無心出未爲非，鳥倦方還毋乃遲。',32,'全唐诗/poet.song.222000.json','["雲無心出未爲非，鳥倦方還毋乃遲。", "只爲當初欠歸早，教人枉費和陶詩。"]'),
('69e41add-bbfb-4eed-b4a2-0259d990e347','送昇甫歸九江  其二','王義山','宋','宋诗','song-poetry','','[]','猿鶴纔聞歸去來，便呼僮僕掃柴扉。',32,'全唐诗/poet.song.222000.json','["猿鶴纔聞歸去來，便呼僮僕掃柴扉。", "如何出市見車馬，惹起他心悔著歸。"]'),
('da04f6c6-3e1c-4d8c-9744-e717e9174111','讀東坡和陶詩有感','王義山','宋','宋诗','song-poetry','','[]','北門西掖傍丹墀，此正坡仙得意時。',32,'全唐诗/poet.song.222000.json','["北門西掖傍丹墀，此正坡仙得意時。", "不是惠州飯難喫，如何去做和陶詩。"]'),
('332b31d3-2694-4f1c-a9ea-7a5168ab873b','蚤起齋簷獨坐','王義山','宋','宋诗','song-poetry','','[]','輕寒測測雨冥冥，不覺閒中春一庭。',64,'全唐诗/poet.song.222000.json','["輕寒測測雨冥冥，不覺閒中春一庭。", "老竹似欺窗草綠，落梅微間翠苔青。", "倏聽鶑語調新曲，默看蛛絲網碎屏。", "物意人情兩相得，莫容塵俗撓中扃。"]'),
('9218da69-fa26-4c6d-bdd3-988053504499','挽黄松澗','王義山','宋','宋诗','song-poetry','','[]','少陵元是誰家數，衣鉢當初自審言。',64,'全唐诗/poet.song.222000.json','["少陵元是誰家數，衣鉢當初自審言。", "松澗於何尋的派，涪翁之後又仍孫。", "幾篇憂國詩奚寄，一念愛君天所根。", "不比騷人弄光景，讀君遺稿死猶存。"]'),
('b2497180-47d6-4c4e-a970-730110f2e11c','題汪才夫石城詩集','王義山','宋','宋诗','song-poetry','','[]','文到龍溪大家數，耳孫分剩有詩材。',32,'全唐诗/poet.song.222000.json','["文到龍溪大家數，耳孫分剩有詩材。", "只因住在修江近，接得涪翁一派來。"]'),
('c9051011-7b16-4527-9bbc-34426dfc6287','題何氏山陰道院  其一','王義山','宋','宋诗','song-poetry','','[]','從來道院江西好，只爲涪翁遂得名。',32,'全唐诗/poet.song.222000.json','["從來道院江西好，只爲涪翁遂得名。", "見說何家更清甚，院中終日讀書聲。"]'),
('53ea50fe-fb51-45fc-9116-88265d88ce55','題何氏山陰道院  其二','王義山','宋','宋诗','song-poetry','','[]','山陰偏被道家占，我祖當年曾寫經。',32,'全唐诗/poet.song.222000.json','["山陰偏被道家占，我祖當年曾寫經。", "君向陰中敞吟境，何時相伴鶴來聽。"]'),
('181c1c9a-772e-4f3e-8308-7ecc51ec822c','和王槐城寄詩韻','王義山','宋','宋诗','song-poetry','','[]','慣熟虀鹽味，誰云食淡難。',48,'全唐诗/poet.song.222000.json','["慣熟虀鹽味，誰云食淡難。", "舊嘗司國子，今又作儒官。", "有手肯炙熱，無氈不怕寒。", "芹香至今在，常夢到槐安。"]'),
('e2797964-b025-4db2-b3bc-efc862a5927c','挽介堂胡知郡  其一','王義山','宋','宋诗','song-poetry','','[]','憶昨雲從東野時，天街携手話心知。',64,'全唐诗/poet.song.222000.json','["憶昨雲從東野時，天街携手話心知。", "澹庵往矣誰其嗣，文定今之學者師。", "德邵年高前輩行，山摧木壞哲人萎。", "虎頭城下艱難共，古道如公更有誰。"]'),
('2f3d1ef4-d160-4053-86f8-c915a2001922','挽介堂胡知郡  其二','王義山','宋','宋诗','song-poetry','','[]','六館諸生伏下風，少年聲價在黌宮。',64,'全唐诗/poet.song.222000.json','["六館諸生伏下風，少年聲價在黌宮。", "交遊湖海天下士，規矩乾坤心匠中。", "竹使分符春坱圠，棠陰匝地晝朦朧。", "新昌人所難爲事，人到于今說介翁。"]'),
('2dd38b65-d1c0-41d0-b03b-1cc1f4123f9a','送按察王僉事除行臺察院  其一','王義山','宋','宋诗','song-poetry','','[]','漠漠天高不可呼，斯民何處訴無辜。',64,'全唐诗/poet.song.222000.json','["漠漠天高不可呼，斯民何處訴無辜。", "從來鷹隼肯敺雀，除却豺狼安問狐。", "霹靂一聲碎姦膽，風霜八路擊貪夫。", "得公數輩遍天下，民命從今盍少蘇。"]'),
('e3ba62be-c30f-4f20-8e21-2c350b263984','送按察王僉事除行臺察院  其二','王義山','宋','宋诗','song-poetry','','[]','奪去江西一福星，維揚無地著先聲。',64,'全唐诗/poet.song.222000.json','["奪去江西一福星，維揚無地著先聲。", "數千百里人相賀，二十四橋風便清。", "祇爲外臺要精采，更煩辣手大支撐。", "勸君放緩騎驄馬，怕有人來境上爭。"]'),
('65257469-57de-4dfd-ab81-e394f483117d','送奉使翰林頒降歷日回','王義山','宋','宋诗','song-poetry','','[]','歷家差只在毫釐，有詔清臺子細推。',64,'全唐诗/poet.song.222000.json','["歷家差只在毫釐，有詔清臺子細推。", "三代以來宗夏正，溥天之下再堯時。", "暫煩英節來將命，歸對薇花好賦詩。", "夜直禁林如有問，江南民力正瘡痍。"]'),
('b5c9146e-f2c8-43bc-a6ee-6d9a3c35d81c','書曹忠勇詩集','王義山','宋','宋诗','song-poetry','','[]','當家七步已稱雄，君更豪吟句律工。',64,'全唐诗/poet.song.222000.json','["當家七步已稱雄，君更豪吟句律工。", "瀘水城存空吊古，睢陽廟在凜生風。", "友聞不死世無敵，武惠重來戰有功。", "能不動心方是勇，教人以善謂之忠。"]'),
('0c0ff9b3-3927-4d16-abbb-cf7bee9a5e64','和清江韓伯善  其一','王義山','宋','宋诗','song-poetry','','[]','厥初是理與俱生，一點靈扃透處明。',64,'全唐诗/poet.song.222000.json','["厥初是理與俱生，一點靈扃透處明。", "誰肯枉身徇時好，從來造物忌文名。", "雌黄一任傍人說，暴白只依天理行。", "輸與老農無箇事，夕陽黄犢带煙耕。"]'),
('3f20dc2c-4ec3-4eab-9fd7-4cd94de19c09','和清江韓伯善  其二','王義山','宋','宋诗','song-poetry','','[]','世間利欲久胥淪，才有詩書不是貧。',64,'全唐诗/poet.song.222000.json','["世間利欲久胥淪，才有詩書不是貧。", "三極經綸須是學，一毫愧怍便非人。", "充之家國而天下，窮則江湖一釣綸。", "寄語黄州王學士，不妨借我華陽巾。"]'),
('cdb6972e-e26c-44c9-86a3-b0e2f73ca211','和清江韓伯善  其三','王義山','宋','宋诗','song-poetry','','[]','文章於道未爲尊，求道須教造大醇。',64,'全唐诗/poet.song.222000.json','["文章於道未爲尊，求道須教造大醇。", "理學一門要精密，時文大病在尖新。", "高談天下經綸易，誰療目前饑饉因。", "拚却掛冠高蹈去，孰云林下果無人。"]'),
('1cf78354-2500-4538-9f25-e61532b5ef2a','挽溪園周知郡  其一','王義山','宋','宋诗','song-poetry','','[]','英英玉立已班行，地位如何不廟堂。',64,'全唐诗/poet.song.222000.json','["英英玉立已班行，地位如何不廟堂。", "久合飛騰上華要，祇緣抱負太剛方。", "階庭競秀誇諸少，衣鉢先傳屬長郎。", "最是一家古三代，棣華今尚有餘芳。"]'),
('04fb651f-189c-4751-b3e5-daf88fd28aba','挽溪園周知郡  其二','王義山','宋','宋诗','song-poetry','','[]','記得年時試別頭，得君引我上瀛洲。',64,'全唐诗/poet.song.222000.json','["記得年時試別頭，得君引我上瀛洲。", "當場獨步眇餘子，好手先拈第一籌。", "錦水曾尋香戟夢，洪崖去伴赤松遊。", "瓣香遥致生芻敬，渺渺螺川涕泗流。"]'),
('08d7f562-4f52-4a6e-818f-2d8f54ad636b','題吳此民遠遊集','王義山','宋','宋诗','song-poetry','','[]','偪仄懷居非丈夫，吾今語子好遊乎。',64,'全唐诗/poet.song.222000.json','["偪仄懷居非丈夫，吾今語子好遊乎。", "沅湘到處有司馬，嵩華至今談小蘇。", "事會無窮閑宇宙，山川有盡眇江湖。", "奇聞壯觀多收拾，刮目他時看阿吳。"]'),
('a9326e4f-a6b8-47b7-91fa-29eb1fcc3aa6','挽松麓李僉判','王義山','宋','宋诗','song-poetry','','[]','手拈老筆眇詞場，餘子如何敢頡頏。',64,'全唐诗/poet.song.222000.json','["手拈老筆眇詞場，餘子如何敢頡頏。", "疑是前身真賀白，不然今世又蘇黄。", "片文落處人爭誦，一第欠於天取償。", "造物却教二郎做，立身既好又名揚。"]'),
('1a9aecf0-e10c-4c48-8b06-8750953deb86','挽李教授','王義山','宋','宋诗','song-poetry','','[]','偏是書生賦分慳，生平受用只儒酸。',64,'全唐诗/poet.song.222000.json','["偏是書生賦分慳，生平受用只儒酸。", "非無熱處可炙手，禁得寒時做冷官。", "乃父向年已科目，好兒今日又衣冠。", "期頤上壽古來少，歸去關山霧雨漫。"]'),
('0dff32b1-c059-4ce8-a595-436d06f3ecd4','題陳宗陽梅花全韻詩集','王義山','宋','宋诗','song-poetry','','[]','騷經比興殆無遺，何獨於梅靳一辭。',64,'全唐诗/poet.song.222000.json','["騷經比興殆無遺，何獨於梅靳一辭。", "從遜以來方有句，到逋而後愈難詩。", "形容雖巧跡之淺，吟狀愈多天者漓。", "獨在孤山孤絕處，定交惟有雪相知。"]'),
('9028f93e-2bd7-4615-8035-45bd16827b67','和申屠御史來豫章韻','王義山','宋','宋诗','song-poetry','','[]','一衣带水繞洪城，水不在深龍則靈。',64,'全唐诗/poet.song.222000.json','["一衣带水繞洪城，水不在深龍則靈。", "簾棟中間人渺渺，烟雲朝暮柳青青。", "肯將明月清風我，來伴西山南浦亭。", "好把甘泉洗貪酷，生民血漬吏牙腥。"]'),
('47a2c405-e5e5-4386-a4e0-e9704f07a607','十月海棠盛開','王義山','宋','宋诗','song-poetry','','[]','海棠攙得小春天，獨向晴窗弄午烟。',32,'全唐诗/poet.song.222000.json','["海棠攙得小春天，獨向晴窗弄午烟。", "造物胡爲太顛倒，此花怎敢占梅先。"]'),
('e1312786-5138-4163-ac7a-b0d4c140bcc4','挽善慶堂黎朝奉','王義山','宋','宋诗','song-poetry','','[]','聞孫姓字魁天下，知是堂中積善深。',64,'全唐诗/poet.song.222000.json','["聞孫姓字魁天下，知是堂中積善深。", "天豈有私惟福善，公於責報本無心。", "方來諸少庭森玉，管取明科榜又金。", "他日貂蟬食家廟，一門青紫列如林。"]'),
('ebda3d52-9bc8-4adf-8dea-d83a2165f9b2','贈醫士熊月湖  其一','王義山','宋','宋诗','song-poetry','','[]','緣何扁鵲號良醫，傳法元來飲上池。',32,'全唐诗/poet.song.222000.json','["緣何扁鵲號良醫，傳法元來飲上池。", "化作月湖湖內水，願捐一滴救瘡痍。"]'),
('034df2c9-fac2-42b7-96c5-759bdb3b8e00','贈醫士熊月湖  其二','王義山','宋','宋诗','song-poetry','','[]','月湖鏡樣十分清，診視還他指下明。',32,'全唐诗/poet.song.222000.json','["月湖鏡樣十分清，診視還他指下明。", "那似月湖心地好，願人常似兔長生。"]'),
('4c8480b3-312e-457b-8fc0-5dd863f1b060','小圃梅柳之爭 梅與柳爭','王義山','宋','宋诗','song-poetry','','[]','水邊半樹月模糊，移取山來更姓孤。',32,'全唐诗/poet.song.222000.json','["水邊半樹月模糊，移取山來更姓孤。", "未許淵明全占斷，盍留一半乞林逋。"]'),
('2afa443f-fa5f-40fa-ad74-eb744a85b308','小圃梅柳之爭 柳與梅爭','王義山','宋','宋诗','song-poetry','','[]','梅兄住在水之濱，五柳先生便有云。',32,'全唐诗/poet.song.222000.json','["梅兄住在水之濱，五柳先生便有云。", "傳語林逋須著讓，堤邊風景要平分。"]'),
('e2dcbab0-c5f8-4abc-847c-9beadb3bd0c8','挽家溪危知郡','王義山','宋','宋诗','song-poetry','','[]','當家舊只說驪塘，近代家溪名又香。',64,'全唐诗/poet.song.222000.json','["當家舊只說驪塘，近代家溪名又香。", "仁智扁齋天動靜，正邪抗疏界陰陽。", "傷哉所到方丹轂，惜也斯人不玉堂。", "孤負錦江人望斷，使君已在白雲鄉。"]'),
('65cce7a8-418d-4674-bfe2-54168491828c','挽蘇少章','王義山','宋','宋诗','song-poetry','','[]','曾趁當年桂子秋，煩公引領廣寒遊。',64,'全唐诗/poet.song.222000.json','["曾趁當年桂子秋，煩公引領廣寒遊。", "春官報罷笑歸去，底事無成付命休。", "詩又江湖一家數，學尋伊洛到源頭。", "忍將感興篇來讀，望斷修江無限愁。"]'),
('685dc28f-ae27-4017-84ee-e91cf1ce79be','題黄草塘詩集','王義山','宋','宋诗','song-poetry','','[]','憑何强占謝家塘，尀耐詩人忒煞狂。',32,'全唐诗/poet.song.222000.json','["憑何强占謝家塘，尀耐詩人忒煞狂。", "只把兩家詩判斷，此塘一半合還黄。"]'),
('fc7a3f2a-e994-4405-a4a7-174e57ce154b','挽胡經幹','王義山','宋','宋诗','song-poetry','','[]','手畫兵家八陣圖，兒時此志已吞吳。',64,'全唐诗/poet.song.222000.json','["手畫兵家八陣圖，兒時此志已吞吳。", "英雄豪傑所同者，將相王侯有種乎。", "事竟無成空感慨，天胡不忍死須臾。", "東南留得斯人在，半壁乾坤隻手扶。"]'),
('c0bfe4c2-c962-4c5c-8000-63aa7f75d274','題武岡向敏衡無加莊','王義山','宋','宋诗','song-poetry','','[]','恭惟陳簡齋，與鶴山魏公。',228,'全唐诗/poet.song.222000.json','["恭惟陳簡齋，與鶴山魏公。", "堂堂二先生，後學之所宗。", "遺跡所到處，百世猶高風。", "武岡有向氏，乃祖家詩禮。", "簡齋曾來訪，鶴山亦踵至。", "二先生來時，草木亦光賁。", "主人跼蹐迎，出門見大賓。", "大带束深衣，整容而肅襟。", "揖客坐上坐，樽酒與細論。", "向氏家本儒，苦無黄金籯。", "惟有無加莊，留以遺子孫。", "此莊不在田，非謂三百囷。", "莊者敬之謂，爲學之入門。", "乃祖燕後人，有書便不貧。", "能令二先生，肯來共斯文。", "向來吾南昌，隠者蘇雲卿。", "魏公令地主，而來訪一民。", "匹夫道義重，王侯失其尊。", "古人不傲士，此風今猶存。"]'),
('a5edc538-c511-4b95-89a7-8f347bba6cd2','挽橫海曾朝議','王義山','宋','宋诗','song-poetry','','[]','父子眉山多一蘇，衣冠盛事再堪圖。',64,'全唐诗/poet.song.222000.json','["父子眉山多一蘇，衣冠盛事再堪圖。", "岫雲懶出官情薄，霖雨未成輿望孤。", "橫海僅存遺藁在，臨川有此老師無。", "瓣香久欠南豐敬，東望靈車天一隅。"]'),
('b3ced153-5c43-4fdc-8a68-c9a617baeb2a','東湖拜朔非禮去職諸生以詩留行和其韻以謝之','王義山','宋','宋诗','song-poetry','','[]','只有春風無世態，世間冷暖若爲情。',64,'全唐诗/poet.song.222000.json','["只有春風無世態，世間冷暖若爲情。", "廢經彼自違先聖，議禮終難强兩生。", "不合拂衣吾竟去，誰云出晝待留行。", "雲卿數畝園猶在，已結東湖松菊盟。"]'),
('b666dd2c-9ad6-44ac-a8b8-b18dc58be600','送孫糾彈歸鎮江','王義山','宋','宋诗','song-poetry','','[]','不待文公立學規，士當無愧此深衣。',64,'全唐诗/poet.song.222000.json','["不待文公立學規，士當無愧此深衣。", "無人可糾孰挑達，有過不彈誰是非。", "不怕轉喉能觸諱，自言垂老盍知歸。", "只從北固山頭處，直道留爲晚景輝。"]'),
('e2253dd7-3835-44a2-b465-07b7ce1b935a','餞申屠御史歸揚州行臺','王義山','宋','宋诗','song-poetry','','[]','僻在江南天一隅，煩公原隰遍馳驅。',64,'全唐诗/poet.song.222000.json','["僻在江南天一隅，煩公原隰遍馳驅。", "數元結輩已多矣，百子駿今安得乎。", "風力喧傳真御史，霜臺勇在去貪夫。", "翩翩隻鶴騎將去，若問腰纏一孔無。"]'),
('ad1af234-1e03-4a9c-bf42-b761d45e6dd0','謁中齋楊左丞','王義山','宋','宋诗','song-poetry','','[]','向來曾拜紫宸衙，親見先班奉日霞。',64,'全唐诗/poet.song.222000.json','["向來曾拜紫宸衙，親見先班奉日霞。", "帝室館甥貴公子，王姬下嫁舊儒家。", "執中默契心傳妙，勤有無窮學問加。", "带取孤山來作伴，清吟尚可趁梅花。"]'),
('98abd96a-d495-463e-b648-c7e7ed8d9c0d','餞長白李左丞','王義山','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','徃來不特地之靈，西有長庚一點星。',64,'全唐诗/poet.song.222000.json','["徃來不特地之靈，西有長庚一點星。", "九路大開行省府，幾人爭看小朝廷。", "只消餘力鎮衡岳，許大先聲到洞庭。", "浄洗甲兵從此去，煩公更爲挽滄溟。"]'),
('3e7ee753-ce53-4689-85e6-445bbf3d7949','跋楊中齋詩詞集','王義山','宋','宋诗','song-poetry','','[]','江西派已遠，後來無聞人。',204,'全唐诗/poet.song.222000.json','["江西派已遠，後來無聞人。", "許大能詩聲，來自浙之濱。", "奚奴背錦囊，馬蹄踏青春。", "來派江西詩，風月浩無垠。", "翩翩佳公子，皆綺紈其身。", "惟君獨不然，每恨無書貧。", "胸中國子監，所積皆輪囷。", "把酒讀君詩，一字一精神。", "句裏带梅香，不涴半點塵。", "家本住孤山，和靖與卜鄰。", "吾聞詩之天，不在巧與新。", "纖穠寄淡泊，清峭寓簡淳。", "古律尤崛奇，可與子建親。", "此詩實兼之，體具衆美純。", "載哦長短篇，音節中韶鈞。", "少游詞如詩，二者皆逼真。", "再拜卷錦還，願言寶所珍。"]'),
('9af9b0df-584e-47db-9bf2-a2125d995fb8','送丁直諒赴西澗山長  其一','王義山','宋','宋诗','song-poetry','','[]','西澗元來只是劉，葉公爭取過台州。',32,'全唐诗/poet.song.222000.json','["西澗元來只是劉，葉公爭取過台州。", "退齋赤手來興復，上水篙撐急向流。"]'),
('6c30c577-bb88-4172-87ca-15d1eb03e846','送丁直諒赴西澗山長  其二','王義山','宋','宋诗','song-poetry','','[]','去時行李只携琴，更带奚奴作伴行。',32,'全唐诗/poet.song.222000.json','["去時行李只携琴，更带奚奴作伴行。", "所謂伊人何所似，漪漪澗水一般清。"]'),
('a5887f4c-eea1-4165-8985-b283a6f9a79a','送允中齋王參政入閩','王義山','宋','宋诗','song-poetry','','[]','未到三山聲已雷，此行正好趁梅開。',64,'全唐诗/poet.song.222000.json','["未到三山聲已雷，此行正好趁梅開。", "榜文爭看乖崖押，士類歡呼常衮來。", "不信閩中能獨占，要令天下總春回。", "江西爭得公來定，只怕朝家有詔催。"]'),
('62badc65-6dde-405d-9187-971874be1fa1','題杜氏匏瓜亭','王義山','宋','宋诗','song-poetry','','[]','道包衆妙起經綸，粒粟中藏天地仁。',64,'全唐诗/poet.song.222000.json','["道包衆妙起經綸，粒粟中藏天地仁。", "五石匏徒誇彼大，一瓢飲有樂之真。", "從來碩果存生意，吾豈匏瓜係此身。", "文穆此心唯念舊，還能續得饉亭春。"]'),
('41819f4a-2e1d-4641-abca-8588d7522638','謁參政張獻子','王義山','宋','宋诗','song-poetry','','[]','曾侍龍樓曉色催，真仙那肯下蓬萊。',64,'全唐诗/poet.song.222000.json','["曾侍龍樓曉色催，真仙那肯下蓬萊。", "離方共覩重光日，震位欣聞長子雷。", "奉使祇應天上去，運籌暫作幄中來。", "老夫羞把詩懷袖，只爲明公是秀才。"]'),
('19a8101c-1152-4371-bef5-a7cb33aba057','五無歌送張參政','王義山','宋','宋诗','song-poetry','','[]','一錢劉太守，也被一錢污。',120,'全唐诗/poet.song.222000.json','["一錢劉太守，也被一錢污。", "今日公歸去，一文錢也無。", "臨去受百紙，清哉杜大夫。", "今日公歸去，半張紙也無。", "清獻出蜀日，琴鶴與之俱。", "今日公歸去，琴和鶴也無。", "東山船載月，皎潔如冰壺。", "今日公歸去，船中月也無。", "問公何所有，所有與人殊。", "只有一廉字，斯人百世無。"]'),
('44805eeb-bf6b-4088-a14e-ef39b333eb62','題黄高士雪月集','王義山','宋','宋诗','song-poetry','','[]','冰作丰姿水作神，羣仙境界裏詩人。',64,'全唐诗/poet.song.222000.json','["冰作丰姿水作神，羣仙境界裏詩人。", "敲從竹起韻不俗，吟到梅來相逼真。", "無己許令參後社，庭堅端的是前身。", "有時石鼎堪聯句，還許平分坐上春。"]'),
('db472b28-98ac-4b6e-ae7a-0f96b9b54589','餞行省郎中王君祥','王義山','宋','宋诗','song-poetry','','[]','以儒飾吏號通材，忽報曹裝打疊回。',64,'全唐诗/poet.song.222000.json','["以儒飾吏號通材，忽報曹裝打疊回。", "箇樣歸舟惟載月，若爲送客只將梅。", "雲凝春樹何堪別，晝永甘棠待再來。", "無限依依懷渭水，攬衣不寢夜徘徊。"]'),
('f2c5189d-b250-414a-aefe-906f918eedd4','別中齋楊左丞','王義山','宋','宋诗','song-poetry','','["\u897f\u6e56"]','孤山久無主，誰伴月昏黄。',48,'全唐诗/poet.song.222000.json','["孤山久無主，誰伴月昏黄。", "歸興西湖動，離情南浦傷。", "官清從馬瘦，政暇又詩忙。", "莫羨和羹事，林逋有暗香。"]'),
('a34d29b0-74be-4c6c-a12c-827a4bbbe08e','和陳榮可感興韻','王義山','宋','宋诗','song-poetry','','[]','元豈好聱張豈乖，世間役役逐塵埃。',64,'全唐诗/poet.song.222000.json','["元豈好聱張豈乖，世間役役逐塵埃。", "容心於物爲身穽，得意之時即禍媒。", "退一步思方是足，放三分弱豈真呆。", "悠然獨坐吟窗下，忽見梅花一朵開。"]'),
('06dcf78d-dbc2-4a3d-982c-e42c21813843','和胡方湖雪韻','王義山','宋','宋诗','song-poetry','','[]','麻姑粒米撒天葩，山色模糊未盡遮。',64,'全唐诗/poet.song.222000.json','["麻姑粒米撒天葩，山色模糊未盡遮。", "月斧鑿天飛下屑，風刀翦水簇成花。", "有時覓句尋歐約，不慣斟羔學黨家。", "呵手撚梅窗下看，只嫌紅蒂带村些。"]'),
('9db46f37-5f50-4bda-ba11-ef906c1bd931','枕上聞風','王義山','宋','宋诗','song-poetry','','[]','風撼林間萬竅開，耳邊雨带暮潮來。',32,'全唐诗/poet.song.222000.json','["風撼林間萬竅開，耳邊雨带暮潮來。", "似知書困難爲覺，剛把天聲爲喚回。"]'),
('e1f6e398-9c81-4ec8-827d-21156aa0afe5','餞怡齋胡憲使','王義山','宋','宋诗','song-poetry','','[]','不是胸中熟呂刑，如何議讞極詳明。',64,'全唐诗/poet.song.222000.json','["不是胸中熟呂刑，如何議讞極詳明。", "嚴於三尺古來法，寬以一分天好生。", "仁意滿腔皆惻隠，政聲交口說廉平。", "玉堂本是青氈舊，跳過郎星向上行。"]'),
('414b22eb-ea17-4dbb-973a-11556bef9f2c','盛暑夜起','王義山','宋','宋诗','song-poetry','','[]','大塊勞形爲有生，爲生受役自紛然。',64,'全唐诗/poet.song.222000.json','["大塊勞形爲有生，爲生受役自紛然。", "幾年寒暑人間世，一點靈明心上天。", "欲待足時無了日，只今悟處是真詮。", "煙霞終是吾歸處，誰道丹砂可引年。"]'),
('cd3a7d3d-6614-436b-b904-6c4ab2fac847','壽崇節致語口號','王義山','宋','宋诗','song-poetry','','[]','東極承顔肅紫宸，恩醲湛露燕羣臣。',64,'全唐诗/poet.song.222000.json','["東極承顔肅紫宸，恩醲湛露燕羣臣。", "香傳禁柳鳴球瑟，影顫宮花藹縉紳。", "璀璨祥光三殿曉，怡愉和氣萬年春。", "明朝又紀流虹瑞，更效封人祝聖人。"]'),
('ea1cc8f3-a849-458e-bb4f-7da2c20ae57e','對廳致語口號','王義山','宋','宋诗','song-poetry','','[]','八葉蓂香夏氣清，坤闈有慶佛同生。',64,'全唐诗/poet.song.222000.json','["八葉蓂香夏氣清，坤闈有慶佛同生。", "楓宸稱壽雲霄迥，苹野霑恩雨露深。", "祚永萬年齊晉福，孝濡九有樂升平。", "電樞又報祥光繞，需拜揚休天子明。"]'),
('15857e06-8860-4283-8b2c-33d32eeb5fb7','吳仙詩','王義山','宋','宋诗','song-poetry','','[]','一曲清歌艷彩鸞，金爐香擁氣如蘭。',32,'全唐诗/poet.song.222000.json','["一曲清歌艷彩鸞，金爐香擁氣如蘭。", "西山高與南山接，剩有當時却老丹。"]'),
('763dc449-f322-48a0-a34f-710739c30f14','諶仙詩','王義山','宋','宋诗','song-poetry','','[]','冉冉飛霜綴綺裳，遥知諶母下丹陽。',32,'全唐诗/poet.song.222000.json','["冉冉飛霜綴綺裳，遥知諶母下丹陽。", "黄金鍊就三山藥，來採蒲花獻壽觴。"]'),
('6586e28e-e5c9-40af-9702-79517ac450ef','鶴仙詩','王義山','宋','宋诗','song-poetry','','[]','飲馬池邊號浴仙，仙姿花鶴古今傳。',32,'全唐诗/poet.song.222000.json','["飲馬池邊號浴仙，仙姿花鶴古今傳。", "金經尤有延年訣，未數莊椿壽八千。"]'),
('5591d893-7d00-438f-b6f7-eb1a13d7a75b','龍仙詩','王義山','宋','宋诗','song-poetry','','[]','楚尾吳頭風乍薰，滄波深擁小龍君。',32,'全唐诗/poet.song.222000.json','["楚尾吳頭風乍薰，滄波深擁小龍君。", "願朝帝母龍樓晚，來曳霞裾駕五雲。"]'),
('154d9562-a668-4bb0-8471-09cb19fb8732','柏仙詩','王義山','宋','宋诗','song-poetry','','[]','古柏林間小劍仙，雲鬟低綰嚲輕蟬。',32,'全唐诗/poet.song.222000.json','["古柏林間小劍仙，雲鬟低綰嚲輕蟬。", "願持天上長生籙，來祝東朝億萬年。"]'),
('c4a5f2d2-c998-4b73-a4bf-e7d9714b8ec5','王母祝語','王義山','宋','宋诗','song-poetry','','[]','壺嶠天低樂聖時，南薰初試度蘭池。',64,'全唐诗/poet.song.222000.json','["壺嶠天低樂聖時，南薰初試度蘭池。", "影飛霞佩朝金殿，曲奏雲和獻玉巵。", "稽首萬年堯曆永，承顔五色舜衣垂。", "仙家更有蟠桃在，明日重來謁帝墀。"]'),
('25446e0a-0859-4a84-abe9-dce6e6db186b','王母祝語 萬年枝詩','王義山','宋','宋诗','song-poetry','','[]','百子池邊種最奇，無人識是萬年枝。',64,'全唐诗/poet.song.222000.json','["百子池邊種最奇，無人識是萬年枝。", "細花密葉青青子，常得披香雨露滋。", "東風向晚薰風早，禁路飛花沾壽草。", "年年聖主壽慈闈，先獻此花名字好。"]'),
('fee521e2-752f-44ad-a3b1-6e9daf4bf99c','王母祝語 長春花詩','王義山','宋','宋诗','song-poetry','','[]','東風不與世情同，多付春光向此中。',64,'全唐诗/poet.song.222000.json','["東風不與世情同，多付春光向此中。", "葉裏儘藏雲外綠，枝頭賸带日邊紅。", "百花能占春多少，何似春顔長自好。", "清和時候卷紅綃，端的長春春不老。"]'),
('b7d38243-9ae4-4d3b-96f7-61fc7a8cab7e','王母祝語 菖蒲花詩','王義山','宋','宋诗','song-poetry','','[]','昔年有母見花輪，富貴長年不記春。',64,'全唐诗/poet.song.222000.json','["昔年有母見花輪，富貴長年不記春。", "今報紫茸依碧節，獻來慈極壽莊椿。", "漢家天子嵩山路，又見蒲仙相與語。", "而今帝母兩怡愉，莫忘九疑山上侶。"]'),
('32015287-08c0-45d0-92d8-343d3542df41','王母祝語 萱草花詩','王義山','宋','宋诗','song-poetry','','[]','當年樹背入詩章，綠葉丹花有暉光。',64,'全唐诗/poet.song.222000.json','["當年樹背入詩章，綠葉丹花有暉光。", "爲道宜男仍永世，福齊太姒熾而昌。", "猶記夏侯曾與賦，灼灼朱華凝瑞露。", "紫微右極是慈闈，歲歲丹霞天近處。"]'),
('fa9bd15d-9a50-407f-99d1-2a11fdba2e00','王母祝語 石榴花詩','王義山','宋','宋诗','song-poetry','','[]','待闕南風欲上場，陰陰穉綠繞丹牆。',64,'全唐诗/poet.song.222000.json','["待闕南風欲上場，陰陰穉綠繞丹牆。", "石榴已著乾紅蕾，無盡春光儘更强。", "不因博望來西域，安得名花出安石。", "朝元閣上舊風光，猶是太真親手植。"]'),
('e969dfd5-f407-4726-89ee-2d34a96a87a8','王母祝語 梔子花詩','王義山','宋','宋诗','song-poetry','','[]','當年曾記晉華林，望氣紅黄梔子深。',64,'全唐诗/poet.song.222000.json','["當年曾記晉華林，望氣紅黄梔子深。", "有敕諸宮勤守護，花開如玉子如金。", "此花端的名薝蔔，千佛林中清更潔。", "從知帝母佛同生，移向慈元供壽佛。"]'),
('518224be-143a-4806-856a-431e57e048e6','王母祝語 薔薇花詩','王義山','宋','宋诗','song-poetry','','[]','碎剪紅綃間綠叢，風流疑在列仙宮。',64,'全唐诗/poet.song.222000.json','["碎剪紅綃間綠叢，風流疑在列仙宮。", "朝真更欲薰香去，爭擲霓衣上寶籠。", "忽驚錦浪洗春色，又似宮娃逞粧飾。", "會當一遣移花根，還比蒲桃天上植。"]'),
('06d61f5d-a6ee-4179-8b14-4737ff181d56','王母祝語 芍藥花詩','王義山','宋','宋诗','song-poetry','','[]','倚竹佳人翠袖長，阿姨天上舞霓裳。',64,'全唐诗/poet.song.222000.json','["倚竹佳人翠袖長，阿姨天上舞霓裳。", "嬌紅凝臉西施醉，青玉欄干說疊香。", "晚春早夏揚州路，濃粧初試鵞紅妬。", "何如御傘掖垣中，日日傳宣金掌露。"]'),
('e68140f5-540b-4cb1-bd8f-1104fc0ebe64','王母祝語 宮柳花詩','王義山','宋','宋诗','song-poetry','','[]','御牆側畔綠垂垂，接夏連春花點衣。',64,'全唐诗/poet.song.222000.json','["御牆側畔綠垂垂，接夏連春花點衣。", "好似雪茵胡旋舞，樓臺簾幙燕初飛。", "薰風日永彤墀曉，宮妃簇仗呈千巧。", "就中妙舞最工奇，戲衮玉毬添一笑。"]'),
('a8d8e530-2a7b-46ce-8b7e-052f33deb3d9','王母祝語 蟠桃花詩','王義山','宋','宋诗','song-poetry','','[]','蘂珠仙子駕紅雲，來說瑶池分外春。',64,'全唐诗/poet.song.222000.json','["蘂珠仙子駕紅雲，來說瑶池分外春。", "道是當年和露種，三千花實又從新。", "紅雲元透西崑路，青鳥銜枝花顫舞。", "薰風初動子成初，消息一年傳一度。"]'),
('b76fb405-c26b-47f8-8906-cb50678387a1','甘露堂','王義山','宋','宋诗','song-poetry','','[]','掃除黄葉拂塵埃，講座雖虛尚有臺。',64,'全唐诗/poet.song.222000.json','["掃除黄葉拂塵埃，講座雖虛尚有臺。", "歲晚喬松典型在，烟波疊嶂畫圖開。", "不須瑞露從天降，應是慈雲爲客來。", "須信中邊甜似蜜，吟詩未足報崔嵬。"]'),
('b8cbabd3-4438-4b85-bd36-8649d04cfa00','壽馬裕齋觀文 山之高，三章，章四句。 其一','陳著','宋','宋诗','song-poetry','','[]','天作高山，大邦之屏。',20,'全唐诗/poet.song.222000.json','["天作高山，大邦之屏。", "外禦其侮，王國庶定。"]'),
('ca98b110-5c28-48b3-a821-8e2516930c5c','壽馬裕齋觀文 山之高，三章，章四句。 其二','陳著','宋','宋诗','song-poetry','','[]','維石巖巖，維德之基。',20,'全唐诗/poet.song.222000.json','["維石巖巖，維德之基。", "天實爲之，是以似之。"]'),
('da3afdd8-bcc2-4086-84d8-35ffe1340f96','壽馬裕齋觀文 山之高，三章，章四句。 其三','陳著','宋','宋诗','song-poetry','','[]','人亦有言，如山之壽。',20,'全唐诗/poet.song.222000.json','["人亦有言，如山之壽。", "萬有千歲，保艾爾後。"]'),
('39e36f7a-57f5-4614-bd7d-1ff55c067d14','壽馬裕齋觀文 江之永，三章，章四句。 其一','陳著','宋','宋诗','song-poetry','','[]','江之永矣，其流湯湯。',20,'全唐诗/poet.song.222000.json','["江之永矣，其流湯湯。", "整我六師，告成于王。"]'),
('8ccd04bb-d161-46da-858b-8b8eb07bda54','壽馬裕齋觀文 江之永，三章，章四句。 其二','陳著','宋','宋诗','song-poetry','','[]','春日載陽，薄言采芑。',20,'全唐诗/poet.song.222000.json','["春日載陽，薄言采芑。", "泳之游之，民之洽矣。"]'),
('0dabfdec-54b2-4a60-aa0f-30619512eb35','壽馬裕齋觀文 江之永，三章，章四句。 其三','陳著','宋','宋诗','song-poetry','','[]','清且淪漪，有美一人。',20,'全唐诗/poet.song.222000.json','["清且淪漪，有美一人。", "懷哉懷哉，率土之濱。"]'),
('87276ad6-f58a-4f40-88b9-e1e782c7af44','壽馬裕齋觀文 東山，二章，章四句。 其一','陳著','宋','宋诗','song-poetry','','[]','我徂東山，以敖以遊。',20,'全唐诗/poet.song.222000.json','["我徂東山，以敖以遊。", "彼采葛兮，謂我何求。"]'),
