('417aedbd-bb89-4f7b-9316-7520146b5b86','橫橋觀薺','陳著','宋','宋诗','song-poetry','','[]','物理元隨世事新，靜觀知是泮宮人。',32,'全唐诗/poet.song.222000.json','["物理元隨世事新，靜觀知是泮宮人。", "穿花野薺雖微草，也占年年一分春。"]'),
('c02ca9aa-b08b-49da-9c00-29931d6b57c7','錦里觀桃','陳著','宋','宋诗','song-poetry','','[]','錦里風光分外春，桃花如市趁時新。',32,'全唐诗/poet.song.222000.json','["錦里風光分外春，桃花如市趁時新。", "鬭風車馬香塵裏，誰是朱門覓水人。"]'),
('6cbf06ff-d1f2-4ea5-bf7d-5395d30dee68','夜坐書懷','陳著','宋','宋诗','song-poetry','','[]','竹窗鐙火足相陪，惟怕梅花畫角催。',32,'全唐诗/poet.song.222000.json','["竹窗鐙火足相陪，惟怕梅花畫角催。", "我欲敧眠尋好夢，照人隙月更徘徊。"]'),
('3a30ff28-8c51-4458-b6e9-03cd87ecfe9f','午景書懷','陳著','宋','宋诗','song-poetry','','[]','虛齋簷馬自丁東，却在鶑啼燕語中。',32,'全唐诗/poet.song.222000.json','["虛齋簷馬自丁東，却在鶑啼燕語中。", "整屐欲尋花信息，不知柳絮已隨風。"]'),
('480161e2-a3aa-4488-ba75-56ef3d9f441f','詠不開牡丹','陳著','宋','宋诗','song-poetry','','[]','一種仙根自洛陽，春深何事不花生。',32,'全唐诗/poet.song.222000.json','["一種仙根自洛陽，春深何事不花生。", "芳心未必全羞澀，猶恨東風用力輕。"]'),
('b6dea1cb-4463-46e1-b050-c2bc1ae0cb53','次韻童志道春晚','陳著','宋','宋诗','song-poetry','','[]','隔窗啼鳥夢驚殘，沈麝香銷冷博山。',32,'全唐诗/poet.song.222000.json','["隔窗啼鳥夢驚殘，沈麝香銷冷博山。", "隻枕半敧閒猛省，又添一日在人閒。"]'),
('dc8b86d7-0068-4886-89f0-4cf8b707331c','春午二首  其一','陳著','宋','宋诗','song-poetry','','[]','春城那被酒纏綿，燕姹鶑嬌近午天。',32,'全唐诗/poet.song.222000.json','["春城那被酒纏綿，燕姹鶑嬌近午天。", "花影滿簾庭院寂，碧紗窗迥淡如煙。"]'),
('896079d7-744a-49de-babf-6bb218f593a6','春午二首  其二','陳著','宋','宋诗','song-poetry','','[]','著雨楊花困舞綿，煖風揚作晚晴天。',32,'全唐诗/poet.song.222000.json','["著雨楊花困舞綿，煖風揚作晚晴天。", "一場春色歸何處，芳草斜陽淡淡煙。"]'),
('228986b3-a7ba-4ab1-acd7-67f00dd6690e','傷春','陳著','宋','宋诗','song-poetry','','[]','杜鵑非是翠芳殘，底事年年叫出山。',32,'全唐诗/poet.song.222000.json','["杜鵑非是翠芳殘，底事年年叫出山。", "紙帳竹牀清到底，不堪聲入夢魂閒。"]'),
('1f7278df-7c44-4a81-8193-96826d70ea31','次韻八姪三首  其一','陳著','宋','宋诗','song-poetry','','[]','春色三分一未歸，雪肌風態露春微。',32,'全唐诗/poet.song.222000.json','["春色三分一未歸，雪肌風態露春微。", "東風且作枝頭主，莫把工夫繡地衣。"]'),
('4bb68cbc-93e5-4dcf-a0cc-6505ac5db43a','次韻八姪三首  其二','陳著','宋','宋诗','song-poetry','','[]','素妝青蓋送春歸，似不禁風體力微。',32,'全唐诗/poet.song.222000.json','["素妝青蓋送春歸，似不禁風體力微。", "收拾韻香歸酒盞，惜花何惜醉淋衣。"]'),
('2628d716-05df-42b2-b7c9-5b417225450e','次韻八姪三首  其三','陳著','宋','宋诗','song-poetry','','[]','花開便是候催歸，濟楚生香清復微。',32,'全唐诗/poet.song.222000.json','["花開便是候催歸，濟楚生香清復微。", "遥想折來深院宇，似初勻粉小青衣。"]'),
('6a83436c-cebf-4f5a-b70b-c4581fd9a8cf','題嚴子陵釣臺二首  其一','陳著','宋','宋诗','song-poetry','','[]','才得心安便是通，乘龍非貴釣非窮。',32,'全唐诗/poet.song.222000.json','["才得心安便是通，乘龍非貴釣非窮。", "那知碌碌攀鱗者，盡在先生不釣中。"]'),
('01b385f5-7971-4c2a-8abb-0223c6965e0a','題嚴子陵釣臺二首  其二','陳著','宋','宋诗','song-poetry','','[]','方信先生大有功，光皇祇是暫時雄。',32,'全唐诗/poet.song.222000.json','["方信先生大有功，光皇祇是暫時雄。", "東都二百年名節，全在桐江一釣風。"]'),
('c1ccdfba-4a73-452b-9b97-f5f5f2df3896','小宴偶成','陳著','宋','宋诗','song-poetry','','[]','小宴珊瑚月未明，滿堂歡笑雜蛙聲。',32,'全唐诗/poet.song.222000.json','["小宴珊瑚月未明，滿堂歡笑雜蛙聲。", "明朝此會知誰續，試把鐙花仔細評。"]'),
('2adbacd9-267b-4bc7-9ce9-513cdf380205','次韻仇生五首  其一','陳著','宋','宋诗','song-poetry','','[]','一春風雨笑談疏，明日南風夏又初。',32,'全唐诗/poet.song.222000.json','["一春風雨笑談疏，明日南風夏又初。", "忽枉翠裾詩在手，勝如書尺寄雙魚。"]'),
('cff4e9a7-74c5-4147-b925-2afef49c3500','次韻仇生五首  其二','陳著','宋','宋诗','song-poetry','','[]','學晚唐詩俗見疏，君家句法到黄初。',32,'全唐诗/poet.song.222000.json','["學晚唐詩俗見疏，君家句法到黄初。", "淡交顧辱聯翩贈，熊掌方嘗又得魚。"]'),
('7007599b-25f7-4ac5-9741-efac6f576b23','次韻仇生五首  其三','陳著','宋','宋诗','song-poetry','','[]','交不緣詩有密疏，詩能宣寫此心初。',32,'全唐诗/poet.song.222000.json','["交不緣詩有密疏，詩能宣寫此心初。", "但從禮義中遊戲，便是趨庭孔伯魚。"]'),
('cb31a7cd-59a6-45dc-b70b-a888dea215db','次韻仇生五首  其四','陳著','宋','宋诗','song-poetry','','[]','詩筒狎至補前疏，快似西風捲峽初。',32,'全唐诗/poet.song.222000.json','["詩筒狎至補前疏，快似西風捲峽初。", "一片襟懷誰似友，曾從仙李跨鯨魚。"]'),
('9241de56-0e48-4078-94b0-09eea6bd07fd','次韻仇生五首  其五','陳著','宋','宋诗','song-poetry','','[]','羨君詩思九河疏，混混泉源只一初。',32,'全唐诗/poet.song.222000.json','["羨君詩思九河疏，混混泉源只一初。", "我欲驅馳無本領，激溝澮水狎蛙魚。"]'),
('8a586708-20eb-4dfa-add8-51b282b4eab2','次韻陳帥幹喜雨二首  其一','陳著','宋','宋诗','song-poetry','','[]','何事猶屯水與雷，夜看雲漢歎昭回。',32,'全唐诗/poet.song.222000.json','["何事猶屯水與雷，夜看雲漢歎昭回。", "五龍一日齊行雨，且莫嫌他欠早來。"]'),
('2d72361d-5525-4ef5-b7f6-6f0f1db3b0b6','次韻陳帥幹喜雨二首  其二','陳著','宋','宋诗','song-poetry','','[]','一雨何關百里雷，天心端爲衆心回。',32,'全唐诗/poet.song.222000.json','["一雨何關百里雷，天心端爲衆心回。", "閒時試向龍君覓，未必滂沱應手來。"]'),
('1b2135a5-5670-4944-87ed-664c8a434501','次韻李景異','陳著','宋','宋诗','song-poetry','','[]','剡溪千古雪坡風，收拾寒清入甕中。',32,'全唐诗/poet.song.222000.json','["剡溪千古雪坡風，收拾寒清入甕中。", "此味世人那得吮，特將撩撥老詩翁。"]'),
('efd8c274-e6ec-4811-b399-01d7c7025ea8','次韻石瑶林帥幹見賀','陳著','宋','宋诗','song-poetry','','[]','溪頭風浪起虛傳，寬大遭逢臺閫賢。',32,'全唐诗/poet.song.222000.json','["溪頭風浪起虛傳，寬大遭逢臺閫賢。", "見說襄城鞭衛士，清朝曾恕范忠宣。"]'),
('938e1ee2-8555-40da-9938-9b230d203aba','解剡孝嘉道中答溪民羣來遮轎問新知縣如何二首并寄李宰  其一','陳著','宋','宋诗','song-poetry','','[]','水淺山深土半沙，刀耕火種做生涯。',32,'全唐诗/poet.song.222000.json','["水淺山深土半沙，刀耕火種做生涯。", "今年水旱那堪說，存得妻兒能幾家。"]'),
('ba52e5aa-5cd7-4c94-8bcd-cc3d78e9ed83','解剡孝嘉道中答溪民羣來遮轎問新知縣如何二首并寄李宰  其二','陳著','宋','宋诗','song-poetry','','[]','新知縣是舊官員，說與田家汝有緣。',32,'全唐诗/poet.song.222000.json','["新知縣是舊官員，說與田家汝有緣。", "安穩過冬耘二麥，明年纔勝似今年。"]'),
('c531594f-364f-42f4-bc27-2e16820c4506','聞剡人望回','陳著','宋','宋诗','song-poetry','','[]','跋涉山程往又還，老懷不是愛遊山。',32,'全唐诗/poet.song.222000.json','["跋涉山程往又還，老懷不是愛遊山。", "爲聞父老勤相送，立滿溪頭幾日閒。"]'),
('998a1f45-b686-4d5d-8b31-6d2c334c5a9a','泌生日二首  其一','陳著','宋','宋诗','song-poetry','','[]','爲學須知次第功，四書爲本要精通。',32,'全唐诗/poet.song.222000.json','["爲學須知次第功，四書爲本要精通。", "不須妄起功名想，立得身時祿在中。"]'),
('dcb49bde-06e3-4afb-83e3-55975abb7aaa','泌生日二首  其二','陳著','宋','宋诗','song-poetry','','[]','莧藜併日不充饑，玉女於成在此時。',32,'全唐诗/poet.song.222000.json','["莧藜併日不充饑，玉女於成在此時。", "道義於人堪雋永，膏粱從古豢愚癡。"]'),
('c159a4ea-fac7-4d47-aeff-43c1099476f0','醉中','陳著','宋','宋诗','song-poetry','','[]','樂遊原上少年春，安樂窩中快活身。',32,'全唐诗/poet.song.222000.json','["樂遊原上少年春，安樂窩中快活身。", "古到如今能幾日，吁嗟天也不由人。"]'),
('b12fc416-0497-4801-a5ed-ed8a6305628b','與弟姪觀小圃梅花二首  其一','陳著','宋','宋诗','song-poetry','','[]','看花須看未開時，到七分開看已遲。',32,'全唐诗/poet.song.222000.json','["看花須看未開時，到七分開看已遲。", "前輩詠梅多此意，水邊竹外兩三枝。"]'),
('985ddd40-67e6-47e5-8711-22ecf3ebfd6e','與弟姪觀小圃梅花二首  其二','陳著','宋','宋诗','song-poetry','','[]','是則看花要及時，看花到實不妨遲。',32,'全唐诗/poet.song.222000.json','["是則看花要及時，看花到實不妨遲。", "前賢亦有留佳句，綠葉成陰子滿枝。"]'),
('923d01d4-05c9-420f-aa1b-1f5bb2b6f758','次韻上乘寺主僧如岳詠菊','陳著','宋','宋诗','song-poetry','','[]','萬紫千紅各炫名，紛紛兒女哄春榮。',32,'全唐诗/poet.song.222000.json','["萬紫千紅各炫名，紛紛兒女哄春榮。", "屈園秋種無人顧，獨遇陶潛氣始平。"]'),
('fc9285ba-9afa-4a81-b3a3-7ea1c99627ba','次韻梅山送牡丹二首  其一','陳著','宋','宋诗','song-poetry','','[]','姚根魏撥兩京貴，蜀本黟枝南度春。',32,'全唐诗/poet.song.222000.json','["姚根魏撥兩京貴，蜀本黟枝南度春。", "今日東風爲誰好，花香不到獨醒人。"]'),
('a956fda0-9537-4681-bd38-7e9fb7da2aa0','次韻梅山送牡丹二首  其二','陳著','宋','宋诗','song-poetry','','[]','毒霧腥塵涴色香，無知蜂蝶自乾忙。',32,'全唐诗/poet.song.222000.json','["毒霧腥塵涴色香，無知蜂蝶自乾忙。", "醉時煩惱不須醉，三斗誰能向汝陽。"]'),
('e4c5ba3b-c79d-49cc-8edf-9af2376cc877','又次韻二首  其一','陳著','宋','宋诗','song-poetry','','[]','猶記年時花下醉，老懷今已不成春。',32,'全唐诗/poet.song.222000.json','["猶記年時花下醉，老懷今已不成春。", "深黄淺紫知何在，留得殘鶑啼向人。"]'),
('db20d8fa-c261-4b43-983c-3fd0149860f0','又次韻二首  其二','陳著','宋','宋诗','song-poetry','','[]','賦詩誰復待沈香，澒洞乾坤走險忙。',32,'全唐诗/poet.song.222000.json','["賦詩誰復待沈香，澒洞乾坤走險忙。", "寂寂春光傷感處，瘦來不是沈東陽。"]'),
('05dfdd48-6535-4f19-8ff7-3c379caa8091','三次前韻二首  其一','陳著','宋','宋诗','song-poetry','','[]','東風吹送世閒塵，斜日消凝洛下春。',32,'全唐诗/poet.song.222000.json','["東風吹送世閒塵，斜日消凝洛下春。", "誰料馬蹄成怪事，旁觀自有豫知人。"]'),
('5a424572-eee3-4717-8673-01ec2a9821fe','三次前韻二首  其二','陳著','宋','宋诗','song-poetry','','[]','花本傷時不肯香，酒無賒處亦空忙。',32,'全唐诗/poet.song.222000.json','["花本傷時不肯香，酒無賒處亦空忙。", "便逢花酒如何醉，回首淒煙鎖景陽。"]'),
('12dd9b6a-3ef8-4db9-92aa-34130c6099f4','題丹霞洞','陳著','宋','宋诗','song-poetry','','[]','丹山高處坐龍宮，山下人歸潤澤中。',32,'全唐诗/poet.song.222000.json','["丹山高處坐龍宮，山下人歸潤澤中。", "北馬一塵飛不到，危時方見有神功。"]'),
('f2cb254c-84a7-4309-82dd-85b8e7fecaec','謝戴時芳惠物','陳著','宋','宋诗','song-poetry','','[]','蟻綠浮香雪外春，錦翰飛動玉芝新。',32,'全唐诗/poet.song.222000.json','["蟻綠浮香雪外春，錦翰飛動玉芝新。", "山人已約餐松柏，此餽應知是獲麟。"]'),
('8477fca8-f475-4602-a81e-b8866b0c8a59','贈趙月堂','陳著','宋','宋诗','song-poetry','','[]','乾坤慘淡真愁絕，民物傷殘欲活難。',32,'全唐诗/poet.song.222000.json','["乾坤慘淡真愁絕，民物傷殘欲活難。", "說相說醫當及此，區區衰病不須看。"]'),
('869375a8-d61d-4bfa-99d6-a9933739a64f','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其一','陳著','宋','宋诗','song-poetry','','[]','人世浮浮風裏塵，不須更問果何因。',32,'全唐诗/poet.song.222000.json','["人世浮浮風裏塵，不須更問果何因。", "有時意思悠然處，流水青山便是親。"]'),
('a2c64fdd-7e66-4ba8-8531-832061b24d0a','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其二','陳著','宋','宋诗','song-poetry','','[]','天地中閒浩浩歌，從他烏兔健飛過。',32,'全唐诗/poet.song.222000.json','["天地中閒浩浩歌，從他烏兔健飛過。", "旁人若問功名事，笑指南柯蟻一窠。"]'),
('efc4449b-35e6-400f-9fb2-6985960eba13','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其三','陳著','宋','宋诗','song-poetry','','[]','春夏交承紅與綠，歲寒三友松與竹。',32,'全唐诗/poet.song.222000.json','["春夏交承紅與綠，歲寒三友松與竹。", "我是蟾宮老桂枝，獨受上天風霜足。"]'),
('9f5664c4-3b8c-4ddc-9eb1-51b451ca3f21','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其四','陳著','宋','宋诗','song-poetry','','[]','天街追逐邊塵亂，更點聽殘鐘鼓院。',32,'全唐诗/poet.song.222000.json','["天街追逐邊塵亂，更點聽殘鐘鼓院。", "歸舟便覺昔年非，高枕已忘前日倦。"]'),
('c194a7b0-2a35-4854-b0de-1d9bb56b731a','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其五','陳著','宋','宋诗','song-poetry','','[]','粟瓶酒榼近多空，書友詩朋亦閒逢。',32,'全唐诗/poet.song.222000.json','["粟瓶酒榼近多空，書友詩朋亦閒逢。", "只有漁樵是知己，也嫌老似雪中松。"]'),
('ab96d71b-d2cf-4fb5-a0fb-d7f1ddc4be36','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其六','陳著','宋','宋诗','song-poetry','','[]','蕭蕭四壁住殘生，不學神仙不學僧。',32,'全唐诗/poet.song.222000.json','["蕭蕭四壁住殘生，不學神仙不學僧。", "有酒未能忘北海，種瓜且自學東陵。"]'),
('8320564c-aece-429c-b6e4-1bc4fb6a52bc','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其七','陳著','宋','宋诗','song-poetry','','[]','自分書生他未暇，物外人來偶清話。',32,'全唐诗/poet.song.222000.json','["自分書生他未暇，物外人來偶清話。", "老聃主見一字虛，莊叟寓言專是化。"]'),
('72c71685-b9f3-4f56-8c8d-af8f6d23c657','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其八','陳著','宋','宋诗','song-poetry','','[]','不到西峯爲日久，一日一日一日又。',32,'全唐诗/poet.song.222000.json','["不到西峯爲日久，一日一日一日又。", "明日有約爲此遊，一片雲山想依舊。"]'),
('3c06b540-8668-420d-8455-1ac87badadfb','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其九','陳著','宋','宋诗','song-poetry','','[]','正覺留題久岑寂，此後此意誰知得。',32,'全唐诗/poet.song.222000.json','["正覺留題久岑寂，此後此意誰知得。", "老僧揖入廊東頭，摩挲石刻令人憶。"]'),
('f2b23d30-c827-4af4-9fc5-9cc5655ddca0','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其一○','陳著','宋','宋诗','song-poetry','','[]','老佛眉閒屋漏愁，殘廊脚下草光浮。',32,'全唐诗/poet.song.222000.json','["老佛眉閒屋漏愁，殘廊脚下草光浮。", "誰能饑坐蘆穿膝，莫問神通石點頭。"]'),
('0a323bf2-497f-4146-b230-3a6a755047e8','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其一一','陳著','宋','宋诗','song-poetry','','[]','小小杯盤共話情，茲行聊爾過浮生。',32,'全唐诗/poet.song.222000.json','["小小杯盤共話情，茲行聊爾過浮生。", "瘦吟學士如工部，楷法書來近率更。"]'),
('ad4f4571-08aa-4016-9783-2cbae7e33d82','次韻如岳醵飲西峰寺分韻成詩十四首見寄  其一二','陳著','宋','宋诗','song-poetry','','[]','四坐詩成以成卷，醉舞者半歌者半。',32,'全唐诗/poet.song.222000.json','["四坐詩成以成卷，醉舞者半歌者半。", "薄雲疏雨且早歸，杜鵑自催鶴自怨。"]'),
