('f68dc9ef-9168-46e7-8546-b113f24364b0','重五有感','陳著','宋','宋诗','song-poetry','','[]','登高時節殃雞犬，乞巧風流狎女牛。',32,'全唐诗/poet.song.222000.json','["登高時節殃雞犬，乞巧風流狎女牛。", "何似今朝酹忠魄，殘杯一洗世人愁。"]'),
('5ec6c042-2193-4cfb-9cbc-a9bd704ae5b8','試墨三首  其一','陳著','宋','宋诗','song-poetry','','[]','元圭珍重鎮書房，紫石磨來滃墨香。',32,'全唐诗/poet.song.222000.json','["元圭珍重鎮書房，紫石磨來滃墨香。", "老去苦無閒著述，以分寸計□時長。"]'),
('db929a32-9074-43a4-a442-c6209c546c73','試墨三首  其二','陳著','宋','宋诗','song-poetry','','[]','墨卿與我是相投，了得時需便罷休。',32,'全唐诗/poet.song.222000.json','["墨卿與我是相投，了得時需便罷休。", "不見江南井中藏，只爲相國寺門留。"]'),
('06fe3f6e-26a2-4ab2-b6dd-2820a97ce187','試墨三首  其三','陳著','宋','宋诗','song-poetry','','[]','兔毫染上何妨淺，蟬翼寫來可放輕。',32,'全唐诗/poet.song.222000.json','["兔毫染上何妨淺，蟬翼寫來可放輕。", "爲愛淡中多醖藉，却嫌濃處太分明。"]'),
('92a36323-0d8f-48f2-83c3-cf7e952d8589','出門偶成','陳著','宋','宋诗','song-poetry','','[]','雙鷺飛飛高復低，復低飛下近山溪。',32,'全唐诗/poet.song.222000.json','["雙鷺飛飛高復低，復低飛下近山溪。", "一聲樵唱山前路，却又飛歸翡翠西。"]'),
('654fe747-bffb-4f79-b4bd-e830b23397f9','遊雪竇杖錫七首 錦鏡池','陳著','宋','宋诗','song-poetry','','[]','萬仞崖擎碧玉臺，中閒一鏡帖天開。',32,'全唐诗/poet.song.222000.json','["萬仞崖擎碧玉臺，中閒一鏡帖天開。", "四時自與幽花對，一點時妝不照來。"]'),
('e5a1f908-f61d-4206-93dd-09cd7ed18e46','遊雪竇杖錫七首 飛雪亭','陳著','宋','宋诗','song-poetry','','[]','雪瀑翻崖直下深，自從開闢到如今。',32,'全唐诗/poet.song.222000.json','["雪瀑翻崖直下深，自從開闢到如今。", "天寒水澀山風急，不斷朝宗一派心。"]'),
