('8fcd7754-130f-41bb-9390-59e00e3fbe16','贊齡叟留東隠二首  其一','陳著','宋','宋诗','song-poetry','','[]','纔出家來恩愛輕，師於東隠却關情。',32,'全唐诗/poet.song.222000.json','["纔出家來恩愛輕，師於東隠却關情。", "一盂菜飯留分與，方信空門有弟兄。"]'),
('d82c6587-3886-4364-a32a-280bfb27d3d4','贊齡叟留東隠二首  其二','陳著','宋','宋诗','song-poetry','','[]','一片丹山雲出山，慈雲高處共清閒。',32,'全唐诗/poet.song.222000.json','["一片丹山雲出山，慈雲高處共清閒。", "春風輕借吹噓力，出本無心也會還。"]'),
('dad51ac8-1769-4bbd-968b-ae8d83c100d6','蒙齋習菴皆有詩在慈雲閣沈端憲又有記文刻石因成二絕  其一','陳著','宋','宋诗','song-poetry','','[]','習老蒙翁兩達尊，借他僧偈說慈雲。',32,'全唐诗/poet.song.222000.json','["習老蒙翁兩達尊，借他僧偈說慈雲。", "一番入寺一感愴，細讀古碑端憲文。"]'),
('1f2e3078-f89b-4e6a-95d7-7c3906a1a5f2','蒙齋習菴皆有詩在慈雲閣沈端憲又有記文刻石因成二絕  其二','陳著','宋','宋诗','song-poetry','','[]','景照堂中憩佛騷，闌干憑處接雲高。',32,'全唐诗/poet.song.222000.json','["景照堂中憩佛騷，闌干憑處接雲高。", "賦詩時會苦吟甫，破約難留嗜酒陶。"]'),
('db3cf9fd-8b15-44cf-9cfe-bb198fd1d17c','寄南湖主人海雪岑','陳著','宋','宋诗','song-poetry','','[]','別雪岑翁不記年，翁今來管四明天。',32,'全唐诗/poet.song.222000.json','["別雪岑翁不記年，翁今來管四明天。", "看翁捲起南湖浪，洗盡浮塵結浄緣。"]'),
('7088d8ee-6bd1-4ef1-ac4e-1df35f2605f0','哭趙觀使墓','陳著','宋','宋诗','song-poetry','','[]','十載重來古樹陰，眼前新冢淚沾襟。',32,'全唐诗/poet.song.222000.json','["十載重來古樹陰，眼前新冢淚沾襟。", "歸家當與諸兒說，要識如今展拜心。"]'),
('2a2fcd7f-f441-467c-8607-751e2da29387','送酒與蒲萄與來石門','陳著','宋','宋诗','song-poetry','','[]','山泉釀出苦醅硬，野蔓生來酸子圓。',32,'全唐诗/poet.song.222000.json','["山泉釀出苦醅硬，野蔓生來酸子圓。", "此味不投甜世界，遣教參透石翁禪。"]'),
('0362e574-5736-4387-95d4-2436f44caf4d','早晴出門','陳著','宋','宋诗','song-poetry','','[]','山光溪色曉晴閒，鷗鷺在溪雪在山。',32,'全唐诗/poet.song.222000.json','["山光溪色曉晴閒，鷗鷺在溪雪在山。", "忽然自笑還自語，白日何似溪山閒。"]'),
('1b94c79e-9c51-4552-9c08-f01e53e16be0','南山白雲','陳著','宋','宋诗','song-poetry','','[]','一片白雲飛入山，須臾又出在人閒。',32,'全唐诗/poet.song.222000.json','["一片白雲飛入山，須臾又出在人閒。", "我歸十年不復出，說道雲閒我更閒。"]'),
('57eff58a-1ed8-44c6-b31e-b72549493039','偶成','陳著','宋','宋诗','song-poetry','','[]','赤日途中嚼冰雪，紅塵城外見林泉。',32,'全唐诗/poet.song.222000.json','["赤日途中嚼冰雪，紅塵城外見林泉。", "一時邂逅猶快意，十載清閒我謝天。"]'),
('a27998e0-4b25-4689-88cc-48c607aaa752','早行到慈雲','陳著','宋','宋诗','song-poetry','','[]','出門早作慈雲行，樓閣崢嶸殘月明。',32,'全唐诗/poet.song.222000.json','["出門早作慈雲行，樓閣崢嶸殘月明。", "老耳虛鳴眼带夢，恍然和甯聞六更。"]'),
('df8f27ff-668b-492c-b245-b21511ec4252','酒邊','陳著','宋','宋诗','song-poetry','','[]','茶甌纔退酒杯來，酒興濃時杯復杯。',32,'全唐诗/poet.song.222000.json','["茶甌纔退酒杯來，酒興濃時杯復杯。", "也須留取三分醒，要带明月清風回。"]'),
('be075a8e-d8ef-4d3d-963f-3756add1b047','送董稼山二首  其一','陳著','宋','宋诗','song-poetry','','[]','三年一去西山雲，一見欲別心知熏。',32,'全唐诗/poet.song.222000.json','["三年一去西山雲，一見欲別心知熏。", "勸君且爲更上酒，何時得與細論文。"]'),
('d7d87733-f81b-44ff-880b-c6dceca829a0','送董稼山二首  其二','陳著','宋','宋诗','song-poetry','','[]','白髮蕭蕭送出門，相携相看兩無言。',32,'全唐诗/poet.song.222000.json','["白髮蕭蕭送出門，相携相看兩無言。", "祇應今日往來夢，攪破百里梅花邨。"]'),
