('bab0cdcc-6e79-42b1-91d3-82894dd93a35','次韻雪竇寺主僧炳同招遊山二首  其一','陳著','宋','宋诗','song-poetry','','[]','萬葉逢秋又纈斑，珠林錦鏡好追攀。',32,'全唐诗/poet.song.222000.json','["萬葉逢秋又纈斑，珠林錦鏡好追攀。", "人生行樂非容易，本是閒人也未閒。"]'),
('b03d86af-4dc5-4f3b-a575-0571ecfdbdf5','次韻雪竇寺主僧炳同招遊山二首  其二','陳著','宋','宋诗','song-poetry','','[]','飛下吟箋墨妙斑，空拳難對敵家攀。',32,'全唐诗/poet.song.222000.json','["飛下吟箋墨妙斑，空拳難對敵家攀。", "肯分半榻清風況，翻怪詩來撓聒閒。"]'),
('4336395a-c2b6-42b4-85d1-bd791f445c1a','次前韻二首似前育王寺主僧如日  其一','陳著','宋','宋诗','song-poetry','','[]','見說東巖弄一斑，萬人表立許誰攀。',32,'全唐诗/poet.song.222000.json','["見說東巖弄一斑，萬人表立許誰攀。", "笑相逢處行雲住，誰主誰賓相對閒。"]'),
('c3dc324b-4ee6-4c3e-8e8d-bd712d2dda4d','次前韻二首似前育王寺主僧如日  其二','陳著','宋','宋诗','song-poetry','','[]','桂漸吹香菊漸斑，西風送步得高攀。',32,'全唐诗/poet.song.222000.json','["桂漸吹香菊漸斑，西風送步得高攀。", "天開圖畫著二老，我亦何妨一笑閒。"]'),
('e0694e51-71be-49cb-a2b6-e59ea3df3650','上巳酒邊即事示女沖二首  其一','陳著','宋','宋诗','song-poetry','','[]','女沖踏露折棠花，引得兒童哄一家。',32,'全唐诗/poet.song.222000.json','["女沖踏露折棠花，引得兒童哄一家。", "說道今朝修禊日，暫拋鍼綫答年華。"]'),
('20c69990-4a91-4e61-a485-fb0af8bdfb1d','上巳酒邊即事示女沖二首  其二','陳著','宋','宋诗','song-poetry','','[]','年華浮動酒中心，笑向吾前滿滿斟。',32,'全唐诗/poet.song.222000.json','["年華浮動酒中心，笑向吾前滿滿斟。", "猶喜家貧詩禮在，一杯真率勝山陰。"]'),
('220f1d27-5b36-4cb9-b726-0ae892e3d820','題思遠行業碑','陳著','宋','宋诗','song-poetry','','[]','虎溪雖小深似海，截斷英雄富貴塵。',32,'全唐诗/poet.song.222000.json','["虎溪雖小深似海，截斷英雄富貴塵。", "却爲淵明過溪笑，方知心自有高人。"]'),
('da0e8e69-75df-4564-af50-243eca5bb0ad','寄題剡竺貫之書堂','陳著','宋','宋诗','song-poetry','','[]','一片心田種善根，粲爲枝葉有兒孫。',32,'全唐诗/poet.song.222000.json','["一片心田種善根，粲爲枝葉有兒孫。", "人從今日封培去，百世金庭好石門。"]'),
('9f6b93e5-44a0-4232-8574-d68907c526db','贈茅意山主簿','陳著','宋','宋诗','song-poetry','','[]','旅鎖傾城慰寂寥，詩篇到眼見賢勞。',32,'全唐诗/poet.song.222000.json','["旅鎖傾城慰寂寥，詩篇到眼見賢勞。", "三年鸞鳳風聲好，萬里驊騮地步高。"]'),
('30bb547f-6d33-4570-ac32-f558df96f42f','次韻邑宰徐何謙道中詠風雨中聞藕花香','陳著','宋','宋诗','song-poetry','','[]','眼空塵世粉紅嬌，看了濂溪興自饒。',32,'全唐诗/poet.song.222000.json','["眼空塵世粉紅嬌，看了濂溪興自饒。", "風雨中閒曾著句，滿身身到慶登橋。"]'),
('306c89b7-b4ed-4795-891e-1f6e7e057aa1','次前人爲余置酒邑廳見示','陳著','宋','宋诗','song-poetry','','[]','公事無多白日閒，笑談風月傲方干。',32,'全唐诗/poet.song.222000.json','["公事無多白日閒，笑談風月傲方干。", "馬鞍雖少難供賦，突兀南山翠撲鞍。"]'),
('a6a8c595-330d-4f5d-aab9-1a6a15506f3a','次前人似任叔實','陳著','宋','宋诗','song-poetry','','[]','字字真真幻幻心，講氈須體美中箴。',32,'全唐诗/poet.song.222000.json','["字字真真幻幻心，講氈須體美中箴。", "分明示我豬龍訓，剪刷成他鸞鵠襟。"]'),
('d9a66b93-0f52-497e-86bc-e79c78ec7cca','丁丑五月六日醵飲茂林偶成','陳著','宋','宋诗','song-poetry','','[]','夾路松杉護午陰，南風吹透樹中心。',32,'全唐诗/poet.song.222000.json','["夾路松杉護午陰，南風吹透樹中心。", "一聲婆餠焦何處，妙法蓮花此妙音。"]'),
('b45b2c74-ce60-4ad6-acf6-e36f1b5596cb','答法椿長老口占','陳著','宋','宋诗','song-poetry','','[]','牀前何必問云何，霜頂誰將手自磨。',32,'全唐诗/poet.song.222000.json','["牀前何必問云何，霜頂誰將手自磨。", "可是法身真有病，皺眉頭處爲人多。"]'),
('0a01f2c3-e8e9-4aea-a238-9e7a79c6a765','似僧一甯','陳著','宋','宋诗','song-poetry','','[]','邂逅交情雲水閒，茶甌香鼎話清閒。',32,'全唐诗/poet.song.222000.json','["邂逅交情雲水閒，茶甌香鼎話清閒。", "他年燕坐千峯上，認取一山山外山。"]'),
('8535ed58-c890-4b1f-8435-81cedbab20a0','似僧耕野雲','陳著','宋','宋诗','song-poetry','','[]','浮雲一片出天涯，南北東西總是家。',32,'全唐诗/poet.song.222000.json','["浮雲一片出天涯，南北東西總是家。", "飛到五山山絕頂，風雷變化雨河沙。"]'),
('e5e8596e-4cd7-44bd-a781-1bb85e11d212','次韻僧雲岫見寄','陳著','宋','宋诗','song-poetry','','[]','憶昔宮花壓帽簷，如今野褐替朝衫。',32,'全唐诗/poet.song.222000.json','["憶昔宮花壓帽簷，如今野褐替朝衫。", "邯鄲夢覺身猶在，安得寒山喝破巖。"]'),
('046b9bb2-ef71-432c-8e68-0ba53c8e86d4','到西山懷趙景文','陳著','宋','宋诗','song-poetry','','[]','曉日南窗一煖烘，采薇人去與誰同。',32,'全唐诗/poet.song.222000.json','["曉日南窗一煖烘，采薇人去與誰同。", "人生畢竟皆如此，休怪浮圖只說空。"]'),
('1587c27d-9af2-484c-b616-9c3bc5cd5f31','次韻椿長老惠蓮花扇','陳著','宋','宋诗','song-poetry','','[]','蓮花法界走輿臺，兩扇香風爲我開。',32,'全唐诗/poet.song.222000.json','["蓮花法界走輿臺，兩扇香風爲我開。", "藜藿皮毛消不盡，若爲囘向我如來。"]'),
('eb77e194-26a6-4e3d-9f9a-c6b592ed27f0','代弟茝詠梅畫十景 先春','陳著','宋','宋诗','song-poetry','','[]','纔得江南第一春，竹籬茅舍便精神。',32,'全唐诗/poet.song.222000.json','["纔得江南第一春，竹籬茅舍便精神。", "百花頭上無相識，只有東風是故人。"]'),
('e3e0f874-c581-4272-91ef-a1e7bcfe0f57','代弟茝詠梅畫十景 古枝','陳著','宋','宋诗','song-poetry','','["\u897f\u6e56"]','分甘冷落傍朱門，傲雪欺霜百歲根。',32,'全唐诗/poet.song.222000.json','["分甘冷落傍朱門，傲雪欺霜百歲根。", "惆悵西湖人不見，暗香依舊月黄昏。"]'),
('7bcf5a21-0409-4fad-84da-37e719b66542','代弟茝詠梅畫十景 宜月','陳著','宋','宋诗','song-poetry','','[]','斜斜瘦影兩三枝，只許寒窗人自知。',32,'全唐诗/poet.song.222000.json','["斜斜瘦影兩三枝，只許寒窗人自知。", "猶恨嫦娥收不盡，却歸羌管曲中吹。"]'),
('04b34b00-9428-4416-a52b-bcf29955594a','代弟茝詠梅畫十景 卧煙','陳著','宋','宋诗','song-poetry','','[]','生香自恨玉爲容，誰放晨光淺碧籠。',32,'全唐诗/poet.song.222000.json','["生香自恨玉爲容，誰放晨光淺碧籠。", "隠約風標難畫處，邯鄲人在夢炊中。"]'),
('8e7c2547-cb72-4b7e-be1b-db4b63ac3428','代弟茝詠梅畫十景 依松','陳著','宋','宋诗','song-poetry','','[]','處子從來不世妝，老蒼相對本相忘。',32,'全唐诗/poet.song.222000.json','["處子從來不世妝，老蒼相對本相忘。", "猶嫌曾受秦封污，冷笑無言祇自香。"]'),
('d5ddb440-ba08-48cd-85b3-04952f6d109e','代弟茝詠梅畫十景 依竹','陳著','宋','宋诗','song-poetry','','[]','香在溪頭古晉林，瀟瀟風雨慣曾禁。',32,'全唐诗/poet.song.222000.json','["香在溪頭古晉林，瀟瀟風雨慣曾禁。", "休尋白玉堂前夢，自有此君知此心。"]'),
('bd94285b-3477-470b-a4ee-d8be09083ebd','代弟茝詠梅畫十景 雪裏','陳著','宋','宋诗','song-poetry','','[]','天花包盡世閒羞，也到孤山老樹頭。',32,'全唐诗/poet.song.222000.json','["天花包盡世閒羞，也到孤山老樹頭。", "寄語東風爲吹拂，本來面目自風流。"]'),
('f76939ac-d31f-4c21-8e2f-ca7ce19f1725','代弟茝詠梅畫十景 風前','陳著','宋','宋诗','song-poetry','','[]','打頭二十四番信，吹透天香雪裏枝。',32,'全唐诗/poet.song.222000.json','["打頭二十四番信，吹透天香雪裏枝。", "總被詩人收拾去，封姨正自未能知。"]'),
('34faa8f5-4ec7-410e-a5bf-0e32c87b3b72','代弟茝詠梅畫十景 飛花','陳著','宋','宋诗','song-poetry','','[]','獨占初春早卸芳，肯隨桃李炫儂妝。',32,'全唐诗/poet.song.222000.json','["獨占初春早卸芳，肯隨桃李炫儂妝。", "如今不到壽陽額，自做孤村流水香。"]'),
('926e8f28-d10d-4457-b4e4-be064171dd43','代弟茝詠梅畫十景 結實','陳著','宋','宋诗','song-poetry','','[]','碧實圓成重壓枝，萬紅千紫竟何知。',32,'全唐诗/poet.song.222000.json','["碧實圓成重壓枝，萬紅千紫竟何知。", "是雖不入甜人口，留得青酸有用時。"]'),
('cbbda304-9751-453d-b06f-c7c9ee1d3da4','到倪菴','陳著','宋','宋诗','song-poetry','','[]','聯袂西菴去，行清不厭深。',48,'全唐诗/poet.song.222000.json','["聯袂西菴去，行清不厭深。", "蘭芳泛幽谷，松翠引長林。", "石路傍山甃，澗源何處尋。", "歸途無所有，時聽一猨吟。"]'),
('57a2699f-3919-402e-bdc9-3a8644878e27','入城似吳竹溪','陳著','宋','宋诗','song-poetry','','[]','投眠方丈室，爲趁午潮差。',48,'全唐诗/poet.song.222000.json','["投眠方丈室，爲趁午潮差。", "父執子愛我，客身心是家。", "夜牀安紙帳，曉枕夢梅花。", "早作臨溪別，此情天共涯。"]'),
('9d8525de-c82f-47d2-96f1-fe9125778c1b','過崎山','陳著','宋','宋诗','song-poetry','','[]','曉過崎山下，溪清水見沙。',48,'全唐诗/poet.song.222000.json','["曉過崎山下，溪清水見沙。", "石根交虎豹，樹影亂龍蛇。", "黄竹藏丹渚，青帘賣酒家。", "扣舷汀鷺起，撇撇带西斜。"]'),
('dd72fc51-577a-41ec-8340-a34474c78271','江口偶成','陳著','宋','宋诗','song-poetry','','[]','出門何所適，欲見邵雲臺。',48,'全唐诗/poet.song.222000.json','["出門何所適，欲見邵雲臺。", "天氣晴相送，灘舟小易推。", "坐恬時掬水，吟苦恰□梅。", "舟子遥相問，江潮來未來。"]'),
('72a0abb8-c35d-4618-9201-e7f1af2ff0a6','西渡堰呈孫古巖朝奉','陳著','宋','宋诗','song-poetry','','[]','行計又怱怱，投西一短篷。',48,'全唐诗/poet.song.222000.json','["行計又怱怱，投西一短篷。", "上河平岸水，暮雨打頭風。", "得飯已昏後，無眠到夜中。", "哦詩欠佳句，爲報古巖翁。"]'),
('d0a965a1-3775-40a5-a46c-cc6d28095d8b','泊丈亭','陳著','宋','宋诗','song-poetry','','[]','丈亭亭下浦，艤棹又終朝。',48,'全唐诗/poet.song.222000.json','["丈亭亭下浦，艤棹又終朝。", "船聚市聲雜，風生江氣驕。", "茲行未百里，已涉第三潮。", "去住向誰問，鷺飛雲影飄。"]'),
('295f37b2-b94a-4a39-8f2b-941bc8bf7b80','同袁通判遊越中三首 禹廟','陳著','宋','宋诗','song-poetry','','[]','舟行可十里，上岸即山林。',48,'全唐诗/poet.song.222000.json','["舟行可十里，上岸即山林。", "曲徑抱深意，怪松傳古音。", "平生能幾到，好處欲窮尋。", "春鳥一聲處，鄉關又上心。"]'),
('738b2af9-e192-4c88-9698-ef589567dd4e','同袁通判遊越中三首 鴻禧觀','陳著','宋','宋诗','song-poetry','','[]','停舟過橋去，兩岸綠垂楊。',48,'全唐诗/poet.song.222000.json','["停舟過橋去，兩岸綠垂楊。", "繞屋水爲界，入門花滿廊。", "如今爲道觀，聞昔是書堂。", "此意與誰說，春風湖渺茫。"]'),
('7bdc0cd3-4c4c-4247-96ab-ad908593932c','同袁通判遊越中三首 趙節使稽山門外花園','陳著','宋','宋诗','song-poetry','','[]','前賢眼力到，占得此名區。',48,'全唐诗/poet.song.222000.json','["前賢眼力到，占得此名區。", "荒徑百年樹，虛堂三面湖。", "簷陰來釣艇，花外起晴鳬。", "借問園中叟，主人曾到無。"]'),
('0dd3d729-fa3c-436c-bedc-9552f7f9a941','示內','陳著','宋','宋诗','song-poetry','','[]','婚娶不在早，在此兩相宜。',48,'全唐诗/poet.song.222000.json','["婚娶不在早，在此兩相宜。", "豈得人無婦，能如子者誰。", "科名圖我取，家務以身支。", "要見看承處，頹然白髮時。"]'),
('62bdd99b-e3e8-4147-993d-46324cef906d','呈月窗兄','陳著','宋','宋诗','song-poetry','','[]','頗有愛山心，山人交未深。',48,'全唐诗/poet.song.222000.json','["頗有愛山心，山人交未深。", "不知迴俗駕，依舊入儒林。", "樂處外何有，故書中可尋。", "漁蓑歸得晚，風雨伴吾吟。"]'),
('fba1bcb0-36a9-483a-80cb-04b3d2f8e16f','張敬之縣尉','陳著','宋','宋诗','song-poetry','','[]','仙棹發秋灣，稽山到不難。',48,'全唐诗/poet.song.222000.json','["仙棹發秋灣，稽山到不難。", "要將培遠業，便答自初官。", "秦望一峯峭，賀湖千頃寬。", "用心行己處，時向此中看。"]'),
('094b4192-8daa-4dda-b0ae-620229548073','公棠溪次待舅氏竺九成舟偶成','陳著','宋','宋诗','song-poetry','','[]','駐馬古溪頭，期舟不見舟。',48,'全唐诗/poet.song.222000.json','["駐馬古溪頭，期舟不見舟。", "未知來否的，難决坐行謀。", "灘遠寬飛鷺，波平穩泛鷗。", "功名在何處，到此兩悠悠。"]'),
('a619ec71-8257-464e-8e03-c63bc3f70007','晴行','陳著','宋','宋诗','song-poetry','','[]','久晴常欲厭，黓裏却宜晴。',48,'全唐诗/poet.song.222000.json','["久晴常欲厭，黓裏却宜晴。", "溪瘠容魚穴，風恬安雁程。", "空山巖出相，老樹葉生聲。", "此景吟不盡，明朝重細評。"]'),
('1946728e-1a5f-43a0-bf6f-371847aa091f','柏溪巖頭','陳著','宋','宋诗','song-poetry','','[]','晴色上遊筇，西行二里中。',48,'全唐诗/poet.song.222000.json','["晴色上遊筇，西行二里中。", "薺花黄纈地，麥穗白潮風。", "紙杵鳴山屋，齋鐘出梵宮。", "歸途須傍早，要折石巖紅。"]'),
('06ed0be3-09ee-4f4c-af2a-53782dc75bc1','遊永固院','陳著','宋','宋诗','song-poetry','','[]','晴行不自覺，又入此山來。',48,'全唐诗/poet.song.222000.json','["晴行不自覺，又入此山來。", "失笑谷聲應，坐迎僧戶開。", "簷風數行竹，窗日一枝梅。", "歸策休催發，得閒能幾囘。"]'),
('601603ae-1a35-4abe-8ff3-aafbf4138685','遊慈雲','陳著','宋','宋诗','song-poetry','','[]','微吟歡信步，不覺到禪關。',48,'全唐诗/poet.song.222000.json','["微吟歡信步，不覺到禪關。", "植杖苔痕上，敲門竹影閒。", "樹高風韻葉，人靜鳥呼山。", "安得長留此，分僧一半閒。"]'),
('9fa9daf3-0856-483f-a5ff-648e90801fb3','秋晚新晴','陳著','宋','宋诗','song-poetry','','[]','杖屨訪郊晴，秋光潑眼明。',48,'全唐诗/poet.song.222000.json','["杖屨訪郊晴，秋光潑眼明。", "溪痕經水沒，山面撥雲呈。", "霞影收虹影，砧聲急雁聲。", "芙蓉花在否，滑路倩人行。"]'),
('66f79461-806f-4325-9468-553b6086696d','秋夜偶成','陳著','宋','宋诗','song-poetry','','[]','小築塵囂外，清標秋氣中。',48,'全唐诗/poet.song.222000.json','["小築塵囂外，清標秋氣中。", "荻花渾妒月，梧葉已嫌風。", "釣箔驚簷馬，冊燈覓候蟲。", "困來還倚竹，此意有誰同。"]'),
('9910e3ac-3106-4d83-8826-75cba249e93a','次前韻與舅氏竺九成求芋','陳著','宋','宋诗','song-poetry','','[]','何處蹲鴟美，雲南一望中。',48,'全唐诗/poet.song.222000.json','["何處蹲鴟美，雲南一望中。", "角巾臨晚歲，拙語寄西風。", "喜報無乾鵲，緘回靳篆蟲。", "還詩元有例，盍與昔人同。"]'),
('dd3d5134-29d0-4d2d-ae4c-f5018b4d6c34','次韻徐直翁仙霞嶺近衢州','陳著','宋','宋诗','song-poetry','','[]','道大誰能用，功名一念微。',48,'全唐诗/poet.song.222000.json','["道大誰能用，功名一念微。", "釋然文石夢，輕似岫雲歸。", "霞嶺空重歷，天書的又飛。", "翻身鳳池去，分閫却成非。"]'),
('af9cb7f1-293a-4fb6-a148-d6eacacee8ab','次韻童尚質書懷三首  其一','陳著','宋','宋诗','song-poetry','','[]','夜室清如許，檠鐙便且明。',48,'全唐诗/poet.song.222000.json','["夜室清如許，檠鐙便且明。", "哦詩鬚已斷，看劍氣難平。", "露戶浸孤月，江城知幾更。", "枕書俄作夢，夢覺骨毛輕。"]'),
('7b48ab85-ddb4-4b2e-a0bf-278a877c344d','次韻童尚質書懷三首  其二','陳著','宋','宋诗','song-poetry','','[]','地偏人迹悄，月到小窗明。',48,'全唐诗/poet.song.222000.json','["地偏人迹悄，月到小窗明。", "鼓瑟希曾點，觀書慨屈平。", "物情閒裏見，世事夢中更。", "不著黄粱枕，虛名已自輕。"]'),
('3d07b706-6c41-4884-a9d3-0c6969632e4c','次韻童尚質書懷三首  其三','陳著','宋','宋诗','song-poetry','','[]','夜寂氣如洗，心閒理自明。',48,'全唐诗/poet.song.222000.json','["夜寂氣如洗，心閒理自明。", "凝香清夢寐，讀易悟生平。", "月樹烏驚曉，雲階鶴報更。", "閉門佳致意，名利一毛輕。"]'),
('e1727179-5b4e-461d-8f14-1c9df0061854','寄貝勉齋馮桂坡','陳著','宋','宋诗','song-poetry','','[]','道誼不今古，世情空淺深。',48,'全唐诗/poet.song.222000.json','["道誼不今古，世情空淺深。", "共君聯夜話，慰我一生心。", "對酒清鐙影，分襟細雨陰。", "天南豈無雁，時得寄書音。"]'),
('8c3129b6-092f-4739-8360-b6c552012e5e','嘉興道中','陳著','宋','宋诗','song-poetry','','[]','此來知幾番，此景孰能言。',48,'全唐诗/poet.song.222000.json','["此來知幾番，此景孰能言。", "有堰留河水，無山礙稻邨。", "船收菱入市，家植桂當門。", "風物有如此，誰招二陸魂。"]'),
('93eed29e-f8ac-4059-9bcc-c4779c24cfa4','六里橋','陳著','宋','宋诗','song-poetry','','[]','拒霜紅蓼叢，兩岸遞迎逢。',48,'全唐诗/poet.song.222000.json','["拒霜紅蓼叢，兩岸遞迎逢。", "風雨日易夜，江湖秋似冬。", "縱觀心浩蕩，無事夢從容。", "不問程途遠，詩情節節濃。"]'),
('6aeb12b3-7416-4cd1-adec-39be6207d441','四安縣道中望一山最尖青問轎夫云是饅頭山因有詩','陳著','宋','宋诗','song-poetry','','[]','眼前山忽好，他處特紛紛。',48,'全唐诗/poet.song.222000.json','["眼前山忽好，他處特紛紛。", "四下正鋪野，一尖高入雲。", "乾坤分外闊，江浙此閒分。", "我欲更邨號，尊爲卓秀君。"]'),
('0ccdd031-c8b3-487a-a547-697af3e0bf7c','到四安','陳著','宋','宋诗','song-poetry','','[]','雨中行數日，今日得新晴。',48,'全唐诗/poet.song.222000.json','["雨中行數日，今日得新晴。", "山到浙閒秀，船從海上行。", "市腥逢海錯，人語带京聲。", "此去總佳景，坡仙曾細評。"]'),
('50c81c1b-d551-430c-b9b4-d1bbd99caad7','長兒吉初生日以四十字示之','陳著','宋','宋诗','song-poetry','','[]','吾年五十五，汝生方九年。',48,'全唐诗/poet.song.222000.json','["吾年五十五，汝生方九年。", "雖知得子晚，亦擬壽家傳。", "立己要莊重，存心無躁偏。", "人皆可向上，從否勿歸天。"]'),
('f639918f-d8ed-4580-8fe1-83fd90d25480','嵊縣勸農途中示同寮二首  其一','陳著','宋','宋诗','song-poetry','','[]','連朝風或雨，今日却霜晴。',48,'全唐诗/poet.song.222000.json','["連朝風或雨，今日却霜晴。", "簇翠麥苗起，纈斑麻甲生。", "雞邨炊色軟，牛隴種痕平。", "此意與誰共，老農歡笑聲。"]'),
('912279d6-92c5-4e00-ae4b-8c329c0cfc8d','嵊縣勸農途中示同寮二首  其二','陳著','宋','宋诗','song-poetry','','[]','老農歡笑聲，三十里春程。',48,'全唐诗/poet.song.222000.json','["老農歡笑聲，三十里春程。", "笳鼓斷還續，杯盤坐又行。", "誰云償縣債，正好看民情。", "歸去不妨晚，出山溪月明。"]'),
('ee3b63aa-3874-4471-83fb-a8a977efbea8','剡中明心寺','陳著','宋','宋诗','song-poetry','','[]','塵勞一笑非，忽此坐多時。',48,'全唐诗/poet.song.222000.json','["塵勞一笑非，忽此坐多時。", "當谷寺如井，滿山泉可池。", "林暄蟬噪早，沙冷筍生遲。", "又見老僧說，此中蘭最奇。"]'),
('2d05de98-9c8f-4752-a9da-ac305e858f85','剡縣次韻石瑶林帥幹春宴','陳著','宋','宋诗','song-poetry','','[]','歲君初領事，豹尾簇黄幡。',48,'全唐诗/poet.song.222000.json','["歲君初領事，豹尾簇黄幡。", "雪喜三番白，春纔幾日斑。", "市盤妝菜活，宮勝壓花繁。", "便覺東風轉，四山浮翠環。"]'),
('80718369-648f-42f3-82d9-9559307c06ce','解剡回家過陳公嶺','陳著','宋','宋诗','song-poetry','','[]','漫仕當閒遊，歸程更自留。',48,'全唐诗/poet.song.222000.json','["漫仕當閒遊，歸程更自留。", "嶺高雲送脚，路險石垂頭。", "家近聽鄉語，山分認水流。", "溪橋聊小憩，雙鷺去悠悠。"]'),
('0c83816a-9d56-4381-9a37-65dfbc6382de','山家即事','陳著','宋','宋诗','song-poetry','','[]','小築山之下，林泉景自成。',48,'全唐诗/poet.song.222000.json','["小築山之下，林泉景自成。", "閒花隨付分，啼鳥本無情。", "日暮嶺雲合，雨餘溪水清。", "相逢是樵客，堪與話平生。"]'),
('e6cf46e5-ab76-4cdc-98d3-8c1b78b066a5','山居避難六首  其一','陳著','宋','宋诗','song-poetry','','[]','三十六風輪，清磨萬古人。',48,'全唐诗/poet.song.222000.json','["三十六風輪，清磨萬古人。", "軍興山勝市，歲歉富齊貧。", "破絮身饒垢，乾糧舌費津。", "吾生不足問，世事入長顰。"]'),
('8f751a13-83d2-457c-97ac-405921f81a3f','山居避難六首  其二','陳著','宋','宋诗','song-poetry','','[]','并刀越砥磨，天奈北風何。',48,'全唐诗/poet.song.222000.json','["并刀越砥磨，天奈北風何。", "到處聞流杵，何時報止戈。", "逃藏愁木柵，淪落泣毬窩。", "多少巖阿□，真成病伏波。"]'),
('70531a24-89fe-4d26-b25c-3afe62cf88fc','山居避難六首  其三','陳著','宋','宋诗','song-poetry','','[]','宦遊二十載，時異即東還。',48,'全唐诗/poet.song.222000.json','["宦遊二十載，時異即東還。", "勇棄斗升給，本無分寸攀。", "家貧空婦巧，學廢重時頑。", "平世已無況，況巢松竹關。"]'),
('ffee639d-0c3d-4996-a69d-67c6a4ccca7e','山居避難六首  其四','陳著','宋','宋诗','song-poetry','','[]','患難合扶携，臨危路各迷。',48,'全唐诗/poet.song.222000.json','["患難合扶携，臨危路各迷。", "傳聞妻奔北，邂逅子隨西。", "心悼驚雷燕，身寒立雨雞。", "明朝問家事，空壁雪風淒。"]'),
('fd27fbbc-f91c-43ec-8692-acca7685a71e','山居避難六首  其五','陳著','宋','宋诗','song-poetry','','[]','避地託山翁，歸心亦欲東。',48,'全唐诗/poet.song.222000.json','["避地託山翁，歸心亦欲東。", "西邨明騎火，北渡撼兵風。", "抖擻塵衣黑，摩挲淚眼紅。", "何如且深隠，苟活老光鴻。"]'),
('3657b1fd-37b7-4b85-a416-13afc25042fc','山居避難六首  其六','陳著','宋','宋诗','song-poetry','','[]','人生有如夢，世變亦浮漚。',48,'全唐诗/poet.song.222000.json','["人生有如夢，世變亦浮漚。", "無有悟雙遣，窮通歸四休。", "終期風日美，不見雪霜愁。", "此意因相諗，聊寬無益憂。"]'),
('948ec353-abaf-4dbc-923b-0d1181706a63','倪峰避難','陳著','宋','宋诗','song-poetry','','[]','衰年踏險行，五賊太無情。',48,'全唐诗/poet.song.222000.json','["衰年踏險行，五賊太無情。", "落葉滑霜路，空山生夜聲。", "相携德耀隠，幾喪卜商明。", "歸計未爲是，時時心自驚。"]'),
('0411a1e5-992d-40f2-a021-1ae1717bf3dd','山家即事','陳著','宋','宋诗','song-poetry','','[]','逃難走山巔，如何要順便。',48,'全唐诗/poet.song.222000.json','["逃難走山巔，如何要順便。", "食艱蔬勝肉，衣薄炭輸綿。", "深靜初心見，高虛遠目鮮。", "沈思亦自好，寫景欠龍眠。"]'),
('4c4ecd4a-e442-4019-94b1-4df9616df0aa','雨後雪','陳著','宋','宋诗','song-poetry','','[]','深山雨易雪，片大不成花。',48,'全唐诗/poet.song.222000.json','["深山雨易雪，片大不成花。", "翁媼熱摩面，兒童寒戰牙。", "如居峩頂寺，休問洛陽花。", "宜麥今雖兆，明年事未涯。"]'),
('59f096df-9eb8-4fea-b615-6d50c8ccd3e0','雪復晴','陳著','宋','宋诗','song-poetry','','[]','冬來多是雨，日日望雲回。',48,'全唐诗/poet.song.222000.json','["冬來多是雨，日日望雲回。", "飄灑不成雪，連綿如入梅。", "高風吹日上，短景爲山催。", "那問歸家事，牀頭有宿醅。"]'),
('de8a053c-fc5f-436c-a734-abb50f1f5a56','似范景山','陳著','宋','宋诗','song-poetry','','[]','我輩豈池蛟，飛騰此一交。',48,'全唐诗/poet.song.222000.json','["我輩豈池蛟，飛騰此一交。", "天門驚路梗，冰港笑舟膠。", "甘甚新薇蕨，依然故草茅。", "從今門外事，洗耳學由巢。"]'),
('ea796187-38a5-4a77-b00c-310290e6656c','還家得驚報復回避所','陳著','宋','宋诗','song-poetry','','[]','北馬又經山，傳聞頃刻閒。',48,'全唐诗/poet.song.222000.json','["北馬又經山，傳聞頃刻閒。", "山將身坐斷，家有夢飛還。", "吞哭自憐甫，忍饑誰念顔。", "真成傷箭鳥，翼翼怕虛彎。"]'),
('c470a0bb-a3a8-46e3-a8d3-18238fbbb1f1','夜宿倪菴坐雨二首  其一','陳著','宋','宋诗','song-poetry','','[]','一自入菴來，翛然百念灰。',48,'全唐诗/poet.song.222000.json','["一自入菴來，翛然百念灰。", "松風晴後雨，澗水靜中雷。", "鄰戶祈蠶母，樵翁挾雉媒。", "若無山外事，何必過天台。"]'),
('404e373c-5c40-4846-9c48-517cfc2c4283','夜宿倪菴坐雨二首  其二','陳著','宋','宋诗','song-poetry','','[]','連朝雲靄靄，一夜雨颼颼。',48,'全唐诗/poet.song.222000.json','["連朝雲靄靄，一夜雨颼颼。", "漲霧黑天曉，洗山黄澗流。", "潤深麻長骨，濕重麥垂頭。", "春水可農事，只愁兵未休。"]'),
('70477889-1177-4e42-b003-0bebff4b4115','杜工部詩有送弟觀歸藍田迎新婦二首偶與縣尉弟達觀同名娶事又同因韻戲示  其一','陳著','宋','宋诗','song-poetry','','[]','墨龜初卜食，青鳥好音回。',48,'全唐诗/poet.song.222000.json','["墨龜初卜食，青鳥好音回。", "冰玉皆前契，風波任外來。", "重因藍袖舞，輕放赤城開。", "此事關宗事，終須飲醮杯。"]'),
('d0f3bba8-524a-4c86-ba30-a01d8b7d49d0','杜工部詩有送弟觀歸藍田迎新婦二首偶與縣尉弟達觀同名娶事又同因韻戲示  其二','陳著','宋','宋诗','song-poetry','','[]','扇手笑終在，琴心曲暗留。',48,'全唐诗/poet.song.222000.json','["扇手笑終在，琴心曲暗留。", "相期星戶夕，莫負月娥秋。", "金瀨遲揚旆，藍橋趣問舟。", "定將先入夢，驂鳳繞簫樓。"]'),
('c6ffd2a3-4189-4d8e-a2ae-b6df31047aac','次韻張子華見寄','陳著','宋','宋诗','song-poetry','','[]','老矣息林邱，平生不徑由。',48,'全唐诗/poet.song.222000.json','["老矣息林邱，平生不徑由。", "知心時一見，安分別無求。", "寒卧死中活，榮華樂處憂。", "世閒何限事，曾看過雲不。"]'),
('6d6eda2f-1955-43db-bd14-bcab30bcef1c','三月晦日同弟觀姪津往寶幢哭刑部伯求弟道從茅山泊東林寺弟觀有詩三首因次韻 東林寺','陳著','宋','宋诗','song-poetry','','[]','投憩得幽寺，便忘行路遥。',48,'全唐诗/poet.song.222000.json','["投憩得幽寺，便忘行路遥。", "竹邊流水過，門外好山朝。", "金相已流土，海音無復潮。", "池簷立良久，老衲忽相邀。"]'),
('596ea29e-7cd8-45cb-b586-6d9a00c58ccf','三月晦日同弟觀姪津往寶幢哭刑部伯求弟道從茅山泊東林寺弟觀有詩三首因次韻 寺前即事','陳著','宋','宋诗','song-poetry','','[]','劫火不飛處，便如仙洞源。',48,'全唐诗/poet.song.222000.json','["劫火不飛處，便如仙洞源。", "載秧交野艇，賣筍到僧門。", "潮水河分港，南風雨暗村。", "家山百里外，回首已黄昏。"]'),
('6819a9d0-2a91-40fb-88e9-75763cf5dcaa','三月晦日同弟觀姪津往寶幢哭刑部伯求弟道從茅山泊東林寺弟觀有詩三首因次韻 坐雨','陳著','宋','宋诗','song-poetry','','[]','山泉今已矣，開落夢中花。',48,'全唐诗/poet.song.222000.json','["山泉今已矣，開落夢中花。", "欲哭青松墓，却留黄檗家。", "眼花飛作練，心事苦如茶。", "造物故相阻，雨陰殊未涯。"]'),
('71a4dd04-5f38-4870-8207-eae5b72d2b28','次韻延慶僧惟巧山見贈','陳著','宋','宋诗','song-poetry','','[]','巧山元不巧，此處不容傳。',48,'全唐诗/poet.song.222000.json','["巧山元不巧，此處不容傳。", "意到頭撞壁，吟香口有蓮。", "江山皆逆旅，風月獨知賢。", "世事如何說，相看一笑邊。"]'),
('98d044e8-0633-4fbb-bd50-c23f37a82a4d','次韻西山寺主僧清月','陳著','宋','宋诗','song-poetry','','[]','高占古松閒，塵埃笑却還。',48,'全唐诗/poet.song.222000.json','["高占古松閒，塵埃笑却還。", "禪機參翠竹，詩價重青山。", "長與雲分榻，時從鶴出關。", "誰云寺門小，窮處足清閒。"]'),
('e0053410-6062-4fd7-81d6-7223caf1463c','俞蓀墅示以雜興四首乃用危驪塘所次唐子西韻因次韻  其一','陳著','宋','宋诗','song-poetry','','[]','小小山前屋，深深竹裏門。',48,'全唐诗/poet.song.222000.json','["小小山前屋，深深竹裏門。", "艱關諳世夢，寬綽養天根。", "趣涉詩書圃，名歸耕釣邨。", "日長無一事，笑諾子孫繁。"]'),
('ec268aed-5d64-40c6-8cfb-c1a4b6d845c4','俞蓀墅示以雜興四首乃用危驪塘所次唐子西韻因次韻  其二','陳著','宋','宋诗','song-poetry','','[]','羨君培早學，人十己千之。',48,'全唐诗/poet.song.223000.json','["羨君培早學，人十己千之。", "燕雀誰知我，蛟龍自有時。", "文場魁衆後，計幕主相知。", "天地如長泰，功名何可涯。"]'),
('326a97b8-0d76-465d-9d3b-789f27403bb0','俞蓀墅示以雜興四首乃用危驪塘所次唐子西韻因次韻  其三','陳著','宋','宋诗','song-poetry','','[]','乾坤今似許，焮禍自非材。',48,'全唐诗/poet.song.223000.json','["乾坤今似許，焮禍自非材。", "危活矛頭米，驚愁笛裏梅。", "世方淫佛老，誰肯問參囘。", "太息復太息，吾徒何以哉。"]'),
('0108eca8-4879-47b0-95a8-da844066dcfe','俞蓀墅示以雜興四首乃用危驪塘所次唐子西韻因次韻  其四','陳著','宋','宋诗','song-poetry','','[]','人生無足處，知足是良方。',48,'全唐诗/poet.song.223000.json','["人生無足處，知足是良方。", "自種蓀成墅，時同雲出鄉。", "江湖殘夢杳，山谷本心長。", "回首門前事，風潮戰石塘。"]'),
('9801dcd7-3ef8-4219-a85b-ac52c194860e','俞蓀墅示以雜興四首乃用危驪塘所次唐子西韻因次韻  其五','陳著','宋','宋诗','song-poetry','','[]','平平聊送目，咄咄不書空。',48,'全唐诗/poet.song.223000.json','["平平聊送目，咄咄不書空。", "靜見蝸爭國，窮知馬福翁。", "逢人無眼白，耐是得顔紅。", "如此閒光景，何須到弱蓬。"]'),
('09271282-ad09-4fdd-92cb-279faf3648c8','俞蓀墅示以雜興四首乃用危驪塘所次唐子西韻因次韻  其六','陳著','宋','宋诗','song-poetry','','[]','學得無名氏，遊於何有鄉。',48,'全唐诗/poet.song.223000.json','["學得無名氏，遊於何有鄉。", "熟眠勝醉酒，清慮當焚香。", "富有書連架，貧無盜伏梁。", "只應詩社友，時節到門牆。"]'),
('b43ba2d7-3e56-44df-a801-4da52c2057e7','俞蓀墅示以雜興四首乃用危驪塘所次唐子西韻因次韻  其七','陳著','宋','宋诗','song-poetry','','[]','世運空更禪，人情任覆翻。',48,'全唐诗/poet.song.223000.json','["世運空更禪，人情任覆翻。", "浮榮歸墮甑，真味寄汙尊。", "見客不問事，學農時踏邨。", "興公舊遊處，長嘯一招魂。"]'),
('10aef6b6-35df-494b-b1d5-6dd2ed89866c','俞蓀墅示以雜興四首乃用危驪塘所次唐子西韻因次韻  其八','陳著','宋','宋诗','song-poetry','','[]','我才雖不武，縱靶洛陽橋。',48,'全唐诗/poet.song.223000.json','["我才雖不武，縱靶洛陽橋。", "本是士行志，非因貧折腰。", "天風吹劫火，國事付回潮。", "待盡山深處，汗顔猨鶴邀。"]'),
('7726536c-2c6b-4a44-89a4-2d6c7505da60','俞蓀墅示以雜興四首乃用危驪塘所次唐子西韻因次韻  其九','陳著','宋','宋诗','song-poetry','','[]','道路塵方暗，田園事豈差。',48,'全唐诗/poet.song.223000.json','["道路塵方暗，田園事豈差。", "營巢難老鶴，謀啄拙饑鴉。", "時有詩題壁，多因病在家。", "學仙非骨相，枉是住丹霞。"]'),
('d7dd4e49-22d1-428a-9278-74ac673f3739','俞蓀墅示以雜興四首乃用危驪塘所次唐子西韻因次韻  其一○','陳著','宋','宋诗','song-poetry','','[]','詩卷勞相寄，吟高欲和難。',48,'全唐诗/poet.song.223000.json','["詩卷勞相寄，吟高欲和難。", "澹情如水接，秀句共霞餐。", "妄奏蛙聲樂，叨盟馬血盤。", "豈能無牴觸，一笑幸吾寬。"]'),
('f6b29eae-f39c-4dbb-886d-8496a631762a','次韻史芝崖','陳著','宋','宋诗','song-poetry','','[]','浮生真夢幻，看破已頻頻。',48,'全唐诗/poet.song.223000.json','["浮生真夢幻，看破已頻頻。", "花柳春心古，乾坤世事新。", "爭芳多煖處，感舊獨幽人。", "寶重復珍重，清風明月身。"]'),
('00f22ccd-550f-416a-8821-77aa153e4d3c','次韻石秀叔','陳著','宋','宋诗','song-poetry','','[]','揮手世閒塵，忘言晉與秦。',48,'全唐诗/poet.song.223000.json','["揮手世閒塵，忘言晉與秦。", "溪山能住客，風雨始知人。", "澹澹秋光趣，悠悠野鶴身。", "相聞願相見，倦脚走雙輪。"]'),
('42c9cf0c-4180-42dd-bb11-564178da6986','次韻齡叟見寄','陳著','宋','宋诗','song-poetry','','[]','方外好交情，詩筒出醉屏。',48,'全唐诗/poet.song.223000.json','["方外好交情，詩筒出醉屏。", "清能濯驕暑，光欲掩常星。", "自愧薄榆景，有生真草亭。", "多年祇多感，岌岌舊門庭。"]'),
('dfe5816a-2b5e-48b9-a08d-715451ac8e9b','崇福寺大用堂乃魏文節祠舊有半牀雲一窗月在兩掖取舒嬾堂詩中語也主僧澤南洲撤兩掖尊大用堂而新之魏東齋有詩因次韻','陳著','宋','宋诗','song-poetry','','[]','魯公香火寺，便道幾經行。',48,'全唐诗/poet.song.223000.json','["魯公香火寺，便道幾經行。", "樹老存高節，碑全見太平。", "浮雲從變化，古月自分明。", "頼有文孫在，毋忘大用名。"]'),
('4a96db08-ab18-4b29-8eba-19afaf7341c5','謝趙菊泉來會於范曉邨家','陳著','宋','宋诗','song-poetry','','[]','虎林唐姥嶺，牛淖范公亭。',48,'全唐诗/poet.song.223000.json','["虎林唐姥嶺，牛淖范公亭。", "不是義高古，誰能行戴星。", "開尊春酒赤，對榻夜鐙青。", "說到閒關處，令人心有銘。"]'),
('5d0d0769-649a-4616-bd90-d5d4bd938d73','用前韻呈曉邨','陳著','宋','宋诗','song-poetry','','[]','溪山兩相望，只隔五長亭。',48,'全唐诗/poet.song.223000.json','["溪山兩相望，只隔五長亭。", "一見坐聯日，高談氣拂星。", "好賓知絡秀，兼僕困樵青。", "此會受多益，歸途杖可銘。"]'),
('a269d5a4-a412-409a-91de-56ff38335a3c','雨中留范曉邨家','陳著','宋','宋诗','song-poetry','','[]','年來常閉戶，一動自知非。',48,'全唐诗/poet.song.223000.json','["年來常閉戶，一動自知非。", "坐雨詩消悶，思家夢當歸。", "山林容自拙，道路目孤飛。", "便整回頭步，西園筍薤肥。"]'),
('1810243a-dd6a-4c90-95d6-44ecf875577b','到永固寺訪曹約齋','陳著','宋','宋诗','song-poetry','','[]','本是塵埃客，夤緣到上方。',48,'全唐诗/poet.song.223000.json','["本是塵埃客，夤緣到上方。", "茶嘗新雨味，酒吸綠陰香。", "半日清風古，百年佳話長。", "悠悠一俯仰，我欲憩斜陽。"]'),
('907ea4bf-c6f0-4634-939b-1f73082e8e8e','用前韻送酒與約齋','陳著','宋','宋诗','song-poetry','','[]','人生以類合，圓木不投方。',48,'全唐诗/poet.song.223000.json','["人生以類合，圓木不投方。", "家話太平舊，山盟晚節香。", "百罹心易足，一醉味何長。", "但得靜中樂，邨邨皆洛陽。"]'),
('cbc862c4-4127-408c-99fd-3e6f3fa1d34c','到浄慈展墓次韻吳棣窗','陳著','宋','宋诗','song-poetry','','[]','有客肯尋僧，新吟漬剡藤。',48,'全唐诗/poet.song.223000.json','["有客肯尋僧，新吟漬剡藤。", "交情自秋月，浮世看春冰。", "猶顧慈雲榻，相期元夜鐙。", "我來當付約，樓上看陳登。"]'),
('940bd9d2-b53b-4c58-abb7-fcadae77b25c','再用前韻謝吳竹修','陳著','宋','宋诗','song-poetry','','[]','禿髠歸陽羨，仙髯卧古藤。',48,'全唐诗/poet.song.223000.json','["禿髠歸陽羨，仙髯卧古藤。", "前賢成昨夢，後輩嗣誰鐙。", "傾蓋欣如故，吟壇得共登。", "春風吹相聚，聊此寄韋冰。"]'),
('ca4fee29-7ab3-43c2-b319-a29436d5bed6','答吳棣窗','陳著','宋','宋诗','song-poetry','','[]','來訪在家僧，連牀坐夜鐙。',48,'全唐诗/poet.song.223000.json','["來訪在家僧，連牀坐夜鐙。", "狂談拋玉麈，劇飲渴黄藤。", "一見皆風月，相投不炭冰。", "何當長作伴，山水足臨登。"]'),
('b9cb121c-a06a-4e07-b474-7065f00a21f7','與齡叟','陳著','宋','宋诗','song-poetry','','[]','幾年西崦寺，門蘚路交藤。',48,'全唐诗/poet.song.223000.json','["幾年西崦寺，門蘚路交藤。", "龍象開禪席，鐘魚張法鐙。", "領徒耕趁雨，對客句裁冰。", "我亦相忘者，慈雲得屢登。"]'),
('d3f39f14-efa1-476e-814d-47f6a6b4f30f','醉書永固方丈示東隠','陳著','宋','宋诗','song-poetry','','[]','西麓與東峯，前緣得二翁。',48,'全唐诗/poet.song.223000.json','["西麓與東峯，前緣得二翁。", "雅心千古上，慈汁一尊同。", "猛省塵埃夢，飽參松竹風。", "黄綺在何處，我欲問冥鴻。"]'),
('dd4a9a54-e132-4679-9bd3-14ee59273ae0','用前韻答齡叟見寄','陳著','宋','宋诗','song-poetry','','[]','草堂存老我，茅屋著而翁。',48,'全唐诗/poet.song.223000.json','["草堂存老我，茅屋著而翁。", "門戶兩家異，溪山一趣同。", "夜鑪榾柮火，春閣杏花風。", "何惜盟吟社，浮塵付過鴻。"]'),
('1cb3b747-bfee-470b-8bc4-ebefc557ff96','題晚照樓','陳著','宋','宋诗','song-poetry','','[]','乳峰天下景，清景此尤多。',48,'全唐诗/poet.song.223000.json','["乳峰天下景，清景此尤多。", "簷影夕陽樹，簾香新水荷。", "虛通雲入室，平送鶴歸窠。", "高坐清凉境，人閒自沸鍋。"]'),
('0ef158a0-0efd-4790-b538-b6081b133d13','呈雪竇僧野翁','陳著','宋','宋诗','song-poetry','','[]','雨屋又留連，回頭七載前。',48,'全唐诗/poet.song.223000.json','["雨屋又留連，回頭七載前。", "同遊半黄土，百感兩霜顛。", "睡醒茶爲祟，吟清山結緣。", "他年北窗下，誰復對牀眠。"]'),
('6e4212ac-8236-4c24-8a47-1f9a8e5a3e2d','丹山主者恭雪航年七十餘清苦善吟八句以似','陳著','宋','宋诗','song-poetry','','[]','本是住林深，浮雲載出林。',48,'全唐诗/poet.song.223000.json','["本是住林深，浮雲載出林。", "蹣跚多病脚，邂逅十年心。", "破鼓饑甘飯，殘鐙老醒吟。", "我來相訪外，梅竹是知音。"]'),
('254aeca7-3ff1-4922-ba56-c762a94ad4a3','丹山酒邊','陳著','宋','宋诗','song-poetry','','[]','衰老受晴光，相携到上方。',48,'全唐诗/poet.song.223000.json','["衰老受晴光，相携到上方。", "意濃忘酒薄，話美奪塵忙。", "天竹靜逾媚，溪梅初有香。", "危時正多事，半日太平鄉。"]'),
('e265dc40-e47f-4fd0-b028-6c68e1ba3d25','次弟觀二首呈雪航  其一','陳著','宋','宋诗','song-poetry','','[]','流俗方瀾倒，禪心自鐵頑。',48,'全唐诗/poet.song.223000.json','["流俗方瀾倒，禪心自鐵頑。", "人於詩信老，天與病全閒。", "拄杖溪山曲，移尊雪月閒。", "相逢多拙句，爲我細修刪。"]'),
('5e60a925-bf0a-4d29-b82b-f8a62bf8e72f','次弟觀二首呈雪航  其二','陳著','宋','宋诗','song-poetry','','[]','如今事如許，我得强癡頑。',48,'全唐诗/poet.song.223000.json','["如今事如許，我得强癡頑。", "避世貧爲福，信天忙亦閒。", "乾坤孤注外，風月兩顰閒。", "賸有遊山記，從他野筆刪。"]'),
('02d6d536-8f6a-48f1-b116-c2379157372f','遊慈雲二首  其一','陳著','宋','宋诗','song-poetry','','[]','今夕是何夕，相携踏雪乾。',48,'全唐诗/poet.song.223000.json','["今夕是何夕，相携踏雪乾。", "弟兄清濁酒，僧俗素葷盤。", "邂逅半年事，笑談終日歡。", "欲歸歸未得，戀月靠闌干。"]'),
('f4b02671-7e8a-4678-8df1-6007d72158cf','遊慈雲二首  其二','陳著','宋','宋诗','song-poetry','','[]','有分醉慈雲，相留氣味真。',48,'全唐诗/poet.song.223000.json','["有分醉慈雲，相留氣味真。", "榧香千丈雪，筍雋萬年春。", "此會不多見，如今能幾人。", "胡爲弗回首，三笑亦風塵。"]'),
('dc78a7ec-873f-419c-b381-2bde30529763','與單君範坐凝光亭','陳著','宋','宋诗','song-poetry','','[]','危世見交情，相逢坐小亭。',48,'全唐诗/poet.song.223000.json','["危世見交情，相逢坐小亭。", "平看二麥秀，虛受萬山青。", "往事酒俱醉，可人詩自醒。", "悠悠一俯仰，白鳥入冥冥。"]'),
('39cab754-6b70-47d3-9496-32b0ba4adaf5','次韻趙菊泉','陳著','宋','宋诗','song-poetry','','[]','世衰人物眇，猶見得閒平。',48,'全唐诗/poet.song.223000.json','["世衰人物眇，猶見得閒平。", "劫火詩書脈，春風杖履盟。", "霏霏木屑話，淡淡菜羹情。", "相對青鐙下，平生心事明。"]'),
('a1a14835-e763-4612-af0d-a22cfc6535db','次韻黄長孺別陳子得','陳著','宋','宋诗','song-poetry','','[]','兩閒何納納，長夜正漫漫。',48,'全唐诗/poet.song.223000.json','["兩閒何納納，長夜正漫漫。", "感舊心猶熱，逢春眼自寒。", "人情伐木宋，世變幻花韓。", "寂寞衡茅下，從他作拙看。"]'),
('90f0e7b4-7f49-433c-8efc-6bd80493150d','題東堂竹','陳著','宋','宋诗','song-poetry','','[]','種來三世遠，一片綠猗猗。',48,'全唐诗/poet.song.223000.json','["種來三世遠，一片綠猗猗。", "節直清自見，心虛高不知。", "甯求千畝富，足與七賢期。", "要得龍孫茂，封培無已時。"]'),
('d7403444-4b44-436b-bfb9-f8290d5ee84d','次韻弟觀田蠶即事','陳著','宋','宋诗','song-poetry','','[]','詩禮雖傳世，農桑不離門。',48,'全唐诗/poet.song.223000.json','["詩禮雖傳世，農桑不離門。", "梅天繅雪屋，秧雨種雲邨。", "衣帛知先老，含飴擬弄孫。", "願言同井樂，無怨亦無恩。"]'),
('4a8a264a-3dfb-473a-861c-1a29b2e5dce1','長孺以新生子求名命曰相兒','陳著','宋','宋诗','song-poetry','','[]','有女諧良偶，承宗在嫡兒。',48,'全唐诗/poet.song.223000.json','["有女諧良偶，承宗在嫡兒。", "館甥纔匝歲，宅相果如期。", "脈發慈溪正，胞成江夏奇。", "咳名應會得，乳口見嘔咿。"]'),
('85302160-a8ba-4add-a756-700a62a5c204','次韻竺梅潭老境','陳著','宋','宋诗','song-poetry','','[]','浮生年復年，安處即神仙。',48,'全唐诗/poet.song.223000.json','["浮生年復年，安處即神仙。", "子壯閒專日，家和笑答天。", "軟炊脂白米，甜釀雪清泉。", "蔗境有餘味，吟情真造玄。"]'),
('e02a1073-1a55-46a8-9300-d8b03879f089','喜見單君範八句','陳著','宋','宋诗','song-poetry','','[]','世衰交道薄，相好獨金蘭。',48,'全唐诗/poet.song.223000.json','["世衰交道薄，相好獨金蘭。", "見面驚雙瘦，知心話百難。", "老饕葱本煖，清坐杏花寒。", "明日休輕別，流年水赴灘。"]'),
('18a92f67-7013-4cfd-a815-e194d67bcbe5','靈濟菴主僧泉蒙山招飲偶成','陳著','宋','宋诗','song-poetry','','[]','水面巧安排，軒窗爽豁哉。',48,'全唐诗/poet.song.223000.json','["水面巧安排，軒窗爽豁哉。", "橋關江氣定，門約市聲開。", "遠景天相送，清風客自來。", "夜牀凉睡足，有夢到蓬萊。"]'),
('e12210e9-d258-42e1-8109-6136b4173c6f','留范景山家聞夜警有作','陳著','宋','宋诗','song-poetry','','[]','鐙窗坐無寐，吾亦自憐吾。',48,'全唐诗/poet.song.223000.json','["鐙窗坐無寐，吾亦自憐吾。", "活在虎狼窟，老猶風雨途。", "世情多短氣，心事一長吁。", "幸有秋成好，仍聞夜警呼。"]'),
('c2d6c1cf-688e-43cd-9e8f-12f3bc61d1ce','雨留景山家','陳著','宋','宋诗','song-poetry','','[]','桂後菊花前，相逢夢覺然。',48,'全唐诗/poet.song.223000.json','["桂後菊花前，相逢夢覺然。", "閒心時外話，親意雨中眠。", "投老會難必，臨行留更堅。", "西風亦解事，未肯放晴天。"]'),
('31de1c42-34a8-45e3-8c32-2b5673ec0b9a','晴歸','陳著','宋','宋诗','song-poetry','','[]','兒造弄晴曦，安排老我歸。',48,'全唐诗/poet.song.223000.json','["兒造弄晴曦，安排老我歸。", "江收閒水退，山戴斷雲飛。", "晚色明官路，清寒攪客衣。", "行行到嵩曲，猶可及斜暉。"]'),
('4b8d4959-46c5-4ecf-88c7-a7b9e7933326','范公亭歸途','陳著','宋','宋诗','song-poetry','','[]','客窗連日雨，晨發趁晴光。',48,'全唐诗/poet.song.223000.json','["客窗連日雨，晨發趁晴光。", "禿鬢去秋老，倦心愁路長。", "終須山坐靜，有感水流忙。", "更有難言處，乾坤事渺茫。"]'),
('7bb663a4-c5ff-4846-bc03-87e63124866e','白珽寄詩次韻見意','陳著','宋','宋诗','song-poetry','','[]','江干風雨別，君住我來回。',48,'全唐诗/poet.song.223000.json','["江干風雨別，君住我來回。", "兩地夢相覓，十年書一來。", "字參老未到，詩放晚唐開。", "直要吟成史，掃清塵世埃。"]'),
('5ac4af97-5d2e-4edb-9d3b-c60d59681421','用梅山別諸賢韻','陳著','宋','宋诗','song-poetry','','[]','世變事難必，天倫愛自深。',48,'全唐诗/poet.song.223000.json','["世變事難必，天倫愛自深。", "醉醒皆外物，甘苦共初心。", "倦翼山招返，寒林風爲吟。", "何當長聚首，衰境況侵尋。"]'),
('558a055a-601b-407e-b9d0-d3ff1fd59dd5','齡叟醉我以鼓笛之筵八句見意','陳著','宋','宋诗','song-poetry','','[]','樓閣倚晴天，知心得老禪。',48,'全唐诗/poet.song.223000.json','["樓閣倚晴天，知心得老禪。", "風光百年事，民命數家煙。", "鐙火猶嬉鼓，山林有醉筵。", "殘生聊爾耳，休話到兵前。"]'),
('79615ee8-24fa-469c-9185-f994eb3b2e1a','次韻吳竹修發慈雲','陳著','宋','宋诗','song-poetry','','[]','入山知幾約，手墨未曾乾。',48,'全唐诗/poet.song.223000.json','["入山知幾約，手墨未曾乾。", "危世一遊重，清交百念寒。", "吟成佳句易，說到太平難。", "終夜飲不醉，何從得睡鼾。"]'),
('8d88e16f-e5ec-4e50-bac8-12b40e547878','靈濟菴會高麗僧全息菴八句遺之','陳著','宋','宋诗','song-poetry','','[]','生其箕子國，來拜觀音山。',48,'全唐诗/poet.song.223000.json','["生其箕子國，來拜觀音山。", "迢迢萬里外，了了一見閒。", "風波任浩蕩，雲月自往還。", "莫怪圖三笑，我非元亮班。"]'),
('fe657a2b-c11b-4b78-9d31-4e04f71a2c74','書於靈濟方丈','陳著','宋','宋诗','song-poetry','','[]','信步領兒行，又來天盡堂。',48,'全唐诗/poet.song.223000.json','["信步領兒行，又來天盡堂。", "老衰憑酒健，春好得詩香。", "花柳年年事，江山處處鄉。", "拍闌一相笑，白鳥入微茫。"]'),
('b10baf6f-9c67-4c27-b6dd-35bd19b75b1e','酒邊呈鄭耐軒','陳著','宋','宋诗','song-poetry','','[]','行行曲曲廊，迤邐入書房。',48,'全唐诗/poet.song.223000.json','["行行曲曲廊，迤邐入書房。", "多客坐氈煖，百花吟几香。", "人閒正桃李，屋角自蔬桑。", "信是閒中好，相忘古話長。"]'),
('4e75cfd8-7034-4706-bfc9-d2dab6af6311','靈溪房偶成','陳著','宋','宋诗','song-poetry','','[]','隨雲入寶坊，寄憩正師房。',48,'全唐诗/poet.song.223000.json','["隨雲入寶坊，寄憩正師房。", "醉枕老易醒，閒窗春亦忙。", "暄風□花氣，好客带詩香。", "信美難久住，我家山水鄉。"]'),
('4805e7de-9a76-4e0a-a97e-df87103435e3','翌日風雨再用韻','陳著','宋','宋诗','song-poetry','','[]','初心驥伏坊，活計蟻營房。',48,'全唐诗/poet.song.223000.json','["初心驥伏坊，活計蟻營房。", "家與水雲遠，春方風月忙。", "僧窗熟處穩，兒信狎來香。", "去住底須問，悠悠何有鄉。"]'),
('2035ca81-b5a7-4870-bb26-f3d59a811ffe','遲留又用韻','陳著','宋','宋诗','song-poetry','','[]','宿留不覺久，非因戀竹房。',48,'全唐诗/poet.song.223000.json','["宿留不覺久，非因戀竹房。", "山林遲老死，萍梗急貧忙。", "走俗形幾穢，還家夢亦香。", "未能憑古語，安處是吾鄉。"]'),
('095e19d9-1219-434a-bf79-bada08bcf4c5','黄虛谷以唐體五言一首來別次韻餞其歸','陳著','宋','宋诗','song-poetry','','[]','我欲話時窮，非翁誰與從。',48,'全唐诗/poet.song.223000.json','["我欲話時窮，非翁誰與從。", "老來有兩健，春到得相逢。", "潮水明朝櫓，雲山後夜鐘。", "相思無盡處，樽酒幾時重。"]'),
('1f78a5d1-21a8-45ab-8c72-8cc7bb439171','次韻天台陳榆收','陳著','宋','宋诗','song-poetry','','[]','世態自浮輕，猶存冷處盟。',48,'全唐诗/poet.song.223000.json','["世態自浮輕，猶存冷處盟。", "功名隨泡影，道義要權衡。", "打破片雲隔，來分半日清。", "且須謀隠事，未問把天擎。"]'),
('dfdcae16-e8f5-4bd4-aa96-7a11f76eab25','似史和甫傳清','陳著','宋','宋诗','song-poetry','','[]','翩翩鶴往還，高眼看塵寰。',48,'全唐诗/poet.song.223000.json','["翩翩鶴往還，高眼看塵寰。", "家世崔盧上，風流晉宋閒。", "開門種桃李，落筆動江山。", "勳業時來做，青春贏得閒。"]'),
('c2ef2179-fc6f-44f7-b6e6-013f5d5d465d','用長兒韻謝黄長孺酒','陳著','宋','宋诗','song-poetry','','[]','薄俗方沈溺，親情自酌斟。',48,'全唐诗/poet.song.223000.json','["薄俗方沈溺，親情自酌斟。", "雨聲書屋冷，春意酒杯深。", "危世不多話，醉中時一吟。", "明年如老健，此會得重尋。"]'),
('3b72291c-3d6e-4426-9be9-58cd1fc532e2','次韻虛谷和長兒奉別','陳著','宋','宋诗','song-poetry','','[]','有便勤相問，何時得近依。',48,'全唐诗/poet.song.223000.json','["有便勤相問，何時得近依。", "詩搜腸藿瘦，字爲眼花肥。", "雲遠心猶遠，春歸人未歸。", "羨君牢閉戶，珍重白山衣。"]'),
('ba7daeb7-5ca7-4590-8b88-71e7b3d65d5b','雨中旅懷呈鄭耐軒','陳著','宋','宋诗','song-poetry','','[]','日日約歸舟，誰知雨又留。',48,'全唐诗/poet.song.223000.json','["日日約歸舟，誰知雨又留。", "滿城爲海市，數步有蓬洲。", "濕夢風難送，急心天與仇。", "今朝好晴色，著履可來不。"]'),
('0dbe94b3-6318-4939-aeb1-4de556d0428c','又自用韻','陳著','宋','宋诗','song-poetry','','[]','泛泛一風舟，誰與管去留。',48,'全唐诗/poet.song.223000.json','["泛泛一風舟，誰與管去留。", "兒翁忘市井，女友隔河洲。", "聊爾詩還債，從他笑有仇。", "山林原自好，明日得歸不。"]'),
('d2fadd41-3249-4f72-bcaf-2deb26cb72d2','城歸憩吳竹修家一詩寫懷','陳著','宋','宋诗','song-poetry','','[]','去時桃未蕊，歸見石榴花。',48,'全唐诗/poet.song.223000.json','["去時桃未蕊，歸見石榴花。", "白首鐙前酒，青山夢裏家。", "鵑聲心路梗，蚊毒面皮麻。", "勞苦書生事，堪嗟老未涯。"]'),
('218f7bf1-7d9f-4be5-94c3-adfc15f7b067','留西山','陳著','宋','宋诗','song-poetry','','[]','西崦已非舊，菴居猶自妍。',48,'全唐诗/poet.song.223000.json','["西崦已非舊，菴居猶自妍。", "樹頭擎月直，山腹轉風圓。", "閒坐忙塵外，清談濁酒邊。", "悠悠一俯仰，今日是何年。"]'),
('5063909f-3b17-4e41-89ff-1f767d85ded8','次韻齡叟招石秀叔','陳著','宋','宋诗','song-poetry','','[]','久知難久別，飛約到柴門。',48,'全唐诗/poet.song.223000.json','["久知難久別，飛約到柴門。", "喚起雨窗困，踏開嵐徑昏。", "世情忙外看，交道淡中存。", "何日巳公屋，新詩得共論。"]'),
('85c60a9c-348a-428d-84e0-f6623e92bbe8','齡叟以詩來壽余次韻以復','陳著','宋','宋诗','song-poetry','','[]','彼美慈雲叟，相存馬少游。',48,'全唐诗/poet.song.223000.json','["彼美慈雲叟，相存馬少游。", "槐淘參玉版，藻句粲銀鉤。", "外友更誰在，前緣曾共修。", "從今各珍重，萬事等虛舟。"]'),
('5fabbf14-d525-4998-9cce-96af976062f2','宿洞真觀呈盧竹溪','陳著','宋','宋诗','song-poetry','','[]','傍家新築好，儒道不相妨。',48,'全唐诗/poet.song.223000.json','["傍家新築好，儒道不相妨。", "松火客牀夢，梅花詩屋香。", "欲盟六逸醉，始託四明狂。", "高視黄塵表，翛然何有鄉。"]'),
('73c55cfb-c996-4f99-acd9-3ea73a10ab1c','樊伯推守歲有詩因次韻以自寫','陳著','宋','宋诗','song-poetry','','[]','盤花明日頌，草草數杯先。',48,'全唐诗/poet.song.223000.json','["盤花明日頌，草草數杯先。", "醉以客呼夜，老嫌人問年。", "那知新換歲，得似舊安眠。", "浮世自多事，春風無棄憐。"]'),
('b22f21da-5abf-41c1-834b-ff315abe05c6','似永固主僧惠福','陳著','宋','宋诗','song-poetry','','[]','偶來乘暇隙，又過古禪林。',48,'全唐诗/poet.song.223000.json','["偶來乘暇隙，又過古禪林。", "白日鐘魚外，清風竹樹陰。", "無言自有趣，得句亦何心。", "相見不相問，老僧知我深。"]'),
('a49fc7a6-1530-49a1-b4de-e8323ad4ea29','與內姪汪景淵西窗小酌','陳著','宋','宋诗','song-poetry','','[]','窗下綢繆處，尊中感愴初。',48,'全唐诗/poet.song.223000.json','["窗下綢繆處，尊中感愴初。", "難危親話重，修阻見時疏。", "老別堪三載，交談勝百書。", "溪山已非昔，爾後更何如。"]'),
('e4b82792-fdc1-45e5-8ddc-6b0b42617d6b','次韻梅山弟見懷','陳著','宋','宋诗','song-poetry','','[]','自笑緣何事，老來還客中。',48,'全唐诗/poet.song.223000.json','["自笑緣何事，老來還客中。", "唱花悲杜牧，隠杵愧梁鴻。", "頗憶良眉白，相歡醉面紅。", "如今各成別，方信坐天窮。"]'),
('dc814b19-49b5-4f9a-bda2-181498b6bf94','謝王景之用前韻見寄','陳著','宋','宋诗','song-poetry','','[]','詩卷舞西風，翩然入眼中。',48,'全唐诗/poet.song.223000.json','["詩卷舞西風，翩然入眼中。", "健回追電馬，清落唳霜鴻。", "遺我寶吳縞，逢人稱相紅。", "但存山上果，誰道剝爲窮。"]'),
('f245d8f7-0c26-4c7e-9651-0a456e9aeda0','遊浄慈道中','陳著','宋','宋诗','song-poetry','','[]','衰年少出門，信步過冬暄。',48,'全唐诗/poet.song.223000.json','["衰年少出門，信步過冬暄。", "黄葉問梅路，青煙芟麥邨。", "危時一自適，造物萬相□。", "試與松風約，尚堪來幾番。"]'),
('097bfc7c-70d4-4708-af20-725d0cf64caa','登慈雲閣','陳著','宋','宋诗','song-poetry','','[]','徜徉古梵宮，如坐畫圖中。',48,'全唐诗/poet.song.223000.json','["徜徉古梵宮，如坐畫圖中。", "峯礙半山日，閣來三面風。", "靜觀知物變，老話入僧空。", "莫訝攙門戶，吾今已禿翁。"]'),
('945fb38a-c971-4c07-8ebd-993e4ad5ae92','次韻內姪竺稷并示諸兒','陳著','宋','宋诗','song-poetry','','[]','春首還相見，吾懷白與兄。',48,'全唐诗/poet.song.223000.json','["春首還相見，吾懷白與兄。", "江湖關老夢，山野避新行。", "危慮船迎浪，殘生漏送更。", "東風溪上路，欲別若爲情。"]'),
('c8671e00-b517-44c6-b82b-95b184589ddd','避難西坑用瀹韻','陳著','宋','宋诗','song-poetry','','[]','頭禿鬢蕭蕭，誰知生轉勞。',48,'全唐诗/poet.song.223000.json','["頭禿鬢蕭蕭，誰知生轉勞。", "危心貪避遠，老脚失低高。", "薄採義山蕨，難逢仙徑桃。", "如何是歸日，世事正囂囂。"]'),
('86b1dfd5-a22a-4b6a-b29d-724d52d44dd7','丙子丁丑年避難南山之西坑今春投北山兩雪竇閒其地名適與前同因記以八句','陳著','宋','宋诗','song-poetry','','[]','西坑曾避難，今又一西坑。',48,'全唐诗/poet.song.223000.json','["西坑曾避難，今又一西坑。", "十有四年夢，兩番多事驚。", "天乎存老息，地亦定前名。", "何動不關命，怡然心氣平。"]'),
('b3def881-c0f2-435c-ad4b-a04a300f2ec2','次弟觀似單君範','陳著','宋','宋诗','song-poetry','','[]','可人忽相訪，恰恰應鐙花。',48,'全唐诗/poet.song.223000.json','["可人忽相訪，恰恰應鐙花。", "古話達時樣，霜毛感歲華。", "雨中書枕榻，山下菜羹家。", "一笑君聽取，歸期待白鴉。"]'),
('786153d1-e794-411b-a4b4-48cc07cb261c','即事','陳著','宋','宋诗','song-poetry','','[]','出門問春事，猶在可疑閒。',48,'全唐诗/poet.song.223000.json','["出門問春事，猶在可疑閒。", "雲弄欲晴日，風堅曾雪山。", "千林芳信遠，百鳥好聲慳。", "要識天珍重，時光漸漸還。"]'),
('4fc7822b-a6fc-4b25-bd7c-0586a2810a9d','元夕風雨','陳著','宋','宋诗','song-poetry','','[]','明日又元日，邨祠一鬨人。',48,'全唐诗/poet.song.223000.json','["明日又元日，邨祠一鬨人。", "溪山渾是雨，鐙火若爲春。", "忍見饑成鬼，癡將飽望神。", "誰知生意處，官好自憂民。"]'),
('7a3dc47c-4d58-420f-865d-9d343fce0f18','醉中示梅山弟','陳著','宋','宋诗','song-poetry','','[]','浮生無足處，樂事有誰真。',48,'全唐诗/poet.song.223000.json','["浮生無足處，樂事有誰真。", "風雨少晴日，弟兄能幾人。", "清談流俗外，薄醉小窗春。", "栩栩投牀夢，方知造物仁。"]'),
('94b15329-e7bd-41e4-977e-dffd6368dc57','即事','陳著','宋','宋诗','song-poetry','','[]','新正已强半，連陰凝不開。',48,'全唐诗/poet.song.223000.json','["新正已强半，連陰凝不開。", "雨聲嚴似雪，春色瘦於梅。", "老不問花事，病猶須酒杯。", "東風自時樣，於我亦悠哉。"]'),
('55462897-6b2d-4b52-adb5-6c5a3b027862','過梅山弟家','陳著','宋','宋诗','song-poetry','','[]','好景在西林，晴邊取次尋。',48,'全唐诗/poet.song.223000.json','["好景在西林，晴邊取次尋。", "路融山脈水，屋戴樹毛陰。", "動脚影爲僕，舉頭天見心。", "清風知酒病，吹我兩衣襟。"]'),
('1258c985-8406-4b4d-b991-af78d4074788','脾疼大作','陳著','宋','宋诗','song-poetry','','[]','頭童面菜色，七十八年閒。',48,'全唐诗/poet.song.223000.json','["頭童面菜色，七十八年閒。", "聊把吟移病，何曾笑答閒。", "老妻愁日計，弱子怯時艱。", "此意有誰會，門前溪與山。"]'),
('70162800-155e-40b2-8dfb-dee4cdc40603','齡叟招飲醉中','陳著','宋','宋诗','song-poetry','','[]','一笠出雲深，因緣坐到今。',48,'全唐诗/poet.song.223000.json','["一笠出雲深，因緣坐到今。", "寺窮僧自飯，山古樹方林。", "借酒看人醉，燒香駐客吟。", "相携不覺笑，門外少知心。"]'),
('64ba89a7-7d86-4f4f-8ee2-bd8b30149d96','二月十日送女清出適還次韻弟觀代主留客','陳著','宋','宋诗','song-poetry','','[]','弟胡爲自專，宴客數朝連。',48,'全唐诗/poet.song.223000.json','["弟胡爲自專，宴客數朝連。", "敢越庖中俎，甘安肋上拳。", "滿腔虛醉飽，一段惡姻緣。", "事過姑休問，風流記剡川。"]'),
('9fc6d3e9-f990-4e4e-a0ef-f6d6e1c6d7b0','次韻黄長孺','陳著','宋','宋诗','song-poetry','','[]','山谷忽精神，一番桃李新。',48,'全唐诗/poet.song.223000.json','["山谷忽精神，一番桃李新。", "杯盤留話處，鐙火苟安人。", "老去刻爲歲，醉來寒亦春。", "催歸莫閒管，此處豈天津。"]'),
('cf81c05f-572c-4f95-b01c-329f6b2c4fab','送張子喬之杭','陳著','宋','宋诗','song-poetry','','[]','文旆舞翩翩，西征興浩然。',48,'全唐诗/poet.song.223000.json','["文旆舞翩翩，西征興浩然。", "樹香三井路，花影六橋船。", "酒貴難爲醉，詩清易得傳。", "丈夫須衣錦，寶重黑頭年。"]'),
('5111ba94-8a0e-43a2-b9ab-260b32b4daf8','似天甯寺僧仁澤','陳著','宋','宋诗','song-poetry','','[]','禪窗小有天，一見喜跫然。',48,'全唐诗/poet.song.223000.json','["禪窗小有天，一見喜跫然。", "壁畫詩爲重，簷花菜共妍。", "而翁十暑別，於我百年緣。", "此日相逢此，勝如三笑傳。"]'),
('a12c7148-f917-4517-a7fd-f99386157b30','答天甯寺僧宗芑用前韻來見','陳著','宋','宋诗','song-poetry','','[]','佳月好風天，詩來眼豁然。',48,'全唐诗/poet.song.223000.json','["佳月好風天，詩來眼豁然。", "定心生古韻，淡態洗春妍。", "一面總如舊，五言相結緣。", "尚能茅屋下，賸把巳公傳。"]'),
('48c6991b-fccf-4565-a920-a229657d44de','深兒歸自杭梅山弟有詩因次韻','陳著','宋','宋诗','song-poetry','','[]','兒歸喜欲泣，難說與他人。',48,'全唐诗/poet.song.223000.json','["兒歸喜欲泣，難說與他人。", "老眼無湖海，初心有鬼神。", "行將八十歲，別可又三春。", "自信天堪靠，甯教做獨民。"]'),
('275d5c93-5381-4e52-8a45-457ff78f41a7','新正過沙堤','陳著','宋','宋诗','song-poetry','','[]','朝雨黄鸝靜，春風暗蕊低。',48,'全唐诗/poet.song.223000.json','["朝雨黄鸝靜，春風暗蕊低。", "極知來令節，未肯踏深泥。", "狼藉桃無語，侵尋草滿蹊。", "還聞騎馬客，躑躅向沙堤。"]'),
('cb8f82a3-c9df-4990-b015-0f153cf470d2','至直學士院樊伯撝家','陳著','宋','宋诗','song-poetry','','[]','遠樹晴堪數，孤雲暝欲遮。',48,'全唐诗/poet.song.223000.json','["遠樹晴堪數，孤雲暝欲遮。", "自憐江海迹，能到友生家。", "落日明江色，輕風動麥花。", "相看吾鬢白，不必問年華。"]'),
('431979e8-8129-499c-b126-9841f7cd1bf3','次韻答樊伯撝','陳著','宋','宋诗','song-poetry','','[]','直以傭爲業，何妨睡作魔。',48,'全唐诗/poet.song.223000.json','["直以傭爲業，何妨睡作魔。", "吟詩終日少，飲酒一生多。", "坐久頭鳴籟，行遲脚有鵝。", "林居三十載，一室小維摩。"]'),
('e5e9f738-4292-4896-95bb-aefc22b30595','似仁澤宗芑','陳著','宋','宋诗','song-poetry','','[]','來訪寄窗師，新田雨茗期。',48,'全唐诗/poet.song.223000.json','["來訪寄窗師，新田雨茗期。", "凉生開酒量，香妙醒詩脾。", "半日舊來話，古心他更誰。", "要知夢非夢，試問兩相知。"]'),
('b5d20b7f-cd2a-43da-baf5-e4a628406ccc','答前人用前韻來謝','陳著','宋','宋诗','song-poetry','','[]','莊老是堪師，浮生何日期。',48,'全唐诗/poet.song.223000.json','["莊老是堪師，浮生何日期。", "空將書拄腹，安得藥封脾。", "年事老如我，歲寒交有誰。", "偶然歸不去，又被若人知。"]'),
('747f34e4-9ace-4d20-809f-2a9f12bb5243','與天甯寺主僧雲岫對坐偶成','陳著','宋','宋诗','song-poetry','','[]','瀟瀟風雨裏，得得又開門。',48,'全唐诗/poet.song.223000.json','["瀟瀟風雨裏，得得又開門。", "兩榻蕙蘭壁，半檐花竹邨。", "鳴蛙藏綠暗，歸翼带黄昏。", "此景少人會，相看付不言。"]'),
('3ed0c967-b06f-4c80-8bd4-4d8a7b484041','寄慈溪赭山寺主僧如岳','陳著','宋','宋诗','song-poetry','','[]','薄俗久淪胥，交心獨抱初。',48,'全唐诗/poet.song.223000.json','["薄俗久淪胥，交心獨抱初。", "孤岑千嶂外，兩載幾行書。", "歲晚梅花瘦，江空雁影疏。", "相逢不相見，近況定何如。"]'),
('18f5b72c-36f0-449f-a5d6-3dd14b82b325','次韻達觀弟送法椿長老入杭','陳著','宋','宋诗','song-poetry','','[]','與師交際狎，弟後我居前。',48,'全唐诗/poet.song.223000.json','["與師交際狎，弟後我居前。", "久憩上方閣，忽登西浙船。", "翩然如過鶴，聽不到啼鵑。", "心契無千里，詩盟終有緣。"]'),
('9c3e99ad-5954-45d8-b00b-68c8cc255d44','次韻天甯僧宗芑見寄','陳著','宋','宋诗','song-poetry','','[]','新詩忽相問，知我有如君。',48,'全唐诗/poet.song.223000.json','["新詩忽相問，知我有如君。", "陶令早還里，少游終守墳。", "犂鋤聊自課，筆硯未全焚。", "時放出門步，仰天看過雲。"]'),
('f3ffeaa1-3562-4e1c-bf3f-7f232dacbb97','到白水有感','陳著','宋','宋诗','song-poetry','','[]','吾氣已衰颯，茲行增慘悽。',48,'全唐诗/poet.song.223000.json','["吾氣已衰颯，茲行增慘悽。", "近山雲易雨，積水路如溪。", "寒食紙錢樹，舊遊莎草畦。", "頹牆獨立久，百感付鵑啼。"]'),
('e8387461-94ae-488c-aeb8-a9426c0fc03a','見童志道舊居已非有感','陳著','宋','宋诗','song-poetry','','[]','人亡屋亦非，世事已堪悲。',48,'全唐诗/poet.song.223000.json','["人亡屋亦非，世事已堪悲。", "遺樹老於我，故山春爲誰。", "論文歸一夢，閉眼立多時。", "默默無言處，東風知不知。"]'),
('7ac50e15-d725-44f2-87cd-79e7054e02df','次韻仁澤僧來見','陳著','宋','宋诗','song-poetry','','[]','嵩溪修竹下，一榻坐幽深。',48,'全唐诗/poet.song.223000.json','["嵩溪修竹下，一榻坐幽深。", "時異交遊少，年衰百病侵。", "生涯成鳥啄，邨景付猨吟。", "惟有相從夢，時時到梵林。"]'),
('40f63816-a655-4419-ad3d-58251e56b1af','次韻張子喬來見','陳著','宋','宋诗','song-poetry','','[]','人生自多事，本是一蘧廬。',48,'全唐诗/poet.song.223000.json','["人生自多事，本是一蘧廬。", "忽忽夢柯外，纍纍炊劍餘。", "清吟投病枕，細讀當醫書。", "此去更何日，相過話索居。"]'),
('f8922599-228a-4396-9306-abba972af72c','日峰菴','陳著','宋','宋诗','song-poetry','','[]','便道得幽尋，清風引入深。',48,'全唐诗/poet.song.223000.json','["便道得幽尋，清風引入深。", "菴依山石脚，僧說老巖心。", "到處鬼無墓，此山松獨林。", "人生竟何事，搔首立青陰。"]'),
('4a1f215d-7d01-4169-ad48-6dd7ab62276d','寄婺州石君瑞料院','陳著','宋','宋诗','song-poetry','','[]','靈光猶巋然，別久忽書傳。',48,'全唐诗/poet.song.223000.json','["靈光猶巋然，別久忽書傳。", "風雨各閉戶，山林多謝天。", "眼花千里外，心事十年前。", "獨爲兒曹喜，通家契有緣。"]'),
('d9b71eff-87c5-4fe8-ada4-dca3a52a3e74','同離孫童蒙遊浄慈','陳著','宋','宋诗','song-poetry','','[]','三月第三日，又來遊梵林。',48,'全唐诗/poet.song.223000.json','["三月第三日，又來遊梵林。", "醉言驚俗耳，貧趣契僧心。", "犬吠落紅外，鳥啼空翠陰。", "一年最佳處，分付老齡吟。"]'),
('6b741f8b-0151-4245-b5b0-92a99569eb17','次韻胡甥幼文留別','陳著','宋','宋诗','song-poetry','','[]','壻車俄見過，喜氣動庭莎。',48,'全唐诗/poet.song.223000.json','["壻車俄見過，喜氣動庭莎。", "別久一來重，病餘相問多。", "親情忘淡薄，歸興及清和。", "山路須囘首，長松有翠蘿。"]'),
('9fb0a92e-babf-46b2-9b2c-456d8eb62fdf','送春酒邊','陳著','宋','宋诗','song-poetry','','[]','今朝天氣新，聚首見情真。',48,'全唐诗/poet.song.223000.json','["今朝天氣新，聚首見情真。", "園木相看古，池魚亦詠春。", "山林如此酒，宇宙幾何人。", "堪笑塵埃世，興懷石季倫。"]'),
('d13f6814-7328-499f-bf9b-456277921486','余自邑歸唐溪袁仲素兄弟拉歸宿次日苦留連偶病以八句辭','陳著','宋','宋诗','song-poetry','','[]','家世厭風波，來居空翠窩。',48,'全唐诗/poet.song.223000.json','["家世厭風波，來居空翠窩。", "山深秋意早，溪近夜聲多。", "似夢忽到此，欲留如病何。", "眼前渾是趣，未得細吟哦。"]'),
('0b3aad36-a8ef-4a87-8e70-0bf99760beac','到梅山次韻弟茝  其一','陳著','宋','宋诗','song-poetry','','[]','山家見禿翁，歡笑走兒童。',48,'全唐诗/poet.song.223000.json','["山家見禿翁，歡笑走兒童。", "坡竹勢飛動，楚蘭香暗通。", "盍分半席地，相扇一瓢風。", "世事非吾分，何妨詩自雄。"]'),
('be7bf954-a534-4c6e-aabf-9646a2a87d11','到梅山次韻弟茝  其二','陳著','宋','宋诗','song-poetry','','[]','相對兩衰翁，此心無復童。',48,'全唐诗/poet.song.223000.json','["相對兩衰翁，此心無復童。", "幸叨無事坐，貧欠有錢通。", "菜粥琴書畫，梅花雪月風。", "黄塵在門外，勞隠是英雄。"]'),
('06dd71d3-3c35-4d49-9a4e-9a585eb3db56','梅山醉後過丹山','陳著','宋','宋诗','song-poetry','','[]','醉揖梅花塢，意行來佛廬。',48,'全唐诗/poet.song.223000.json','["醉揖梅花塢，意行來佛廬。", "相看如夜夢，一別又年餘。", "話到供無粥，笑言園有蔬。", "杯茶出山去，拍手謝鐘魚。"]'),
('fe0664b1-4dc4-43f1-a6f8-821bfce63ae4','次前韻示弟茝','陳著','宋','宋诗','song-poetry','','[]','梅老竹疏疏，先人有敝廬。',48,'全唐诗/poet.song.223000.json','["梅老竹疏疏，先人有敝廬。", "偷生俄八十，課子尚三餘。", "脚軟安憑杖，牙衰爛煮蔬。", "天猶嫌過分，時復病河魚。"]'),
('8f849a2f-eda1-4ea0-b89a-46317726514a','次韻王得淦長至','陳著','宋','宋诗','song-poetry','','[]','二十四節氣，來自混元前。',48,'全唐诗/poet.song.223000.json','["二十四節氣，來自混元前。", "老息他無分，新陽例有緣。", "從教寒又暑，慣得海爲田。", "此理須看破，何妨日當年。"]'),
('53b8d9ab-2f30-4f1a-915e-3062387735e1','正月二十四日到梅山二首  其一','陳著','宋','宋诗','song-poetry','','[]','困來禁不住，一動亦悠然。',48,'全唐诗/poet.song.223000.json','["困來禁不住，一動亦悠然。", "家事青山外，春心白髮前。", "逢人相問歲，爲客又開年。", "得醉梅花下，何妨就石眠。"]'),
('5909bc36-708d-45b7-bae2-256f92a3bf8c','正月二十四日到梅山二首  其二','陳著','宋','宋诗','song-poetry','','[]','梅花草屋邊，好景得天然。',48,'全唐诗/poet.song.223000.json','["梅花草屋邊，好景得天然。", "夢境閒爲上，歸途倦莫前。", "無情推醉石，有分是流年。", "已約重來日，白雲留醉眠。"]'),
('a1528573-80f1-496c-b8bb-9a2f00025af9','正月晦日與弟觀對酌','陳著','宋','宋诗','song-poetry','','[]','聚散等風沙，相知要當家。',48,'全唐诗/poet.song.223000.json','["聚散等風沙，相知要當家。", "弟兄窗下酒，世俗眼前花。", "隠去方爲福，貧驅未有涯。", "明朝吉凶事，分付與昏鴉。"]'),
('36a6a6e2-3fb6-4d6e-9246-cdca35019b84','四月三日與家人小酌轉官毬花因成八句略爲花吐氣也','陳著','宋','宋诗','song-poetry','','[]','紅芳銷歇後，天質最分明。',48,'全唐诗/poet.song.223000.json','["紅芳銷歇後，天質最分明。", "剪襯青雲薄，團成白雪輕。", "官途榮進取，時樣妄推評。", "本色相看處，幽窗不世情。"]'),
('5d48f319-06d2-4fb1-8c5e-f01707b4d852','次韻雪竇主同少野見寄','陳著','宋','宋诗','song-poetry','','[]','誰肯寄衰翁，當年應夢熊。',48,'全唐诗/poet.song.223000.json','["誰肯寄衰翁，當年應夢熊。", "知心厪惠遠，載酒壽揚雄。", "古道今猶在，清交老更豐。", "和詩不盡意，極目萬山中。"]'),
('e965d193-7ffc-494b-b1db-f15975c5089e','次韻洛陽秦慶父贄見','陳著','宋','宋诗','song-poetry','','[]','洛中人物好，磊磊實過名。',48,'全唐诗/poet.song.223000.json','["洛中人物好，磊磊實過名。", "和氣春浮動，新詩玉琢成。", "相逢交義重，一笑世情輕。", "問到牡丹外，淒然百感生。"]'),
('799bdd17-b20f-432a-aca1-e6e8a3d12190','示王侑翁二首  其一','陳著','宋','宋诗','song-poetry','','[]','垂髫已解吟，髣髴學何陰。',48,'全唐诗/poet.song.223000.json','["垂髫已解吟，髣髴學何陰。", "暗動梅窗喜，遥傳桂種心。", "染聲毋市井，近拙要山林。", "耄矣不成句，中閒意自深。"]'),
('2186c09b-ea73-4733-a06f-2700002ec0fb','示王侑翁二首  其二','陳著','宋','宋诗','song-poetry','','[]','碩果生機在，從他剝五陰。',48,'全唐诗/poet.song.223000.json','["碩果生機在，從他剝五陰。", "南山四時面，殘屋百年心。", "家薄有書種，客多成笑林。", "要閒元自老，不在卜居深。"]'),
('8b1fe91a-f8e7-4e91-88a2-0a535228e8e9','到西山懷趙景文似諸孤','陳著','宋','宋诗','song-poetry','','[]','山屋著孤嫠，采薇人更誰。',48,'全唐诗/poet.song.223000.json','["山屋著孤嫠，采薇人更誰。", "寒鐙長夜影，春帖去年詩。", "後死祇多感，獨來能幾時。", "願言相勸學，西席佇賢師。"]'),
('a83b7c3b-8a05-46e8-b44b-94f3665c4f0e','次韻林芳叔夜雨立春二首  其一','陳著','宋','宋诗','song-poetry','','[]','今春第一雨，颯颯打窗紗。',48,'全唐诗/poet.song.223000.json','["今春第一雨，颯颯打窗紗。", "莫怪妨鐙節，惟憂釀雪花。", "報晴俄喜鵲，吠早底嫌蛙。", "不自知年耄，隨人樂歲華。"]'),
('4d2c94a7-963a-4438-9c24-c9ff6a207958','次韻林芳叔夜雨立春二首  其二','陳著','宋','宋诗','song-poetry','','[]','官府年頭事，山中知未知。',48,'全唐诗/poet.song.223000.json','["官府年頭事，山中知未知。", "更新夏正朔，依舊漢威儀。", "病脚春扶起，歸心雨壓遲。", "東家未吾厭，飽飯細論詩。"]'),
('7795fc6e-5f9c-4ae8-b9c0-91d50c8df348','次韻林國器元夕','陳著','宋','宋诗','song-poetry','','[]','世情多異好，幻出滿城星。',48,'全唐诗/poet.song.223000.json','["世情多異好，幻出滿城星。", "塵市月無色，醉鄉風亦腥。", "從他兒戲哄，輸我客眠醒。", "老耳虛鳴處，笙歌足自聽。"]'),
('1c4c467c-74cb-4a7c-8478-9c443b8aa1ba','次韻樊伯撝見貺','陳著','宋','宋诗','song-poetry','','[]','自笑我何如，叨年八十餘。',48,'全唐诗/poet.song.223000.json','["自笑我何如，叨年八十餘。", "戶門覺老病，梅竹護窮居。", "拙計信天鳥，殘生減水魚。", "時將一字命，仰卧向空書。"]'),
('7c9ef22d-cbc9-4067-b573-6d2d34669be5','次韻王得淦和兒泌西山所作二首  其一','陳著','宋','宋诗','song-poetry','','[]','門徑不爲深，溪山巧带襟。',48,'全唐诗/poet.song.223000.json','["門徑不爲深，溪山巧带襟。", "老來無過計，貧極見初心。", "兒漫煮饑字，甥能賡醉吟。", "不羞狂脫帽，無髮可勝簪。"]'),
('99c40925-7c65-4ed4-812d-764116aff6e6','次韻王得淦和兒泌西山所作二首  其二','陳著','宋','宋诗','song-poetry','','[]','親戚要綢繆，其來遠有由。',48,'全唐诗/poet.song.223000.json','["親戚要綢繆，其來遠有由。", "溪山行可到，歲月去難留。", "休問酒無有，但將詩應酬。", "春光是堪處，不是少年遊。"]'),
('79c607f1-a9af-44df-bb6f-dbdbbb7664c2','次韻王監叔二首  其一','陳著','宋','宋诗','song-poetry','','[]','青山綠水鄉，竹裏喜還堂。',48,'全唐诗/poet.song.223000.json','["青山綠水鄉，竹裏喜還堂。", "犬竇可曾警，雀羅何用張。", "苦詩誰是甫，問字我非揚。", "有感飛霞佩，相從老不忘。"]'),
('00afc0f3-14a4-4630-abce-bd27b418250b','次韻王監叔二首  其二','陳著','宋','宋诗','song-poetry','','[]','古道在山林，還從冷處尋。',48,'全唐诗/poet.song.223000.json','["古道在山林，還從冷處尋。", "醉時詩落紙，夢裏鶴隨琴。", "歲月悠悠外，乾坤浩浩心。", "何妨且留住，風雨是知音。"]'),
('66571445-5f60-4f2b-9e3a-171c2d71b46b','四月五日後圃酴醿芍藥侍郎三花盛開醉中成三詠  其一','陳著','宋','宋诗','song-poetry','','[]','酴醿忽盡花，春與夏交加。',48,'全唐诗/poet.song.223000.json','["酴醿忽盡花，春與夏交加。", "頃刻當千日，風流能幾家。", "香叢迷粉蝶，曲蔓走青蛇。", "火急要清賞，可人歸未邪。"]'),
('cdfc63b6-7e0c-4aa0-85a4-bd3f8d932d86','四月五日後圃酴醿芍藥侍郎三花盛開醉中成三詠  其二','陳著','宋','宋诗','song-poetry','','[]','芍藥又將開，那堪夜雨催。',48,'全唐诗/poet.song.223000.json','["芍藥又將開，那堪夜雨催。", "密鋪萱草襯，巧傍牡丹栽。", "省砌休思著，揚州曾看來。", "芳菲概如許，俯仰亦悠哉。"]'),
('716b5396-69df-4102-aa92-25e5610b83f6','四月五日後圃酴醿芍藥侍郎三花盛開醉中成三詠  其三','陳著','宋','宋诗','song-poetry','','[]','芍藥圃中央，有花名侍郎。',48,'全唐诗/poet.song.223000.json','["芍藥圃中央，有花名侍郎。", "叢叢嬌翠羽，朵朵淡紅妝。", "鳳閣樣如夢，雞冠班自行。", "何如付一醉，歲歲有春光。"]'),
('d90a06f8-344f-439c-9bba-14028cd5514d','次韻孫與之見寄','陳著','宋','宋诗','song-poetry','','[]','江山百里餘，相得肯相疏。',48,'全唐诗/poet.song.223000.json','["江山百里餘，相得肯相疏。", "寄雁苦無便，遺魚俄有書。", "心能謙以下，義得兌之初。", "耐久難忘處，我將銘陋居。"]'),
('6be2f175-1774-4f51-9ee5-4203182a1b34','次韻泌雨後','陳著','宋','宋诗','song-poetry','','[]','秋來苦淫雨，轉見我衰殘。',48,'全唐诗/poet.song.223000.json','["秋來苦淫雨，轉見我衰殘。", "餘息朝陽露，危生風浪灘。", "病深多夢藥，凉早入披禪。", "萬事有天在，隨時且放寬。"]'),
('b64109be-a6bd-4995-a420-4b0479849620','送嚴心傳鄞縣學教任滿','陳著','宋','宋诗','song-poetry','','[]','賢哉昔魯山，心地出芝蘭。',48,'全唐诗/poet.song.223000.json','["賢哉昔魯山，心地出芝蘭。", "不負義方教，相傳本色官。", "三年脚根正，萬里路頭寬。", "須信功名事，要教人耐看。"]'),
('44ad847c-94b2-4edf-ab9b-d5b3f5050f7e','次韻東平趙孟益遊北山寺','陳著','宋','宋诗','song-poetry','','[]','瀟灑一僧關，錢家古墓山。',48,'全唐诗/poet.song.223000.json','["瀟灑一僧關，錢家古墓山。", "雲多迷早晚，溪闊限忙閒。", "齋鼓青龍麓，漁歌白鷺灣。", "欲吟吟不盡，巖溜自潺潺。"]'),
('1dad9487-4aa6-4ac4-88b8-ede1153e47da','次韻遊南山寺','陳著','宋','宋诗','song-poetry','','[]','紫蓋矗天開，更無山並來。',48,'全唐诗/poet.song.223000.json','["紫蓋矗天開，更無山並來。", "脚飛雲外去，眼到海東囘。", "長嘯落林葉，新題淋壁苔。", "茲遊亦奇絕，休惜醉徘徊。"]'),
('9efc2e8c-9699-420f-bfbd-466fba1428a5','次王得淦韻','陳著','宋','宋诗','song-poetry','','[]','浴出矮檐陰，披襟小雨侵。',48,'全唐诗/poet.song.223000.json','["浴出矮檐陰，披襟小雨侵。", "坐凉三鼓漏，和夢一鐙吟。", "自分死中活，誰知升與沈。", "明朝書局事，奔走豈初心。"]'),
('202e1f02-a0ec-47ba-a41b-abfe1f3f4366','遊北苑寺似主僧漢仲章','陳著','宋','宋诗','song-poetry','','[]','隨人入寶坊，一坐到斜陽。',48,'全唐诗/poet.song.223000.json','["隨人入寶坊，一坐到斜陽。", "僧老話多古，春來山自香。", "放吟聊走筆，乘興不論觴。", "今日是何日，悠然何有鄉。"]'),
('d1ca8af8-2c7c-49d4-af17-dc203cdc4e62','謝前人','陳著','宋','宋诗','song-poetry','','[]','意行非夙盟，一見眼雙青。',48,'全唐诗/poet.song.223000.json','["意行非夙盟，一見眼雙青。", "款接生如熟，高談醉易醒。", "夜牀清老夢，晨粥洗餘腥。", "須踐楊梅約，重來水月亭。"]'),
('afb95210-5710-4b15-83ea-d0d58abe16a7','送邑宰丁溉解任置酒取別因賦示','陳著','宋','宋诗','song-poetry','','[]','古道轉悠悠，送君那值秋。',48,'全唐诗/poet.song.223000.json','["古道轉悠悠，送君那值秋。", "惡懷醒似醉，苦語去難留。", "鐙雨今宵酒，帆風明日舟。", "從今夢相見，老眼在心頭。"]'),
('7672cb9e-189b-4f5c-a206-cbb8c630751e','送蘇松軒路教解任','陳著','宋','宋诗','song-poetry','','[]','三載多材地，一團和氣鄉。',48,'全唐诗/poet.song.223000.json','["三載多材地，一團和氣鄉。", "蛙池疏道脈，蓬島矗文芒。", "明日歸舟穩，春風驛路長。", "詞林是氈舊，此去足翱翔。"]'),
('a8203eda-6e54-47e7-b396-3e14d31122d2','到西峰寺見弟蒙所與僧屋詩因次韻','陳著','宋','宋诗','song-poetry','','[]','檄便入雲山，相逢話晚年。',48,'全唐诗/poet.song.223000.json','["檄便入雲山，相逢話晚年。", "慣吟茅屋下，時打葛藤前。", "應世未圓覺，無人識聖顛。", "滔滔兒女境，猶抱穎師弦。"]'),
('377068f0-9f0d-4f29-90c2-efcf29bfe48b','到香山寺似僧能子良','陳著','宋','宋诗','song-poetry','','[]','當年真應老，坐斷此名邱。',48,'全唐诗/poet.song.223000.json','["當年真應老，坐斷此名邱。", "交障鎖山定，曲溪依路流。", "聳肩擎佛迹，分脚踏龍頭。", "形勝不可盡，平生償一遊。"]'),
('db69df5e-aea1-4a7c-9bab-3d082e1af008','似雪竇西麓菴僧昂蒙純','陳著','宋','宋诗','song-poetry','','[]','□□□□□，□□□□□。',48,'全唐诗/poet.song.223000.json','["□□□□□，□□□□□。", "詩話半窗日，禪機萬竹風。", "悠然相契處，付與不言中。", "長揖出門去，水流雲外空。"]'),
('75d0127c-d248-4ee5-a911-60b5064d51cc','次韻洞真道士盧致遠','陳著','宋','宋诗','song-poetry','','[]','虹橋關福地，門外任風濤。',48,'全唐诗/poet.song.223000.json','["虹橋關福地，門外任風濤。", "襟带金鐘秀，根基鐵柱牢。", "安心培大棗，辦手摘蟠桃。", "坐鎮江山穩，新題立石高。"]'),
('d0874007-5c65-4d75-a506-8495f279d127','似法椿齡叟','陳著','宋','宋诗','song-poetry','','[]','人生契合處，信是宿因緣。',48,'全唐诗/poet.song.223000.json','["人生契合處，信是宿因緣。", "坐到無言外，參成有佛前。", "好山非昨日，啼鳥又今年。", "带得醉歸去，醒時風滿天。"]'),
('6c496a0c-fc67-4bc2-9fb6-e2b7ae631d6e','次韻東皋寺主僧知恭見寄','陳著','宋','宋诗','song-poetry','','[]','平地起叢林，工夫歲月深。',48,'全唐诗/poet.song.223000.json','["平地起叢林，工夫歲月深。", "百吟三教髓，一飯十方心。", "慣聽人傳說，閒將夢去尋。", "書來足自慰，亦是老知音。"]'),
('9cfc780f-5321-412f-ad57-d80bca3ef599','次韻弟觀留慈雲','陳著','宋','宋诗','song-poetry','','[]','相携入翠林，聊爾豁塵襟。',48,'全唐诗/poet.song.223000.json','["相携入翠林，聊爾豁塵襟。", "恃熟出家話，得閒生梵心。", "凉多却扇坐，困倦把詩吟。", "試問虎溪上，多情如此深。"]'),
('19b8909e-e8c7-4bd1-8695-d0dc6b4591d4','萬壽寺主僧圓鑑留酒醉中','陳著','宋','宋诗','song-poetry','','[]','人世一漚浮，時光如瞬流。',48,'全唐诗/poet.song.223000.json','["人世一漚浮，時光如瞬流。", "相違十年久，偶見兩心稠。", "法嗣驚初意，香厨出異羞。", "那知年到此，不枉少遲留。"]'),
('6d7bec97-2457-45b3-bcb6-029dd5177bdc','聞樊桂卿初歸自鏡湖寄之','陳著','宋','宋诗','song-poetry','','[]','短世淵明醉，長愁子美歌。',48,'全唐诗/poet.song.223000.json','["短世淵明醉，長愁子美歌。", "高情誰復爾，久別公如何。", "淡月初出浦，好風來颺蓑。", "買田滄海上，耕亦不須多。"]'),
('00958b50-3176-4c81-8299-a6132f3d23c6','次韻留友直道士來訪','陳著','宋','宋诗','song-poetry','','[]','九六盪摩中，幾人閒處同。',48,'全唐诗/poet.song.223000.json','["九六盪摩中，幾人閒處同。", "浮生絲傀儡，後計石婆翁。", "事事休休過，時時咄咄空。", "何如仙羽健，來往傲方蓬。"]'),
('f9cadca6-a570-4abb-ade2-36a468b08485','遊鹿頂山','陳著','宋','宋诗','song-poetry','','[]','茲菴擅佳境，一到願方償。',48,'全唐诗/poet.song.223000.json','["茲菴擅佳境，一到願方償。", "鐘鼓江湖笠，琴棋水竹房。", "相逢多故舊，小憩得清凉。", "自笑因緣淺，又催行路忙。"]'),
('7ee55713-749a-4684-a145-05776b62d441','次韻僧仁澤  其一','陳著','宋','宋诗','song-poetry','','[]','來詩自有師，心與晚唐期。',48,'全唐诗/poet.song.223000.json','["來詩自有師，心與晚唐期。", "開我正牆面，喜於聞樂脾。", "山林人似許，風月事還誰。", "不用盟爲社，從今是故知。"]'),
('15850fcb-a1e5-4386-94ea-d408c5a2415d','次韻僧仁澤  其二','陳著','宋','宋诗','song-poetry','','[]','灑灑忘家客，相逢若有期。',48,'全唐诗/poet.song.223000.json','["灑灑忘家客，相逢若有期。", "茶腴參道味，詩瘦出饑脾。", "避俗無新計，談空更阿誰。", "吾言太浪蕩，休遣世人知。"]'),
('316a746e-03d1-483f-9918-9b1c544855fb','次韻僧仁澤  其三','陳著','宋','宋诗','song-poetry','','[]','來遊大梵天，邂逅興悠然。',48,'全唐诗/poet.song.223000.json','["來遊大梵天，邂逅興悠然。", "一見新猶故，相忘醜亦妍。", "藕花詩有句，蓮社我無緣。", "不必參禪話，詩鐙自可傳。"]'),
('9bc458a9-2a1f-4834-9f40-90064202290b','樊學士送菊次韻答之','陳著','宋','宋诗','song-poetry','','[]','黄菊有名花，淵明無酒官。',48,'全唐诗/poet.song.223000.json','["黄菊有名花，淵明無酒官。", "酒多人自醉，花好月同看。", "老未厭人世，天教共歲寒。", "未應携不去，高步蓬萊山。"]'),
('66a91ee1-6b07-4b3c-b8a1-bdab3ee095d7','次韻孫古巖冬景','陳著','宋','宋诗','song-poetry','','[]','臘天風景最無常，兒造顛狂亦有方。',64,'全唐诗/poet.song.223000.json','["臘天風景最無常，兒造顛狂亦有方。", "將放雪飛連夜雨，欲留晴住一朝霜。", "城頭柳色吟邊動，山曲梅花夢裏香。", "身在黄塵三尺外，靜中無日不春光。"]'),
('de93e85d-2b5a-4af3-ae8f-1cfd18f13740','次韻單景山酴醿','陳著','宋','宋诗','song-poetry','','[]','東風先遣百花開，坐後妝梳殢鏡臺。',64,'全唐诗/poet.song.223000.json','["東風先遣百花開，坐後妝梳殢鏡臺。", "雪豔慣逢風落絮，雲香不到雨成梅。", "下交芍藥當階發，高伴金沙上架來。", "珍重美人收拾去，春衣芬馥雅持杯。"]'),
('38aeb7c6-4dd4-435f-9395-060a4ba41cd2','浦城外界梨嶺西水碓頭阻雪三日','陳著','宋','宋诗','song-poetry','','[]','小小籃輿出遠林，南來長苦路崎嶔。',64,'全唐诗/poet.song.223000.json','["小小籃輿出遠林，南來長苦路崎嶔。", "一千里外鄉山杳，十二月中風雪深。", "清夜到家惟有夢，少年觸事易酸心。", "須知行止元非我，陰六陽三古到今。"]'),
('c309f62d-f2fb-4e02-bdd6-bd1bd3b04bc0','定海','陳著','宋','宋诗','song-poetry','','[]','一夜南風便葉舟，天教償我定川遊。',64,'全唐诗/poet.song.223000.json','["一夜南風便葉舟，天教償我定川遊。", "兩崖踞海潮吞脚，萬石封堤水掉頭。", "家家活計魚蝦市，處處歡聲鼓笛樓。", "不用丹青狀風景，逢人且說小杭州。"]'),
('9c7cc4b4-7eb6-4b05-8563-ec884dcfa91d','宿靈石方丈','陳著','宋','宋诗','song-poetry','','[]','偶因塵隙遊靈石，不覺夷猶到夜深。',64,'全唐诗/poet.song.223000.json','["偶因塵隙遊靈石，不覺夷猶到夜深。", "坐對半窗山月影，參成一片白雲心。", "寒螿著露更相調，老葉無風也自吟。", "分得僧牀伴僧夢，夢闌詩料滿山林。"]'),
('86924f73-3986-4d60-ae56-3a026918c6e8','謝童志道書','陳著','宋','宋诗','song-poetry','','[]','相逢一歲一開懷，不奈怱怱兩望賒。',64,'全唐诗/poet.song.223000.json','["相逢一歲一開懷，不奈怱怱兩望賒。", "緘口已生愁裏棘，共鐙空結夢中花。", "芳林丹桂君須折，厄閏黄楊我自嗟。", "猶喜鄮峯雲一葉，故教風裏到天涯。"]'),
('1f238649-debf-46ca-9f22-177604bb8f65','夢中得詩二句王景雲聞之擬成八句來因次韻','陳著','宋','宋诗','song-poetry','','[]','浮生誰不愛名成，未到頭時未是名。',64,'全唐诗/poet.song.223000.json','["浮生誰不愛名成，未到頭時未是名。", "不意事多人易老，知音者少路難行。", "清閒信是終身福，得失須教一念輕。", "林下有家歸有日，離騷聲裏聽猨聲。"]'),
('c1f8533b-f936-4da6-8255-a8b89e158bb7','回家','陳著','宋','宋诗','song-poetry','','[]','爲嫌客悶轉還鄉，到得還鄉夢轉長。',64,'全唐诗/poet.song.223000.json','["爲嫌客悶轉還鄉，到得還鄉夢轉長。", "密友會疏心欲折，貧家事富擔難當。", "秋山有態忻新雨，風葉無名怨夕陽。", "此景勸君評洎取，免教詩社報淒涼。"]'),
('7bb9f090-1749-4e87-ad88-d44aa88d7a44','張氏館中早作','陳著','宋','宋诗','song-poetry','','[]','小窗一榻清於水，親戚相看話久暌。',64,'全唐诗/poet.song.223000.json','["小窗一榻清於水，親戚相看話久暌。", "困带詩情投角枕，夢隨梅伴策霜藜。", "鄰家落杵催樵爨，山寺分鐘撼竹棲。", "犯冷披衣捲簾立，小丹山在翠樓西。"]'),
('8f6fe81f-2b85-4f13-b3e4-0323f5d6ef0a','病起','陳著','宋','宋诗','song-poetry','','[]','西風喚起眼中仙，竹榻饒涼不愛眠。',64,'全唐诗/poet.song.223000.json','["西風喚起眼中仙，竹榻饒涼不愛眠。", "數樹秋聲窗著雨，一簾山影屋浮煙。", "案頭古帖無完紙，壁上焦琴不具絃。", "小摘畦蔬炊脫粟，與妻閒話孟光賢。"]'),
('bae39095-452a-450f-baf4-7507da9863db','次前韻謝月窗兄見和','陳著','宋','宋诗','song-poetry','','[]','人得清閒便是仙，秋光堪畫欠龍眠。',64,'全唐诗/poet.song.223000.json','["人得清閒便是仙，秋光堪畫欠龍眠。", "瀉檐纔歇催詩雨，入戶驚飛落紙煙。", "句與杜陵同中律，世無鍾子莫知絃。", "籟鳴機動聊相友，捧硯猶强武士賢。"]'),
('5020878f-deda-4e17-bbed-07341c36dfe7','次韻竹窗兄委順齋','陳著','宋','宋诗','song-poetry','','[]','知君委順是心銘，揭以名齋豈浪名。',64,'全唐诗/poet.song.223000.json','["知君委順是心銘，揭以名齋豈浪名。", "夜兔晨烏真似夢，秋蟲春鳥不關情。", "人生未死終歸困，天道從來不益盈。", "我亦當今知命者，請於此處話平生。"]'),
('c94e5ce3-0e90-4f25-b6b5-1fde6863634b','竹窗兄因貓捕雞日囚夜縱有詩自憐因次韻','陳著','宋','宋诗','song-poetry','','[]','坎止流行不在人，人生只合任天真。',64,'全唐诗/poet.song.223000.json','["坎止流行不在人，人生只合任天真。", "無聊句踐能興越，垂死范雎終相秦。", "病足不妨登上衮，顰眉休復效東鄰。", "竹窗悟得窮通理，雖致狸奴許自新。"]'),
('11337fdc-1d6b-4cd1-859b-4adafdb258fb','孟春書懷','陳著','宋','宋诗','song-poetry','','[]','老健羲娥不住車，東君依樣做年華。',64,'全唐诗/poet.song.223000.json','["老健羲娥不住車，東君依樣做年華。", "十來日雨洗梅萼，一半春風歸杏花。", "醉裏出門忘故我，閒心到處是吾家。", "臨溪忽悟前程事，流水方生未到涯。"]'),
('b93e895d-2ef9-4b37-8145-4dfb8f782b07','趙氏樓偶成','陳著','宋','宋诗','song-poetry','','[]','過耳南宮捷奏鈴，功名宿夢頓呼醒。',64,'全唐诗/poet.song.223000.json','["過耳南宮捷奏鈴，功名宿夢頓呼醒。", "清風席上龜占古，細雨樓頭鵲語靈。", "袖裏瓌文珍白璧，眼中霜穎銳青萍。", "問津當繼宣和躅，要得人言更妙齡。"]'),
('6dad88d3-c6aa-4e16-96f8-5c520c563e7a','次前韻謝同樓諸公','陳著','宋','宋诗','song-poetry','','[]','凝香畫閣晝聞鈴，喚我真心十倍醒。',64,'全唐诗/poet.song.223000.json','["凝香畫閣晝聞鈴，喚我真心十倍醒。", "奮臂勇尋西學侶，囘頭挹謝北山靈。", "京華是則薪炊桂，旅食何妨實剖萍。", "此去功名如到手，也須伏闕疏延齡。"]'),
('fc6e2447-f059-44e4-bd19-03d3123b58cd','入京到西渡','陳著','宋','宋诗','song-poetry','','[]','昨宵北渡今西渡，繫是離家第二宵。',64,'全唐诗/poet.song.223000.json','["昨宵北渡今西渡，繫是離家第二宵。", "詩伴風流勤犯驛，櫂郎醉飽健迎潮。", "丈亭浦上鄰州接，筆架峯迷故里遥。", "得意歸來期可數，榴花如火照高標。"]'),
('08b403d0-8475-47b6-b613-25dce668d79c','吳宜之生日以一詩勉之','陳著','宋','宋诗','song-poetry','','[]','伍山鍾秀出人龍，頭角崢嶸意氣雄。',64,'全唐诗/poet.song.223000.json','["伍山鍾秀出人龍，頭角崢嶸意氣雄。", "須著父兄深責望，好從師友細磨礱。", "始勤却是終身福，下學方收上達功。", "它日前程相約處，杏園多少馬頭風。"]'),
('00544f17-216c-4c6b-b6d4-be0391f1ee6d','遊西湖','陳著','宋','宋诗','song-poetry','','["\u897f\u6e56"]','多謝東君巧剸裁，工夫都在禁城西。',64,'全唐诗/poet.song.223000.json','["多謝東君巧剸裁，工夫都在禁城西。", "松蘿霽藹羣峯寺，楊柳輕風十里堤。", "酒向畫闌樓上買，詩從翠館壁中題。", "都門路迥馬蹄困，奔得歸來醉似泥。"]'),
('2b7faaa8-b574-42d9-ba6a-d4fff04f8c66','過鑑湖','陳著','宋','宋诗','song-poetry','','[]','越城勝境素來誇，纔入東關分外嘉。',64,'全唐诗/poet.song.223000.json','["越城勝境素來誇，纔入東關分外嘉。", "八百頃荷西子態，幾千餘寺賀君家。", "畫屏山色饒煙水，麗錦天光落晚霞。", "惜景欲圖湖上住，釣船泊處是生涯。"]'),
('571299cf-c5fd-4504-a935-65642d4cf683','次韻劉生秋夜郊行','陳著','宋','宋诗','song-poetry','','[]','護索郊行秋夜秒，無心萬籟自悲鳴。',64,'全唐诗/poet.song.223000.json','["護索郊行秋夜秒，無心萬籟自悲鳴。", "月林散葉風前下，村舍孤鐙夜半明。", "暗裏家山應在望，醉中砧杵不關情。", "歸來東榻鴛衾穩，應笑詞人怨五更。"]'),
('c0cddb23-e20c-4561-8c4d-961b2c5acd70','題西四明趙氏書院','陳著','宋','宋诗','song-poetry','','[]','他鄉久客不堪懷，風雨書窗又獨來。',64,'全唐诗/poet.song.223000.json','["他鄉久客不堪懷，風雨書窗又獨來。", "夢惡喜聞鶑喚醒，歸途羞見雁聲囘。", "望春山色今須好，年少時光老易催。", "坎止流行天已定，掀髯一笑且銜杯。"]'),
('f9387da6-cd44-4c67-8687-f5bd00ca7c66','首夏','陳著','宋','宋诗','song-poetry','','[]','花塵絮雪已茫茫，一景清和便可量。',64,'全唐诗/poet.song.223000.json','["花塵絮雪已茫茫，一景清和便可量。", "脅霽驚風眠秀麥，尾雲疏雨健新秧。", "鶑啼未怯隨春去，犬吠相催入夜長。", "酒興詩情都懶散，祇將清夢試藜牀。"]'),
('decbc8d3-83ee-4059-9eda-afc131421e71','春殘','陳著','宋','宋诗','song-poetry','','[]','出門隨意踏蒼苔，過眼時光一笑陪。',64,'全唐诗/poet.song.223000.json','["出門隨意踏蒼苔，過眼時光一笑陪。", "二十四風清繡地，兩三點雨試輕雷。", "纈空舞絮隨春去，鈿水嬌荷闖夏開。", "對景傷心兒女事，剛腸無奈祇銜杯。"]'),
('7da82661-b889-4c13-b16d-9dad0d02931b','乙卯鄉貢鹿鳴宴次韻','陳著','宋','宋诗','song-poetry','','[]','結髮書癡氣吸川，壯年纔得預賓筵。',64,'全唐诗/poet.song.223000.json','["結髮書癡氣吸川，壯年纔得預賓筵。", "射穿楊葉心何武，夢入梅花骨已仙。", "設席肆筵勞送上，著鞭跨馬欲飛前。", "令君早晚朝天去，桃李妍春正耐煙。"]'),
('4c3ce9de-826b-4716-8cb7-a6dbebbc632e','送胡檢閲','陳著','宋','宋诗','song-poetry','','[]','塵鞅紛紛走畏途，眼中得見古璠璵。',64,'全唐诗/poet.song.223000.json','["塵鞅紛紛走畏途，眼中得見古璠璵。", "利名抑末有知己，骨相雖癯却飽書。", "已把三長修信史，應無千斛到清居。", "文章到地此爲最，鳳閣鸞臺次第除。"]'),
('7ce10c9a-4cb6-4752-a9b6-5d5310db076a','吳江縣作','陳著','宋','宋诗','song-poetry','','["\u592a\u6e56"]','不行浙右已三年，却上今秋考試船。',64,'全唐诗/poet.song.223000.json','["不行浙右已三年，却上今秋考試船。", "文禁何妨鷗鷺狎，厨供旋得蟹魚鮮。", "遠山浮動太湖浪，密樹冥濛小市煙。", "及過長橋風正惡，倚船無語看青天。"]'),
('a305389b-65d1-4fb8-9ce6-1171d3d0c340','長橋望湖','陳著','宋','宋诗','song-poetry','','["\u592a\u6e56"]','太湖缺處束爲橋，總把吳中景物包。',64,'全唐诗/poet.song.223000.json','["太湖缺處束爲橋，總把吳中景物包。", "去百里閒山獨立，跨三州地水平交。", "古亭休說曾垂釣，長劍何妨更斬蛟。", "欲覓鴟夷無處所，如今祇自網船拋。"]'),
('7f75466f-255e-402c-9daa-f12a7b7a6e5c','送沿江制使姚橘州尚書自金陵赴召三首  其一','陳著','宋','宋诗','song-poetry','','[]','自紫巖來百載餘，我公德量世閒無。',64,'全唐诗/poet.song.223000.json','["自紫巖來百載餘，我公德量世閒無。", "官高也只如韋布，家慶真堪入畫圖。", "忙處轉多閒氣象，平時惟做實工夫。", "此行當坐經綸閣，須念蒼生已及膚。"]'),
('36dbff14-7b69-4f9d-ab04-a9eda2bc66d8','送沿江制使姚橘州尚書自金陵赴召三首  其二','陳著','宋','宋诗','song-poetry','','[]','閫寄當今第一難，三年裘带笑談閒。',64,'全唐诗/poet.song.223000.json','["閫寄當今第一難，三年裘带笑談閒。", "寬扶民力野聲樂，靜壓邊風江水閒。", "□□有緣鍾阜住，清朝却詔履星還。", "過家聞說須留憩，荷滿江洲筍滿山。"]'),
('88c069f0-5b01-4446-a15f-0aaa5201c4a2','送沿江制使姚橘州尚書自金陵赴召三首  其三','陳著','宋','宋诗','song-poetry','','[]','當年赤手戰南宮，道眼收歸造化中。',64,'全唐诗/poet.song.223000.json','["當年赤手戰南宮，道眼收歸造化中。", "欲把一陶成異日，已教兩度受春風。", "登門英俊知何限，著意孤寒却最豐。", "但願身如秋後菊，橘州深處寄霜叢。"]'),
('4e5ad87c-ed33-4467-9800-57152c7aed99','咸淳元年乙丑冬同金陵制幕諸公遊舊烏衣巷新來燕堂制參董靜有詩因次韻','陳著','宋','宋诗','song-poetry','','[]','王謝風流墮渺茫，黯然懷舊見新堂。',64,'全唐诗/poet.song.223000.json','["王謝風流墮渺茫，黯然懷舊見新堂。", "山無多樹夕陽遠，梅始一花春意長。", "燕去有時來畫屋，鶴飛何日到青岡。", "休言枉灑新亭淚，猶勝如今似醉鄉。"]'),
('c42f7d57-b64c-43ae-8b62-ee249a450272','雲西已矣江東漕司繡春園柱閒詩尚存因次韻以寫感云','陳著','宋','宋诗','song-poetry','','[]','柳邊桃杏竹邊梅，盡是先生手自栽。',64,'全唐诗/poet.song.223000.json','["柳邊桃杏竹邊梅，盡是先生手自栽。", "舊事已隨春夢斷，新愁偏入老懷來。", "空將滿柱留題看，無復當花畫冊開。", "試上層臺望秦望，鄉心禁得杜鵑催。"]'),
('cbd1b73d-2bd7-41ad-bf01-f54b062c858e','自金陵趨行都過顧城湖三十里水光接天但風逆不可帆午閒到銀林登陸雨作','陳著','宋','宋诗','song-poetry','','[]','船路連朝天逆吹，今朝登陸雨相隨。',64,'全唐诗/poet.song.223000.json','["船路連朝天逆吹，今朝登陸雨相隨。", "自緣寒素例難阻，非爲老蒼私控持。", "山色青青無世變，梅花皎皎是心知。", "眼前有景足消遣，到闕何妨數日遲。"]'),
('e326f895-9525-420f-9847-dc7dfb13dc2e','聞伯求弟鞫獄明允今日行刑而雪應祈喜而賦詩','陳著','宋','宋诗','song-poetry','','[]','敕香勤雪未如期，誰信沈冤在獄扉。',64,'全唐诗/poet.song.223000.json','["敕香勤雪未如期，誰信沈冤在獄扉。", "玉闕曉俞三覆奏，瑶妃夜剪六花飛。", "從知刑罰分明處，最係天人感應機。", "喜極吾家有宣靜，眼中瓊樹轉光輝。"]'),
('d9c18546-4eed-4ed9-85d8-9e92ec6cced7','次韻子倉二首  其一','陳著','宋','宋诗','song-poetry','','[]','清溪遊倦又浮家，带雪來觀上國華。',64,'全唐诗/poet.song.223000.json','["清溪遊倦又浮家，带雪來觀上國華。", "飛檄有聲爭致稿，通閨得薦已攢花。", "立看雲雨蛟龍起，坐笑春風鳥雀譁。", "好向江湖忙著句，囘頭綸鳳出南衙。"]'),
('2b48d44d-d9ce-4501-8acd-4e85f167e55f','次韻子倉二首  其二','陳著','宋','宋诗','song-poetry','','[]','君學柯山我學家，相逢悃愊兩無華。',64,'全唐诗/poet.song.223000.json','["君學柯山我學家，相逢悃愊兩無華。", "有緣偶食金陵粟，連歲同聽玉樹花。", "各占路頭圖展布，不隨人口鬭諠譁。", "向來平實交相勉，笑殺粗心古押衙。"]'),
('dc7a86ab-bf09-4605-89c7-befa01d0831c','次韻史猷父鄉集','陳著','宋','宋诗','song-poetry','','[]','兩賢主禮一般春，還是慈湖曲里人。',64,'全唐诗/poet.song.223000.json','["兩賢主禮一般春，還是慈湖曲里人。", "久曠忽行知世變，相逢交賀見情真。", "發身清苦盟方暖，囘首榮華迹總陳。", "更看它年陪菜酒，耆英會後接芳塵。"]'),
('f507adc3-d82a-42d3-a811-0b69363ea3e8','嵊縣次韻趙主簿','陳著','宋','宋诗','song-poetry','','[]','爲長於斯愧善羣，那當世事日輪雲。',64,'全唐诗/poet.song.223000.json','["爲長於斯愧善羣，那當世事日輪雲。", "吾甯忤俗少行志，誰忍欺民上負君。", "臨政可能皆冉季，讀書均欲致華勳。", "有澹臺者良知我，嘉惠新詩不敢聞。"]'),
('00525a8b-a8fe-4e5f-a2e5-3692d3578ff4','嵊縣次韻答過客常德尉覓酒','陳著','宋','宋诗','song-poetry','','[]','淵明欲學醉陽城，種秫無田漫著情。',64,'全唐诗/poet.song.223000.json','["淵明欲學醉陽城，種秫無田漫著情。", "渴枕誤成頹玉夢，空槽甯有滴珠聲。", "去尋雲島人非俗，吟到雪溪詩轉清。", "鄰甕夜賒聊送似，知君已洗大蘇觥。"]'),
('f9ed36a2-bb90-4029-b39e-f9ee70d398f6','嵊縣解印回家東郭道中','陳著','宋','宋诗','song-poetry','','[]','過雪溪前第一灣，面前境界儘寬閒。',64,'全唐诗/poet.song.223000.json','["過雪溪前第一灣，面前境界儘寬閒。", "猶聽人說我知縣，誰識身□前住山。", "民社三年憂責外，家山百里笑聲閒。", "最堪喜處交情好，明月清風心往還。"]'),
('d0524226-e53f-4de6-abac-ba28011e57a7','剡民望回再回剡宿陳公嶺','陳著','宋','宋诗','song-poetry','','[]','夜宿雲閒第一峯，一雞鳴動萬山空。',64,'全唐诗/poet.song.223000.json','["夜宿雲閒第一峯，一雞鳴動萬山空。", "薄餐菜飯留中火，牢著芒鞋踏上風。", "高處更無塵隔礙，滿空惟有理玲瓏。", "此時此意平生樂，山下人誰此樂同。"]'),
('f0428a95-9ee6-432b-a14e-09ad97a9d3ed','出剡北門道中','陳著','宋','宋诗','song-poetry','','[]','晴日烘冬掃宿陰，籃輿伊軋出山深。',64,'全唐诗/poet.song.223000.json','["晴日烘冬掃宿陰，籃輿伊軋出山深。", "田夫忍凍妝旗帳，學子忘勞走佩衿。", "三載一餘多少過，萬人相送獨何心。", "新官便好觀風俗，莫道無人識古琴。"]'),
('b0a33ea4-abf1-4304-8bf7-35e25518b3ba','到徐晚邨點木𥱼三首  其一','陳著','宋','宋诗','song-poetry','','[]','江雲薄薄弄秋晴，小小籃輿款款行。',64,'全唐诗/poet.song.223000.json','["江雲薄薄弄秋晴，小小籃輿款款行。", "才近□光山自別，稍迂石險路方清。", "峭崖全是古銅色，好鳥略無京樣聲。", "林下住家圖穩靜，近來此處亦多爭。"]'),
('c184e67a-9ae4-4ffd-a908-9c9abc17d52b','到徐晚邨點木𥱼三首  其二','陳著','宋','宋诗','song-poetry','','[]','□□□□□□□，出門猶有夢悠揚。',64,'全唐诗/poet.song.223000.json','["□□□□□□□，出門猶有夢悠揚。", "五更風裏秋初旺，十里湖邊雨亦香。", "才出江頭腥滿市，却行潮脚淖濡裳。", "□□□□□□□，□□□□□□□。"]'),
('1ccd0c65-f44d-41b0-a7ba-3fb62bd71b2d','到徐晚邨點木𥱼三首  其三','陳著','宋','宋诗','song-poetry','','[]','山民墾種不供炊，專把山林抵歲支。',64,'全唐诗/poet.song.223000.json','["山民墾種不供炊，專把山林抵歲支。", "父子風濤關性命，官司分寸取便宜。", "澤梁無禁是三代，竹木有征何待時。", "便盡放寬能幾許，低頭不問只攢眉。"]'),
('a785dfa4-45cd-48af-9082-750239cf9695','甲戌考類試院呈同官','陳著','宋','宋诗','song-poetry','','[]','天風吹散撲衣塵，奎壁光中預□文。',64,'全唐诗/poet.song.223000.json','["天風吹散撲衣塵，奎壁光中預□文。", "老眼可能私李豸，公朝正欲第劉蕡。", "平生涇渭豈無見，暗室雷霆如有聞。", "一雨快晴秋意好，預占太史奏祥雲。"]'),
('4472f9c5-8305-4070-8b7b-4c84806b3554','答直學士院見訪','陳著','宋','宋诗','song-poetry','','[]','一春煙雨暗荆扉，繫馬憐君共落暉。',64,'全唐诗/poet.song.223000.json','["一春煙雨暗荆扉，繫馬憐君共落暉。", "酒琖香風吹月桂，硯池清露滴酴醿。", "水中郭索嗔皆是，屋上慈烏愛亦非。", "天道不移人自異，紅塵飛上釣魚磯。"]'),
('df05c88f-0e64-4fe9-adc5-8f0f5fd01c12','次韻答樊伯撝見拉釣','陳著','宋','宋诗','song-poetry','','[]','好共溪山結晚緣，竹枝深夜響漁椽。',64,'全唐诗/poet.song.223000.json','["好共溪山結晚緣，竹枝深夜響漁椽。", "風清月朗滄溟外，魚躍鳶飛枕几邊。", "茶竈煙銷回野艇，竹竿霜冷釣秋天。", "少年孟浪東西走，衰病於今恥復然。"]'),
('6d4d98a5-5a14-4bb5-8405-e472b199638e','次韻梅山弟惠雞臡','陳著','宋','宋诗','song-poetry','','[]','手製雞臡味可知，雨書走餉慰窮饑。',64,'全唐诗/poet.song.223000.json','["手製雞臡味可知，雨書走餉慰窮饑。", "可能夜去聞聲舞，却效早鳴逃難馳。", "伴宋讀書知已久，爲由爲黍愧非宜。", "從今定入餐松約，分付饕涎莫再垂。"]'),
('faae1166-786b-4408-a6ee-89df5edf8ee6','次韻前人醵更生會三首  其一','陳著','宋','宋诗','song-poetry','','[]','滿天地裏暗塵飛，老息奄奄一髮危。',64,'全唐诗/poet.song.223000.json','["滿天地裏暗塵飛，老息奄奄一髮危。", "種秫爲生姑託醉，采薇忍死未忘饑。", "三閒書屋鬼神護，百兩芒鞋風雨知。", "咄咄書空如夢寐，龍山誰記有佳期。"]'),
('498dc60e-4982-4ee8-900c-2b74200ff017','次韻前人醵更生會三首  其二','陳著','宋','宋诗','song-poetry','','[]','劫火吹炎海水飛，九州同惴釜魚危。',64,'全唐诗/poet.song.223000.json','["劫火吹炎海水飛，九州同惴釜魚危。", "有時杜老淚盈把，終日顔回面忍饑。", "今古滔滔無限事，乾坤納納竟何知。", "便教强趁黄花約，終恐趑趄罰後期。"]'),
('ac86e843-aca5-47b6-813f-4e0f92d2bbe9','次韻前人醵更生會三首  其三','陳著','宋','宋诗','song-poetry','','[]','世變如輪到厄年，危魂飛遶萬山巔。',64,'全唐诗/poet.song.223000.json','["世變如輪到厄年，危魂飛遶萬山巔。", "冥心前路追陶令，回首中原屬漢淵。", "樹鵲頻驚枝上月，醯雞苟活甕中天。", "悠悠未是歸時節，風雨何□復對眠。"]'),
('87dcc2ba-97d4-4ba8-b823-2193ffd56c9f','次前韻示前人','陳著','宋','宋诗','song-poetry','','[]','人生不料有今年，知汝扶親走翠巔。',64,'全唐诗/poet.song.223000.json','["人生不料有今年，知汝扶親走翠巔。", "動脚可能無陷穽，保身正合懼冰淵。", "夷傷無奈明歸地，坎險惟將心靠天。", "豈意老軀幾折臂，未能扃戶日高眠。"]'),
('9129bf36-1a58-4e6c-b3c8-f7485fa3a7fe','次韻前人訊余遭蹶之苦','陳著','宋','宋诗','song-poetry','','[]','桑榆正要補東隅，與子初期繼二疏。',64,'全唐诗/poet.song.223000.json','["桑榆正要補東隅，與子初期繼二疏。", "鐵馬漲塵難著脚，霜猨引徑各傷膚。", "苦勞筋骨甯非福，剝落皮毛不管癯。", "賸欲寄書相慰藉，呼兒頻問雁來無。"]');
